CANCEL_OPERATION = False # Прерывание запущенных операций 

# ============================================================================
# УНИВЕРСАЛЬНЫЕ ФУНКЦИИ ДЛЯ РАБОТЫ С КОМПОНЕНТАМИ
# ============================================================================

def expand_user_path(path):
    """
    Расширяет путь с учетом SUDO_USER для корректной работы при запуске с sudo
    
    КРИТИЧНО: При запуске с sudo os.path.expanduser("~") возвращает /root
    вместо домашней директории реального пользователя. Эта функция
    корректно определяет домашнюю директорию реального пользователя.
    
    Args:
        path: Путь для расширения (может содержать ~)
    
    Returns:
        Расширенный путь с учетом реального пользователя
    """
    if not path or '~' not in path:
        return path
    
    # Определяем домашнюю директорию реального пользователя
    real_user = os.environ.get('SUDO_USER')
    if real_user and real_user != 'root':
        try:
            home = pwd.getpwnam(real_user).pw_dir
        except KeyError:
            # Если пользователь не найден, используем стандартный expanduser
            home = os.path.expanduser("~")
    else:
        home = os.path.expanduser("~")
    
    # Заменяем ~ на реальную домашнюю директорию
    return path.replace('~', home)

def fix_dir_permissions(dir_path):
    """
    Устанавливает права доступа для папки (владелец - текущий пользователь)
    Универсальная функция для установки прав пользователя к любой папке в Linux
    
    Args:
        dir_path: Путь к папке
    """
    if not os.path.exists(dir_path):
        return
    
    try:
        current_uid = os.getuid()
        
        # Если запущено от root, определяем реального пользователя
        if current_uid == 0:
            real_user = os.environ.get('SUDO_USER')
            if real_user and real_user != 'root':
                try:
                    user_info = pwd.getpwnam(real_user)
                    os.chown(dir_path, user_info.pw_uid, user_info.pw_gid)
                    os.chmod(dir_path, 0o755)
                    return
                except (KeyError, ImportError):
                    pass  # Пользователь не найден или pwd недоступен (macOS)
        
        # Если не root, устанавливаем права для текущего пользователя
        if current_uid != 0:
            try:
                user_info = pwd.getpwuid(current_uid)
                os.chown(dir_path, current_uid, user_info.pw_gid)
                os.chmod(dir_path, 0o755)
            except (ImportError, OSError):
                pass  # Игнорируем ошибки на macOS или если нет прав
    except Exception:
        pass  # Игнорируем все ошибки прав доступа

def get_component_field(component_id, field_name, default=None):
    """
    Получает значение поля компонента по ID
    
    Args:
        component_id: Строковый ID компонента ('wine_9', 'wineprefix', и т.д.)
        field_name: Имя поля ('name', 'command_name', 'path', 'dependencies', 'sort_order', и т.д.)
        default: Значение по умолчанию, если поле не найдено
    
    Returns:
        Значение поля или default
    """
    if component_id not in COMPONENTS_CONFIG:
        return default
    return COMPONENTS_CONFIG[component_id].get(field_name, default)

def get_component_data(component_id):
    """
    Получает всю конфигурацию компонента по ID
    
    Args:
        component_id: Строковый ID компонента
    
    Returns:
        dict: Конфигурация компонента или None
    """
    return COMPONENTS_CONFIG.get(component_id)

def check_component_status(component_id, wineprefix_path=None):
    """
    ЕДИНАЯ функция проверки статуса компонента
    
    КРИТИЧНО: Это единственное место для проверки статуса компонентов!
    Все остальные методы должны вызывать эту функцию.
    
    Args:
        component_id: ID компонента из COMPONENTS_CONFIG
        wineprefix_path: Путь к WINEPREFIX (опционально, определяется автоматически)
        
    Returns:
        bool: True если компонент установлен, False если нет
    """
    if component_id not in COMPONENTS_CONFIG:
        return False
    
    config = COMPONENTS_CONFIG[component_id]
    # Определяем метод проверки (по умолчанию 'simple' - простая проверка через check_paths)
    check_method = config.get('check_method', 'simple')
    
    # Определяем путь к WINEPREFIX если не передан
    if wineprefix_path is None:
        # НОВОЕ: Проверяем наличие wineprefix_path в конфигурации компонента
        config_wineprefix_path = config.get('wineprefix_path')
        if config_wineprefix_path:
            wineprefix_path = expand_user_path(config_wineprefix_path)
        else:
            # Используем стандартный префикс
            # КРИТИЧНО: Используем expand_user_path для учета SUDO_USER
            wineprefix_path = expand_user_path("~/.wine-astraregul")
    
    # Специальная проверка для wineprefix
    if check_method == 'wineprefix':
        # Проверяем существование папки WINEPREFIX
        if not os.path.exists(wineprefix_path):
            return False
        
        # Проверяем наличие признаков инициализации WINEPREFIX:
        # 1. system.reg - реестр Wine (гарантированно означает инициализацию)
        # 2. drive_c - папка с диском C: (также означает инициализацию)
        system_reg = os.path.join(wineprefix_path, 'system.reg')
        drive_c = os.path.join(wineprefix_path, 'drive_c')
        
        if os.path.exists(system_reg) or os.path.exists(drive_c):
            return True
        
        return False
    
    # Специальная проверка для системных настроек (проверка значения файла)
    if check_method == 'system_config':
        check_paths = config.get('check_paths', [])
        check_value = config.get('check_value')  # Ожидаемое значение файла
        
        if not check_paths or check_value is None:
            return False
        
        # Проверяем первый путь из check_paths
        check_path = check_paths[0]
        
        # Обрабатываем абсолютные пути
        if not os.path.isabs(check_path):
            check_path = os.path.abspath(check_path)
        
        if os.path.exists(check_path):
            try:
                with open(check_path, 'r') as f:
                    actual_value = f.read().strip()
                    # Сравниваем фактическое значение с ожидаемым
                    return actual_value == check_value
            except Exception:
                return False
        
        return False
    
    # Простая проверка через check_paths (по умолчанию)
    check_paths = config.get('check_paths', [])
    if not check_paths:
        return False
    
    # КРИТИЧНО: Для desktop_shortcut используем ~/Desktop (система сама управляет активным рабочим столом)
    if config.get('category') == 'desktop_shortcut':
        # КРИТИЧНО: Используем expand_user_path для учета SUDO_USER
        desktop_dir = expand_user_path('~/Desktop')
        
        # Если ~/Desktop существует - проверяем там
        if os.path.exists(desktop_dir):
            for path in check_paths:
                # Если путь содержит полный путь (старый формат) - извлекаем только имя файла
                if '/' in path or '~' in path:
                    path_name = os.path.basename(path)
                else:
                    path_name = path
                
                full_path = os.path.join(desktop_dir, path_name)
                if os.path.exists(full_path):
                    return True
            return False
    
    # Для остальных компонентов - стандартная проверка
    for path in check_paths:
        # Обрабатываем специальные пути
        if path.startswith('~/'):
            # КРИТИЧНО: Используем expand_user_path для учета SUDO_USER
            full_path = expand_user_path(path)
            # КРИТИЧНО: Преобразуем в абсолютный путь
            full_path = os.path.abspath(full_path)
        elif path.startswith('drive_c/'):
            # Путь внутри WINEPREFIX - КРИТИЧНО: проверяем сначала существование WINEPREFIX
            if not os.path.exists(wineprefix_path):
                return False
            full_path = os.path.join(wineprefix_path, path)
            # КРИТИЧНО: Преобразуем в абсолютный путь
            full_path = os.path.abspath(full_path)
        else:
            # Для абсолютных путей используем как есть, для относительных - преобразуем
            if os.path.isabs(path):
                full_path = path
            else:
                # Относительный путь - преобразуем в абсолютный
                full_path = os.path.abspath(path)
        
        # Проверяем существование файла/директории
        if os.path.exists(full_path):
            return True
    
    return False

def resolve_dependencies(component_id, wine_app_manager=None):
    """
    Рекурсивно разрешает все зависимости компонента с учетом порядка зависимостей
    
    Поддерживает:
    - Существующие компоненты из COMPONENTS_CONFIG
    - Динамические экземпляры из wine_app_manager
    
    Args:
        component_id: Строковый ID компонента
        wine_app_manager: Менеджер экземпляров (опционально, для поддержки экземпляров)
    
    Returns:
        list: Список ID всех зависимостей (включая транзитивные),
              отсортированный по порядку зависимостей, а внутри одного уровня - по sort_order
    
    Raises:
        ValueError: Если обнаружен цикл зависимостей
    """
    resolved = []
    visited = set()
    path = set()  # Для обнаружения циклов
    
    def _get_component_config(cid):
        """Получить конфигурацию компонента (из COMPONENTS_CONFIG или экземпляра)"""
        # ПРОВЕРКА 1: Существующий компонент из COMPONENTS_CONFIG
        if cid in COMPONENTS_CONFIG:
            return COMPONENTS_CONFIG[cid]
        
        # ПРОВЕРКА 2: Динамический экземпляр из менеджера
        if wine_app_manager:
            instance_config = wine_app_manager.get_instance_config(cid)
            if instance_config:
                return instance_config
        
        return None
    
    def _get_dependencies(cid):
        """Получить зависимости компонента"""
        config = _get_component_config(cid)
        if config:
            return config.get('dependencies', [])
        return []
    
    def _get_sort_order(cid):
        """Получить sort_order компонента"""
        config = _get_component_config(cid)
        if config:
            return config.get('sort_order', 999)
        return 999
    
    def _resolve_recursive(cid):
        # Проверка циклов
        if cid in path:
            raise ValueError(f"Обнаружен цикл зависимостей: {cid} уже в пути {path}")
        
        # Проверяем существование компонента
        config = _get_component_config(cid)
        if cid in visited or not config:
            return
        
        visited.add(cid)
        path.add(cid)
        
        # Разрешаем зависимости в порядке их указания
        deps = _get_dependencies(cid)
        for dep_id in deps:
            _resolve_recursive(dep_id)
            if dep_id not in resolved:
                resolved.append(dep_id)
        
        path.remove(cid)
        
        # Добавляем сам компонент после зависимостей
        if cid not in resolved:
            resolved.append(cid)
    
    _resolve_recursive(component_id)
    
    # Сортируем компоненты одного уровня по sort_order
    # Но порядок зависимостей сохраняется (родители всегда перед детьми)
    resolved.sort(key=lambda cid: _get_sort_order(cid))
    
    return resolved

def resolve_dependencies_for_install(component_ids, wine_app_manager=None):
    """
    Разрешает зависимости для списка компонентов в порядке установки
    
    Поддерживает динамические экземпляры через wine_app_manager
    
    Args:
        component_ids: Список строковых ID компонентов
        wine_app_manager: Менеджер экземпляров (опционально)
    
    Returns:
        list: Отсортированный список ID для установки
    """
    all_resolved = []
    visited = set()
    
    for component_id in component_ids:
        if component_id not in visited:
            resolved = resolve_dependencies(component_id, wine_app_manager=wine_app_manager)
            for cid in resolved:
                if cid not in all_resolved:
                    all_resolved.append(cid)
            visited.update(resolved)
    
    return all_resolved

def resolve_dependencies_for_uninstall(component_ids):
    """
    Разрешает зависимости для списка компонентов в порядке удаления
    
    КРИТИЧНО: При удалении компонента удаляем его и всех его детей (компоненты, зависящие от него),
    но НЕ удаляем родителей. Это позволяет удалять только листья без удаления родительских компонентов.
    
    Args:
        component_ids: Список строковых ID компонентов для удаления
    
    Returns:
        list: Список ID для удаления: сначала дети, потом сами компоненты (в порядке удаления)
    """
    # Находим всех детей указанных компонентов (компоненты, зависящие от них)
    children = set()
    
    def find_children_recursive(parent_id):
        """Рекурсивно находит всех детей компонента"""
        for component_id, config in COMPONENTS_CONFIG.items():
            if component_id == parent_id:
                continue  # Пропускаем сам компонент
            deps = config.get('dependencies', [])
            if parent_id in deps:
                # Найден ребенок - добавляем его и рекурсивно ищем его детей
                if component_id not in children:
                    children.add(component_id)
                    find_children_recursive(component_id)
    
    # Находим всех детей для всех указанных компонентов
    for component_id in component_ids:
        find_children_recursive(component_id)
    
    # Формируем список для удаления: сначала дети (в порядке зависимостей), потом сами компоненты
    # Используем resolve_dependencies для детей, чтобы получить правильный порядок
    children_list = []
    for child_id in children:
        # Получаем зависимости ребенка, чтобы правильно упорядочить
        child_deps = resolve_dependencies(child_id)
        # Добавляем ребенка после его зависимостей
        if child_id not in children_list:
            children_list.append(child_id)
    
    # В итоговый список: сначала дети, потом сами компоненты
    result = []
    added = set()
    
    # Добавляем детей (в порядке зависимостей)
    for child_id in children_list:
        if child_id not in added:
            result.append(child_id)
            added.add(child_id)
    
    # Добавляем сами компоненты
    for component_id in component_ids:
        if component_id not in added:
            result.append(component_id)
            added.add(component_id)
    
    return result

def validate_component_config():
    """
    Валидирует конфигурацию компонентов
    
    Returns:
        list: Список ошибок (пустой, если все в порядке)
    
    Raises:
        ValueError: Если есть критические ошибки конфигурации
    """
    errors = []
    
    for component_id, config in COMPONENTS_CONFIG.items():
        # Проверяем обязательные поля
        required_fields = ['name', 'category', 'dependencies']
        for field in required_fields:
            if field not in config:
                errors.append(f"Компонент {component_id}: отсутствует поле '{field}'")
        
        # Проверяем зависимости
        deps = config.get('dependencies', [])
        for dep_id in deps:
            if dep_id not in COMPONENTS_CONFIG:
                errors.append(f"Компонент {component_id}: зависимость {dep_id} не найдена")
        
        # Проверяем наличие sort_order
        if 'sort_order' not in config:
            errors.append(f"Компонент {component_id}: отсутствует поле 'sort_order'")
    
    # Проверяем циклы зависимостей
    for component_id in COMPONENTS_CONFIG.keys():
        try:
            resolve_dependencies(component_id)
        except ValueError as e:
            errors.append(f"Ошибка зависимостей: {str(e)}")
    
    if errors:
        error_msg = "Ошибки конфигурации компонентов:\n" + "\n".join(errors)
        raise ValueError(error_msg)
    
    return []
class ActivityTracker(object):
# ============================================================================
# КЛАСС ОТСЛЕЖИВАНИЯ АКТИВНОСТИ КЛАССОВ (определяем рано для использования в декораторах)
# ============================================================================
    """Легковесный трекер активности классов и установщиков"""
    
    def __init__(self):
        self.active_operations = {}  # {class_name: {method: start_time, status: 'running'}}
        self.operation_history = []  # История операций
        self.max_history = 100  # Максимальное количество записей в истории
    
    def track_operation(self, class_name, method_name, status='start'):
        """Отслеживание операции класса"""
        key = f"{class_name}.{method_name}"
        current_time = time.time()
        
        if status == 'start':
            self.active_operations[key] = {
                'start_time': current_time,
                'status': 'running',
                'class': class_name,
                'method': method_name
            }
        elif status == 'end':
            if key in self.active_operations:
                duration = current_time - self.active_operations[key]['start_time']
                operation_data = {
                    'class': class_name,
                    'method': method_name,
                    'duration': duration,
                    'end_time': current_time
                }
                self.operation_history.append(operation_data)
                
                # Ограничиваем размер истории
                if len(self.operation_history) > self.max_history:
                    self.operation_history = self.operation_history[-self.max_history:]
                
                del self.active_operations[key]
    
    def get_active_operations(self):
        """Получить список активных операций"""
        current_time = time.time()
        
        active = []
        for key, op in self.active_operations.items():
            duration = current_time - op['start_time']
            active.append({
                'class': op['class'],
                'method': op['method'],
                'duration': duration,
                'status': op['status']
            })
        
        return active
    
    def get_recent_operations(self, limit=10):
        """Получить последние операции"""
        return sorted(self.operation_history, key=lambda x: x['end_time'], reverse=True)[:limit]

# Глобальный трекер активности
_global_activity_tracker = ActivityTracker()

def track_class_activity(class_name):
    """Декоратор для отслеживания активности методов класса"""
    def decorator(func):
        def wrapper(*args, **kwargs):
            _global_activity_tracker.track_operation(class_name, func.__name__, 'start')
            try:
                result = func(*args, **kwargs)
                _global_activity_tracker.track_operation(class_name, func.__name__, 'end')
                return result
            except Exception as e:
                _global_activity_tracker.track_operation(class_name, func.__name__, 'end')
                raise
        return wrapper
    return decorator

# ============================================================================
# МЕНЕДЖЕР ЭКЗЕМПЛЯРОВ WINE ПРИЛОЖЕНИЙ
# ============================================================================
class WineApplicationInstanceManager:
    """Управление экземплярами Wine приложений для разных wineprefix"""
    
    def __init__(self):
        self.instances = {}  # instance_id -> instance_data
    
    def create_instance_id(self, wineprefix_id, template_id):
        """Создает ID экземпляра"""
        return f"{wineprefix_id}__{template_id}"
    
    def get_or_create_instance(self, wineprefix_id, template_id):
        """Получает или создает экземпляр приложения для wineprefix
        
        Args:
            wineprefix_id: ID wineprefix (например, 'wineprefix', 'cont_wineprefix')
            template_id: ID шаблона приложения (например, 'wine_app_notepad_plus_plus')
        
        Returns:
            tuple: (instance_id, instance_data)
        """
        instance_id = self.create_instance_id(wineprefix_id, template_id)
        
        # Если экземпляр уже существует - возвращаем его
        if instance_id in self.instances:
            return instance_id, self.instances[instance_id]
        
        # Получаем конфигурацию wineprefix
        wineprefix_config = COMPONENTS_CONFIG.get(wineprefix_id, {})
        if not wineprefix_config:
            raise ValueError(f"Wineprefix {wineprefix_id} не найден в COMPONENTS_CONFIG")
        
        # Получаем конфигурацию шаблона из COMPONENTS_CONFIG
        template_config = COMPONENTS_CONFIG.get(template_id, {})
        if not template_config or template_config.get('template') != True:
            raise ValueError(f"Шаблон {template_id} не найден в COMPONENTS_CONFIG или не является шаблоном")
        
        # Создаем конфигурацию экземпляра
        instance_config = {
            'name': template_config['name'],
            'wineprefix_id': wineprefix_id,
            'template_id': template_id,
            'wineprefix_path': wineprefix_config.get('wineprefix_path', '~/.wine-astraregul'),
            'wine_source': wineprefix_config.get('wine_source', 'astrapack'),
            'path': template_config['default_path'],
            'check_paths': [template_config['default_path']],
            'install_method': template_config['install_method'],
            'uninstall_method': template_config['uninstall_method'],
            'uninstall_paths': template_config['default_uninstall_paths'],
            'dependencies': [wineprefix_id],  # Зависит от wineprefix
            'category': 'wine_application',
            'download_url': template_config.get('download_url'),
            'download_filename': template_config.get('download_filename'),
            'download_sha256': template_config.get('download_sha256'),
            'install_args': template_config.get('install_args', ['/S']),
            'description': template_config.get('description', ''),
            'sort_order': template_config.get('sort_order', 999),
            'gui_selectable': True
        }
        
        self.instances[instance_id] = {
            'config': instance_config,
            'status': 'missing'
        }
        
        return instance_id, self.instances[instance_id]
    
    def get_instances_for_wineprefix(self, wineprefix_id):
        """Получает все экземпляры для указанного wineprefix
        
        Args:
            wineprefix_id: ID wineprefix
        
        Returns:
            dict: {instance_id: instance_data, ...}
        """
        return {
            inst_id: inst_data
            for inst_id, inst_data in self.instances.items()
            if inst_data['config']['wineprefix_id'] == wineprefix_id
        }
    
    def remove_instances_for_wineprefix(self, wineprefix_id):
        """Удаляет все экземпляры при удалении wineprefix
        
        Args:
            wineprefix_id: ID wineprefix
        
        Returns:
            list: Список ID удаленных экземпляров
        """
        to_remove = [
            inst_id for inst_id, inst_data in self.instances.items()
            if inst_data['config']['wineprefix_id'] == wineprefix_id
        ]
        for inst_id in to_remove:
            del self.instances[inst_id]
        return to_remove
    
    def get_instance_config(self, instance_id):
        """Получает конфигурацию экземпляра
        
        Args:
            instance_id: ID экземпляра
        
        Returns:
            dict: Конфигурация экземпляра или None
        """
        instance_data = self.instances.get(instance_id)
        if instance_data:
            return instance_data['config']
        return None
    
    def update_instance_status(self, instance_id, status):
        """Обновляет статус экземпляра
        
        Args:
            instance_id: ID экземпляра
            status: Новый статус ('missing', 'ok', 'installing', 'removing', 'error')
        """
        if instance_id in self.instances:
            self.instances[instance_id]['status'] = status

# ============================================================================
# БАЗОВЫЙ КЛАСС ДЛЯ ОБРАБОТЧИКОВ КОМПОНЕНТОВ
# ============================================================================
class ComponentHandler(ABC):
    """Базовый класс для обработчиков компонентов с интеграцией всех систем"""
    
    def __init__(self, 
                 astrapack_dir=None,
                 logger=None,
                 callback=None,
                 universal_runner=None,
                 progress_manager=None,
                 dual_logger=None,
                 status_manager=None):
        """
        Инициализация обработчика компонентов
        
        Args:
            astrapack_dir: Путь к директории AstraPack
            logger: Экземпляр Logger для записи в файл
            callback: Функция для обновления статуса в GUI
            universal_runner: UniversalProcessRunner для запуска процессов
            progress_manager: UniversalProgressManager для прогресса
            dual_logger: DualStreamLogger для двойных потоков логирования
            status_manager: ComponentStatusManager для управления статусами
        """
        self.astrapack_dir = astrapack_dir
        self.logger = logger
        self.callback = callback
        self.universal_runner = universal_runner or get_global_universal_runner()
        self.progress_manager = progress_manager
        self.dual_logger = dual_logger or (globals().get('_global_dual_logger') if '_global_dual_logger' in globals() else None)
        self.status_manager = status_manager  # КРИТИЧНО: для обновления статусов
        
        # Определяем домашнюю директорию РЕАЛЬНОГО пользователя
        real_user = os.environ.get('SUDO_USER')
        if real_user and real_user != 'root':
            self.home = pwd.getpwnam(real_user).pw_dir
        else:
            self.home = os.path.expanduser("~")
        
        self.wineprefix = os.path.join(self.home, ".wine-astraregul")
    
    def _log(self, message, level="INFO"):
        """
        Универсальное логирование через все системы
        
        ВАЖНО: Вся инфраструктура логирования сохраняется:
        - print() продолжает работать везде (переопределен через builtins.print = universal_print)
        - universal_print использует DualStreamLogger для логирования
        - UniversalProcessRunner.log_info/log_error также используют DualStreamLogger
        
        Метод _log() - удобная обертка, но handlers могут использовать и прямой print()
        """
        # Логирование через UniversalProcessRunner
        # (UniversalProcessRunner.log_info/log_error/log_debug внутри используют DualStreamLogger)
        if self.universal_runner:
            if level == "ERROR":
                self.universal_runner.log_error(message)
            elif level == "WARNING":
                self.universal_runner.log_warning(message)
            elif level == "DEBUG":
                self.universal_runner.log_debug(message)
            else:
                self.universal_runner.log_info(message)
        
        # Дополнительное логирование через DualStreamLogger напрямую (если есть)
        # (обычно это уже делается через UniversalProcessRunner, но для надежности)
        if self.dual_logger:
            if level == "ERROR":
                self.dual_logger.write_analysis(f"[ERROR] {message}")
            elif level == "WARNING":
                self.dual_logger.write_analysis(f"[WARNING] {message}")
            elif level == "DEBUG":
                self.dual_logger.write_analysis(f"[DEBUG] {message}")
            else:
                self.dual_logger.write_analysis(f"[INFO] {message}")
        
        # Callback в GUI
        if self.callback:
            self.callback(message)
        
        # ПРИМЕЧАНИЕ: handlers также могут использовать прямой print():
        # print(f"[INFO] {message}")  # Работает через universal_print → DualStreamLogger
    
    def _get_source_dir(self, source_dir_name):
        """
        Получить путь к директории с предустановленной конфигурацией
        
        Args:
            source_dir_name: Имя директории (например, 'CountPack', 'AstraPack')
            
        Returns:
            str: Полный путь к директории или None если source_dir_name не указан
        """
        if not source_dir_name:
            return None
        
        # Если абсолютный путь - используем как есть
        if os.path.isabs(source_dir_name):
            return source_dir_name
        
        # Относительный путь - ищем в директории скрипта
        if os.path.isabs(sys.argv[0]):
            script_path = sys.argv[0]
        else:
            script_path = os.path.join(os.getcwd(), sys.argv[0])
        script_dir = os.path.dirname(os.path.abspath(script_path))
        full_path = os.path.join(script_dir, source_dir_name)
        return full_path
    
    def _get_script_dir(self):
        """
        Получить директорию скрипта
        
        Returns:
            str: Полный путь к директории скрипта
        """
        if os.path.isabs(sys.argv[0]):
            script_path = sys.argv[0]
        else:
            script_path = os.path.join(os.getcwd(), sys.argv[0])
        return os.path.dirname(os.path.abspath(script_path))
    
    def _resolve_single_file(self, file_path, config=None, script_dir=None, cleanup_temp=True, 
                             source_priority=None, fallback=True):
        """
        Вспомогательная функция для получения одного файла из различных источников
        
        Поддерживает:
        - Прямые пути (относительные от скрипта или абсолютные)
        - Файлы в архивах (формат: "Wine/wine_packages.tar.gz/файл.deb")
        - URL для загрузки из интернета (http://, https://)
        - Несколько путей (список) - возвращает первый найденный
        
        Args:
            file_path: Путь к файлу (строка) или список путей
            config: Конфигурация компонента (для получения download_sha256 и download_filename)
            script_dir: Директория скрипта (если None, определяется автоматически)
            cleanup_temp: Если True, временная директория будет удалена при выходе из контекста
            source_priority: Приоритет источника ('archive', 'url', 'direct', None)
                            Если указан, проверяет сначала этот тип источника
            fallback: Если True, при недоступности приоритетного источника пробует другие
                     Если False, возвращает None если приоритетный источник недоступен
            
        Returns:
            tuple: (путь_к_файлу, временная_директория, источник) или (None, None, None) если файл не найден
                   Источник: 'url', 'archive', 'direct' или None
        """
        if script_dir is None:
            script_dir = self._get_script_dir()
        
        # Нормализуем входные данные: всегда список
        if isinstance(file_path, str):
            file_paths = [file_path]
        else:
            file_paths = file_path
        
        # Группируем пути по типам источников
        url_paths = []
        archive_paths = []
        direct_paths = []
        
        for path in file_paths:
            if not path:
                continue
            
            if path.startswith('http://') or path.startswith('https://'):
                url_paths.append(path)
            elif '.tar.gz/' in path or '.tar/' in path:
                archive_paths.append(path)
            else:
                direct_paths.append(path)
        
        # Определяем порядок проверки источников
        if source_priority:
            if fallback:
                # С fallback: приоритетный источник первый, потом остальные
                if source_priority == 'url':
                    check_order = ['url', 'archive', 'direct']
                elif source_priority == 'archive':
                    check_order = ['archive', 'url', 'direct']
                elif source_priority == 'direct':
                    check_order = ['direct', 'archive', 'url']
                else:
                    check_order = ['url', 'archive', 'direct']
            else:
                # Без fallback: только приоритетный источник
                check_order = [source_priority]
        else:
            # Без приоритета: стандартный порядок
            check_order = ['url', 'archive', 'direct']
        
        temp_dirs = []
        
        # Пробуем источники в порядке приоритета
        for source_type in check_order:
            # Выбираем пути для текущего типа источника
            if source_type == 'url':
                paths_to_check = url_paths
            elif source_type == 'archive':
                paths_to_check = archive_paths
            elif source_type == 'direct':
                paths_to_check = direct_paths
            else:
                continue
            
            for path in paths_to_check:
                # 1. URL (http:// или https://)
                if source_type == 'url':
                    try:
                        download_filename = None
                        if config:
                            download_filename = config.get('download_filename')
                        
                        if not download_filename:
                            download_filename = os.path.basename(urllib.parse.urlparse(path).path)
                            if not download_filename:
                                download_filename = 'downloaded_file'
                        
                        temp_dir = tempfile.mkdtemp(prefix='astra_download_')
                        temp_dirs.append(temp_dir)
                        download_path = os.path.join(temp_dir, download_filename)
                        
                        print(f"[INFO] Загрузка файла из интернета: {path}", level='INFO')
                        # Обработка SSL ошибок (для macOS и других систем без сертификатов)
                        try:
                            ssl_context = ssl.create_default_context()
                            ssl_context.check_hostname = False
                            ssl_context.verify_mode = ssl.CERT_NONE
                            # Создаем opener с SSL контекстом
                            opener = urllib.request.build_opener(urllib.request.HTTPSHandler(context=ssl_context))
                            urllib.request.install_opener(opener)
                            urllib.request.urlretrieve(path, download_path)
                        except Exception as ssl_error:
                            # Если не удалось с SSL контекстом, пробуем без него
                            try:
                                urllib.request.urlretrieve(path, download_path)
                            except Exception as e:
                                raise e
                        
                        # Проверка SHA256
                        if config and config.get('download_sha256'):
                            expected_sha256 = config.get('download_sha256')
                            if expected_sha256:
                                sha256_hash = hashlib.sha256()
                                with open(download_path, 'rb') as f:
                                    for chunk in iter(lambda: f.read(4096), b''):
                                        sha256_hash.update(chunk)
                                actual_sha256 = sha256_hash.hexdigest()
                                
                                if actual_sha256.lower() != expected_sha256.lower():
                                    print(f"[ERROR] SHA256 не совпадает! Ожидался: {expected_sha256}, получен: {actual_sha256}", level='ERROR')
                                    for td in temp_dirs:
                                        try:
                                            shutil.rmtree(td)
                                        except:
                                            pass
                                    continue
                                else:
                                    print(f"[INFO] SHA256 проверка пройдена: {actual_sha256}", level='INFO')
                        
                        print(f"[INFO] Файл успешно загружен: {download_path}", level='INFO')
                        return (download_path, temp_dir if not cleanup_temp else None, 'url')
                        
                    except Exception as e:
                        print(f"[ERROR] Ошибка загрузки файла из {path}: {e}", level='ERROR')
                        for td in temp_dirs:
                            try:
                                shutil.rmtree(td)
                            except:
                                pass
                        continue
                
                # 2. Архив (формат: "путь/к/архиву.tar.gz/файл.расширение")
                elif source_type == 'archive':
                    parts = path.split('/')
                    archive_part = None
                    file_in_archive = None
                    
                    for i, part in enumerate(parts):
                        if part.endswith('.tar.gz') or part.endswith('.tar'):
                            archive_part = '/'.join(parts[:i+1])
                            file_in_archive = '/'.join(parts[i+1:])
                            break
                    
                    if archive_part and file_in_archive:
                        if os.path.isabs(archive_part):
                            archive_path = archive_part
                        else:
                            archive_path = os.path.join(script_dir, archive_part)
                        
                        if os.path.exists(archive_path):
                            try:
                                temp_dir = tempfile.mkdtemp(prefix='astra_extract_')
                                temp_dirs.append(temp_dir)
                                
                                with tarfile.open(archive_path, 'r:gz') as tar:
                                    try:
                                        tar.extract(file_in_archive, temp_dir)
                                        extracted_path = os.path.join(temp_dir, file_in_archive)
                                        
                                        if os.path.exists(extracted_path):
                                            print(f"[INFO] Файл извлечен из архива: {archive_path} -> {extracted_path}", level='INFO')
                                            return (extracted_path, temp_dir if not cleanup_temp else None, 'archive')
                                    except KeyError:
                                        continue
                            except Exception as e:
                                print(f"[ERROR] Ошибка извлечения файла из архива {archive_path}: {e}", level='ERROR')
                                for td in temp_dirs:
                                    try:
                                        shutil.rmtree(td)
                                    except:
                                        pass
                                continue
                
                # 3. Прямой путь
                elif source_type == 'direct':
                    if os.path.isabs(path):
                        if os.path.exists(path):
                            return (path, None, 'direct')
                    else:
                        full_path = os.path.join(script_dir, path)
                        if os.path.exists(full_path):
                            return (full_path, None, 'direct')
        
        # Очистка временных директорий
        for td in temp_dirs:
            try:
                shutil.rmtree(td)
            except:
                pass
        
        return (None, None, None)
    
    def _resolve_component_files(self, component_id, cleanup_temp=True, source_priority=None, fallback=True):
        """
        Универсальная функция для получения файлов компонента из различных источников
        
        Поддерживает:
        - Прямые пути (относительные от скрипта или абсолютные)
        - Файлы в архивах (формат: "Wine/wine_packages.tar.gz/файл.deb")
        - URL для загрузки из интернета (http://, https://)
        - Несколько файлов для разных архитектур (x86/x64, 32/64)
        
        Args:
            component_id: ID компонента
            cleanup_temp: Если True, временная директория будет удалена при выходе из контекста
            source_priority: Приоритет источника ('archive', 'url', 'direct', None)
                            Если указан, проверяет сначала этот тип источника
            fallback: Если True, при недоступности приоритетного источника пробует другие
                     Если False, возвращает None если приоритетный источник недоступен
            
        Returns:
            dict: {
                'files': {
                    'default': '/path/to/file',  # Для одного файла
                    # ИЛИ для нескольких:
                    'x86': '/path/to/x86', 'x64': '/path/to/x64',
                    '32': '/path/to/32', '64': '/path/to/64'
                },
                'temp_dir': '/tmp/...',  # Временная директория для очистки
                'cleanup': True,  # Нужно ли очищать temp_dir
                'source': 'url'  # Источник файла ('url', 'archive', 'direct')
            }
            Или None если файлы не найдены
        """
        # Получаем конфигурацию компонента
        config = get_component_data(component_id)
        if not config:
            print(f"[ERROR] Компонент {component_id} не найден в конфигурации", level='ERROR')
            return None
        
        script_dir = self._get_script_dir()
        temp_dirs = []  # Список временных директорий для очистки
        result_files = {}  # Результирующий словарь файлов
        source_info = {}  # Информация об источниках для каждого файла
        
        # 1. Проверяем package_file (для пакетов)
        package_file = config.get('package_file')
        if package_file:
            file_path, temp_dir, source = self._resolve_single_file(
                package_file, config, script_dir, cleanup_temp, source_priority, fallback
            )
            if file_path:
                result_files['default'] = file_path
                source_info['default'] = source
                if temp_dir:
                    temp_dirs.append(temp_dir)
                return {
                    'files': result_files,
                    'temp_dir': temp_dirs[0] if temp_dirs else None,
                    'cleanup': cleanup_temp,
                    'source': source
                }
        
        # 2. Проверяем download_url (один файл из интернета)
        download_url = config.get('download_url')
        if download_url:
            file_path, temp_dir, source = self._resolve_single_file(
                download_url, config, script_dir, cleanup_temp, source_priority, fallback
            )
            if file_path:
                result_files['default'] = file_path
                source_info['default'] = source
                if temp_dir:
                    temp_dirs.append(temp_dir)
                return {
                    'files': result_files,
                    'temp_dir': temp_dirs[0] if temp_dirs else None,
                    'cleanup': cleanup_temp,
                    'source': source
                }
        
        # 3. Проверяем download_url_x86 / download_url_x64 (два файла для разных архитектур)
        download_url_x86 = config.get('download_url_x86')
        download_url_x64 = config.get('download_url_x64')
        if download_url_x86 or download_url_x64:
            if download_url_x86:
                file_path, temp_dir, source = self._resolve_single_file(
                    download_url_x86, 
                    {'download_sha256': config.get('download_sha256_x86'), 
                     'download_filename': config.get('download_filename_x86')},
                    script_dir, cleanup_temp, source_priority, fallback
                )
                if file_path:
                    result_files['x86'] = file_path
                    source_info['x86'] = source
                    if temp_dir:
                        temp_dirs.append(temp_dir)
            
            if download_url_x64:
                file_path, temp_dir, source = self._resolve_single_file(
                    download_url_x64,
                    {'download_sha256': config.get('download_sha256_x64'),
                     'download_filename': config.get('download_filename_x64')},
                    script_dir, cleanup_temp, source_priority, fallback
                )
                if file_path:
                    result_files['x64'] = file_path
                    source_info['x64'] = source
                    if temp_dir:
                        temp_dirs.append(temp_dir)
            
            if result_files:
                # Определяем основной источник (если все из одного источника)
                main_source = source_info.get('x86') or source_info.get('x64')
                return {
                    'files': result_files,
                    'temp_dir': temp_dirs[0] if temp_dirs else None,
                    'cleanup': cleanup_temp,
                    'source': main_source,
                    'sources': source_info  # Детальная информация по каждому файлу
                }
        
        # 4. Проверяем download_url_32 / download_url_64 (альтернативные варианты)
        download_url_32 = config.get('download_url_32')
        download_url_64 = config.get('download_url_64')
        if download_url_32 or download_url_64:
            if download_url_32:
                file_path, temp_dir, source = self._resolve_single_file(
                    download_url_32,
                    {'download_sha256': config.get('download_sha256_32'),
                     'download_filename': config.get('download_filename_32')},
                    script_dir, cleanup_temp, source_priority, fallback
                )
                if file_path:
                    result_files['32'] = file_path
                    source_info['32'] = source
                    if temp_dir:
                        temp_dirs.append(temp_dir)
            
            if download_url_64:
                file_path, temp_dir, source = self._resolve_single_file(
                    download_url_64,
                    {'download_sha256': config.get('download_sha256_64'),
                     'download_filename': config.get('download_filename_64')},
                    script_dir, cleanup_temp, source_priority, fallback
                )
                if file_path:
                    result_files['64'] = file_path
                    source_info['64'] = source
                    if temp_dir:
                        temp_dirs.append(temp_dir)
            
            if result_files:
                # Определяем основной источник
                main_source = source_info.get('32') or source_info.get('64')
                return {
                    'files': result_files,
                    'temp_dir': temp_dirs[0] if temp_dirs else None,
                    'cleanup': cleanup_temp,
                    'source': main_source,
                    'sources': source_info
                }
        
        # Файлы не найдены
        # Очищаем временные директории
        for td in temp_dirs:
            try:
                shutil.rmtree(td)
            except:
                pass
        
        return None
    
    def _get_active_desktop_dir(self):
        """
        Определяет активный рабочий стол
        
        Система сама управляет ~/Desktop и всегда показывает активный рабочий стол.
        КРИТИЧНО: Использует expand_user_path для учета SUDO_USER.
        
        Returns:
            str: Полный путь к активному рабочему столу (~/Desktop)
        """
        # КРИТИЧНО: Используем expand_user_path для учета SUDO_USER
        desktop_dir = expand_user_path('~/Desktop')
        
        # Если ~/Desktop существует - используем его (система сама управляет активным рабочим столом)
        if os.path.exists(desktop_dir):
            return desktop_dir
        
        # Если ~/Desktop не существует - используем Desktop1 как fallback
        # КРИТИЧНО: Используем expand_user_path для учета SUDO_USER
        return expand_user_path('~/Desktops/Desktop1')
    
    def _check_wine_processes_running(self):
        """
        Проверка запущенных процессов wine/установщика
        
        Returns:
            list: Список запущенных процессов [(pid, name, cmdline), ...]
        """
        running_processes = []
        
        if not PSUTIL_AVAILABLE:
            # Если psutil недоступен, используем pgrep
            try:
                result = subprocess.run(['pgrep', '-f', 'wine'], 
                                      stdout=subprocess.PIPE, stderr=subprocess.PIPE, 
                                      text=True, timeout=5)
                if result.returncode == 0:
                    pids = result.stdout.strip().split('\n')
                    for pid_str in pids:
                        if pid_str:
                            try:
                                pid = int(pid_str)
                                running_processes.append((pid, 'wine', ''))
                            except ValueError:
                                pass
            except Exception:
                pass
            return running_processes
        
        # Используем psutil для более точной проверки
        try:
            for proc in psutil.process_iter(['pid', 'name', 'cmdline']):
                try:
                    cmdline = ' '.join(proc.info['cmdline'] or [])
                    name = proc.info['name'] or ''
                    
                    # Проверяем процессы wine (wine, wineserver, wineboot, msiexec, установщики .NET и т.д.)
                    if 'wine' in name.lower() or 'wine' in cmdline.lower():
                        running_processes.append((proc.info['pid'], name, cmdline))
                except (psutil.NoProcess, psutil.AccessDenied):
                    continue
                except Exception:
                    continue
        except Exception:
            pass
        
        return running_processes
    
    def _wait_for_all_processes_terminated(self, max_wait=30, check_interval=1):
        """
        Ожидание завершения всех процессов wine/установщика с таймаутом
        
        Args:
            max_wait: Максимальное время ожидания в секундах (по умолчанию 30)
            check_interval: Интервал проверки в секундах (по умолчанию 1)
        
        Returns:
            bool: True если все процессы завершились, False если таймаут
        """
        
        start_time = time.time()
        
        while time.time() - start_time < max_wait:
            running = self._check_wine_processes_running()
            if not running:
                return True
            
            # Логируем оставшиеся процессы
            if len(running) > 0:
                proc_info = ', '.join([f"PID:{pid}" for pid, _, _ in running[:3]])
                if len(running) > 3:
                    proc_info += f" и еще {len(running) - 3}"
                print(f"[ComponentHandler] Ожидание завершения процессов wine: {proc_info}")
            
            time.sleep(check_interval)
        
        # Таймаут - принудительно завершаем процессы
        running = self._check_wine_processes_running()
        if running:
            print(f"[ComponentHandler] Таймаут ожидания завершения процессов, принудительно завершаем {len(running)} процессов")
            self._force_terminate_wine_processes()
            return False
        
        return True
    
    def _force_terminate_wine_processes(self):
        """Принудительное завершение всех процессов wine"""
        
        if PSUTIL_AVAILABLE:
            try:
                # Сначала мягкое завершение (SIGTERM)
                for proc in psutil.process_iter(['pid', 'name']):
                    try:
                        name = proc.info['name'] or ''
                        cmdline = ' '.join(proc.cmdline() or [])
                        if 'wine' in name.lower() or 'wine' in cmdline.lower():
                            proc.terminate()
                    except (psutil.NoProcess, psutil.AccessDenied):
                        continue
                    except Exception:
                        continue
                
                # Ждем немного
                time.sleep(2)
                
                # Принудительное завершение (SIGKILL) оставшихся процессов
                for proc in psutil.process_iter(['pid', 'name']):
                    try:
                        name = proc.info['name'] or ''
                        cmdline = ' '.join(proc.cmdline() or [])
                        if 'wine' in name.lower() or 'wine' in cmdline.lower():
                            proc.kill()
                    except (psutil.NoProcess, psutil.AccessDenied):
                        continue
                    except Exception:
                        continue
            except Exception:
                pass
        
        # Дополнительно используем pkill для надежности
        try:
            subprocess.run(['pkill', '-9', 'wine'], stdout=subprocess.PIPE, stderr=subprocess.PIPE, check=False, timeout=5)
            subprocess.run(['pkill', '-9', 'wineserver'], stdout=subprocess.PIPE, stderr=subprocess.PIPE, check=False, timeout=5)
            subprocess.run(['pkill', '-9', 'wineboot'], stdout=subprocess.PIPE, stderr=subprocess.PIPE, check=False, timeout=5)
        except Exception:
            pass
    
    def _terminate_wineserver(self):
        """
        Остановка wineserver (как в оригинале: wineserver -k)
        """
        
        try:
            # Определяем wineserver путь
            wine_path = '/opt/wine-9.0/bin/wine'
            wineserver_path = wine_path.replace('/wine', '/wineserver')
            
            if not os.path.exists(wineserver_path):
                # Пробуем найти wineserver в PATH
                result = subprocess.run(['which', 'wineserver'], 
                                      stdout=subprocess.PIPE, stderr=subprocess.PIPE, 
                                      text=True, timeout=5)
                if result.returncode == 0:
                    wineserver_path = result.stdout.strip()
                else:
                    wineserver_path = 'wineserver'  # Используем из PATH
            
            # Настраиваем окружение для wineserver
            env = os.environ.copy()
            env['WINEPREFIX'] = self.wineprefix
            
            print(f"[ComponentHandler] Остановка wineserver: {wineserver_path} -k")
            result = subprocess.run([wineserver_path, '-k'], env=env, 
                                  stdout=subprocess.PIPE, stderr=subprocess.PIPE, 
                                  text=True, timeout=10)
            
            if result.returncode == 0:
                print("[ComponentHandler] wineserver успешно остановлен")
            else:
                print(f"[ComponentHandler] Предупреждение: wineserver вернул код {result.returncode}")
        except Exception as e:
            print(f"[ComponentHandler] Ошибка при остановке wineserver: {e}")
    
    def _ensure_no_conflicting_processes(self, max_wait=30):
        """
        Проверка перед установкой/удалением компонента - убедиться что нет запущенных процессов от предыдущей операции
        
        Args:
            max_wait: Максимальное время ожидания завершения процессов в секундах
        
        Returns:
            bool: True если нет конфликтующих процессов, False если процессы не завершились
        """
        running = self._check_wine_processes_running()
        
        if not running:
            return True
        
        print(f"[ComponentHandler] Обнаружены запущенные процессы wine от предыдущей операции ({len(running)} процессов)")
        print(f"[ComponentHandler] Ожидание их завершения (максимум {max_wait} секунд)...")
        
        # Ждем завершения процессов
        all_terminated = self._wait_for_all_processes_terminated(max_wait=max_wait)
        
        if not all_terminated:
            print("[ComponentHandler] Некоторые процессы не завершились, принудительно завершаем их", level='WARNING')
            self._force_terminate_wine_processes()
            # Ждем еще немного после принудительного завершения
            time.sleep(2)
        
        return True
    
    def _update_progress(self, stage_name, stage_progress, global_progress, details="", **kwargs):
        """Обновление прогресса через UniversalProgressManager"""
        if self.progress_manager:
            # НОВОЕ: Извлекаем elapsed_time из kwargs если есть
            elapsed_time = kwargs.get('elapsed_time', 0)
            
            self.progress_manager.update_progress(
                process_type='wine_install',  # КРИТИЧНО: для различения от system_update
                stage_name=stage_name,
                stage_progress=stage_progress,
                global_progress=global_progress,
                details=details,
                elapsed_time=elapsed_time  # НОВОЕ: Передаем время
            )
    
    def _update_status(self, component_id, status):
        """Обновление статуса компонента через ComponentStatusManager"""
        if self.status_manager:
            self.status_manager.update_component_status(component_id, status)
        else:
            print(f"_update_status() status_manager отсутствует, статус не обновлен", level='WARNING')
    
    def _run_process(self, command, process_type="install", channels=["file", "terminal"], env=None, timeout=None):
        """Запуск процесса через UniversalProcessRunner"""
        if self.universal_runner:
            return self.universal_runner.run_process(
                command=command,
                process_type=process_type,
                channels=channels,
                env=env,
                timeout=timeout
            )
        return -1
    
    def _is_leaf_component(self, component_id):
        """
        Проверяет, является ли компонент листовым (без дочек)
        
        Args:
            component_id: ID компонента
        
        Returns:
            bool: True если компонент листовой (без дочек), False если есть дочки
        """
        # Проверяем, есть ли компоненты, которые зависят от этого компонента
        for child_id, child_config in COMPONENTS_CONFIG.items():
            if child_id == component_id:
                continue  # Пропускаем сам компонент
            child_deps = get_component_field(child_id, 'dependencies', [])
            if component_id in child_deps:
                return False  # Есть дочка - не лист
        
        return True  # Нет дочек - лист
    
    def _stop_processes(self, processes_list, max_wait_time=30):
        """
        Универсальная остановка процессов с таймаутом
        
        Args:
            processes_list: Список имен процессов для остановки (например, ['wine', 'wineserver'])
            max_wait_time: Максимальное время ожидания в секундах (по умолчанию 30)
        
        Returns:
            bool: True если все процессы остановлены, False если некоторые не удалось остановить
        """
        if not processes_list:
            return True
        
        print(f"Остановка процессов: {', '.join(processes_list)}")
        
        # Сначала мягкая остановка (SIGTERM)
        for proc_name in processes_list:
            try:
                # Находим процессы
                result = subprocess.run(
                    ['pgrep', '-f', proc_name],
                    stdout=subprocess.PIPE,
                    stderr=subprocess.PIPE,
                    text=True
                )
                if result.returncode == 0:
                    pids = result.stdout.strip().split('\n')
                    for pid_str in pids:
                        if pid_str:
                            try:
                                pid = int(pid_str)
                                print(f"Отправка SIGTERM процессу {proc_name} (PID: {pid})")
                                os.kill(pid, signal.SIGTERM)
                            except (OSError, ValueError) as e:
                                pass  # Процесс уже не существует
            except Exception as e:
                pass  # Игнорируем ошибки при поиске процессов
        
        # Ждем до max_wait_time секунд для мягкого завершения
        check_interval = 1
        waited = 0
        
        print(f"Ожидание завершения процессов (максимум {max_wait_time} секунд)...")
        while waited < max_wait_time:
            # Проверяем, остались ли процессы
            still_running = []
            for proc_name in processes_list:
                try:
                    result = subprocess.run(
                        ['pgrep', '-f', proc_name],
                        stdout=subprocess.PIPE,
                        stderr=subprocess.PIPE,
                        text=True
                    )
                    if result.returncode == 0:
                        still_running.append(proc_name)
                except:
                    pass
            
            if not still_running:
                print("Все процессы завершились корректно")
                return True
            
            time.sleep(check_interval)
            waited += check_interval
            
            if waited % 5 == 0:  # Каждые 5 секунд логируем
                print(f"Ожидание завершения процессов... (прошло {waited} секунд)")
        
        # Принудительная остановка процессов, которые не завершились
        if waited >= max_wait_time:
            print("Некоторые процессы не завершились, принудительная остановка (SIGKILL)", level='WARNING')
            for proc_name in processes_list:
                try:
                    result = subprocess.run(
                        ['pgrep', '-f', proc_name],
                        stdout=subprocess.PIPE,
                        stderr=subprocess.PIPE,
                        text=True
                    )
                    if result.returncode == 0:
                        pids = result.stdout.strip().split('\n')
                        for pid_str in pids:
                            if pid_str:
                                try:
                                    pid = int(pid_str)
                                    print(f"Принудительная остановка процесса {proc_name} (PID: {pid})", level='WARNING')
                                    os.kill(pid, signal.SIGKILL)
                                except (OSError, ValueError) as e:
                                    pass  # Процесс уже не существует
                except Exception as e:
                    pass  # Игнорируем ошибки
        
        # Финальная проверка
        final_check = []
        for proc_name in processes_list:
            try:
                result = subprocess.run(
                    ['pgrep', '-f', proc_name],
                    stdout=subprocess.PIPE,
                    stderr=subprocess.PIPE,
                    text=True
                )
                if result.returncode == 0:
                    final_check.append(proc_name)
            except:
                pass
        
        if final_check:
            print(f"Некоторые процессы все еще работают: {', '.join(final_check)}", level='WARNING')
            print(f"Удаление будет продолжено, но файлы могут быть заняты процессами", level='WARNING')
            # НЕ возвращаем False - продолжаем удаление, так как процессы могут быть не критичны
            # или могут быть остановлены системой позже
        
        return True
    
    def _collect_all_processes_for_stop(self, component_id):
        """
        Рекурсивно собирает все процессы компонента и всех его дочек
        
        Args:
            component_id: ID компонента
        
        Returns:
            set: Множество уникальных имен процессов для остановки
        """
        all_processes = set()
        
        # Собираем процессы самого компонента
        own_processes = get_component_field(component_id, 'processes_to_stop', [])
        if own_processes:
            all_processes.update(own_processes)
        
        # Рекурсивно находим все дочки и собираем их процессы
        visited = set()
        
        def _collect_children_recursive(cid):
            """Рекурсивно собирает процессы всех дочек"""
            if cid in visited:
                return
            visited.add(cid)
            
            # Находим все компоненты, которые зависят от этого компонента
            for child_id, child_config in COMPONENTS_CONFIG.items():
                if child_id == cid:
                    continue  # Пропускаем сам компонент
                child_deps = get_component_field(child_id, 'dependencies', [])
                if cid in child_deps:
                    # Это дочка - добавляем ее процессы
                    child_processes = get_component_field(child_id, 'processes_to_stop', [])
                    if child_processes:
                        all_processes.update(child_processes)
                    # Рекурсивно обрабатываем дочки дочки
                    _collect_children_recursive(child_id)
        
        # Собираем процессы всех дочек
        _collect_children_recursive(component_id)
        
        return all_processes
    
    @abstractmethod
    def install(self, component_id: str, config: dict) -> bool:
        """
        Установка компонента
        
        Args:
            component_id: ID компонента из COMPONENTS_CONFIG
            config: Конфигурация компонента из COMPONENTS_CONFIG
            
        Returns:
            bool: True если установка успешна, False если ошибка
            
        Обязательные действия:
        1. self._update_status(component_id, 'installing')
        2. Выполнить установку
        3. self._update_status(component_id, 'ok' или 'error')
        """
        pass
    
    @abstractmethod
    def uninstall(self, component_id: str, config: dict) -> bool:
        """
        Удаление компонента
        
        Args:
            component_id: ID компонента из COMPONENTS_CONFIG
            config: Конфигурация компонента из COMPONENTS_CONFIG
            
        Returns:
            bool: True если удаление успешно, False если ошибка
            
        Обязательные действия:
        1. self._update_status(component_id, 'removing')
        2. Выполнить удаление
        3. self._update_status(component_id, 'missing' или 'error')
        """
        pass
    
    @abstractmethod
    def check_status(self, component_id: str, config: dict) -> bool:
        """
        Проверка статуса компонента
        
        Args:
            component_id: ID компонента из COMPONENTS_CONFIG
            config: Конфигурация компонента из COMPONENTS_CONFIG
            
        Returns:
            bool: True если компонент установлен, False если нет
        """
        pass
    
    @abstractmethod
    def get_category(self) -> str:
        """
        Возвращает категорию компонентов
        
        Returns:
            str: Категория ('wine_packages', 'wine_environment', 'winetricks', 'system_config', 'application')
        """
        pass
    
    def _check_command_available(self, command: str) -> bool:
        """
        Проверка доступности команды в системе
        
        Args:
            command: Имя команды (например, 'rsync', 'tar', 'cp')
        
        Returns:
            bool: True если команда доступна
        """
        return shutil.which(command) is not None
    
    def _truncate_path(self, path: str, max_length: int = 60) -> str:
        """
        Обрезает путь, оставляя конец, если он слишком длинный
        
        Args:
            path: Полный путь
            max_length: Максимальная длина (по умолчанию 60)
        
        Returns:
            str: Обрезанный путь с "..." в начале если нужно
        """
        if len(path) <= max_length:
            return path
        return "..." + path[-(max_length - 3):]

# ============================================================================
# ОБРАБОТЧИК WINE ПАКЕТОВ
# ============================================================================
class WinePackageHandler(ComponentHandler):
    """Обработчик Wine пакетов (wine_astraregul, wine_9)"""
    
    def get_category(self) -> str:
        return 'wine_packages'
    
    @track_class_activity('WinePackageHandler')
    def install(self, component_id: str, config: dict) -> bool:
        """Установка Wine пакета через apt"""
        # КРИТИЧНО: Сбрасываем флаг отмены в начале установки
        # Это гарантирует, что установка не будет прервана из-за старого флага
        global CANCEL_OPERATION
        CANCEL_OPERATION = False
        
        # КРИТИЧНО: Проверяем, установлен ли компонент ПЕРЕД установкой статуса
        if self.check_status(component_id, config):
            return True
        
        # ОБНОВЛЯЕМ СТАТУС: устанавливаем 'installing'
        self._update_status(component_id, 'installing')
        
        print(f"Установка компонента: {config['name']}")
        
        # Обновляем прогресс
        self._update_progress(
            stage_name=f"Установка {config['name']}",
            stage_progress=0,
            global_progress=0,
            details=f"Подготовка к установке {component_id}"
        )
        
        # Получаем приоритет источника из конфигурации
        source_priority = config.get('source_priority')  # 'archive', 'url', 'direct' или None
        source_fallback = config.get('source_fallback', True)  # По умолчанию True
        
        # Если приоритет не указан, определяем автоматически на основе доступных источников
        if source_priority is None:
            if config.get('package_file'):
                package_file = config.get('package_file')
                # Если package_file указывает на архив - приоритет архива
                if '.tar.gz/' in package_file or '.tar/' in package_file:
                    source_priority = 'archive'
                # Если package_file - URL - приоритет интернета
                elif package_file.startswith('http://') or package_file.startswith('https://'):
                    source_priority = 'url'
                # Иначе - прямой путь
                else:
                    source_priority = 'direct'
            elif config.get('download_url') or config.get('download_url_x86') or config.get('download_url_x64'):
                # Если есть download_url - приоритет интернета
                source_priority = 'url'
        
        # Получаем файлы компонента через универсальную функцию
        files_result = self._resolve_component_files(
            component_id,
            cleanup_temp=True,
            source_priority=source_priority,
            fallback=source_fallback
        )
        if not files_result or 'default' not in files_result['files']:
            source_priority_display = source_priority if source_priority else 'auto'
            print(f"[ERROR] Файл пакета не найден для {component_id}", level='ERROR')
            print(f"[ERROR] Приоритет источника: {source_priority_display}, fallback: {source_fallback}", level='ERROR')
            self._update_status(component_id, 'error')
            return False
        
        package_path = files_result['files']['default']
        source = files_result.get('source', 'unknown')
        print(f"[INFO] Файл получен из источника: {source}", level='INFO')
        if source == 'archive':
            print(f"[INFO] Файл извлечен из архива", level='INFO')
        elif source == 'url':
            print(f"[INFO] Файл загружен из интернета", level='INFO')
        elif source == 'direct':
            print(f"[INFO] Файл найден по прямому пути", level='INFO')
        temp_dir = files_result.get('temp_dir')
        
        try:
            # Обновляем прогресс
            self._update_progress(
                stage_name=f"Установка {config['name']}",
                stage_progress=50,
                global_progress=50,
                details="Установка через apt..."
            )
            
            # КРИТИЧНО: Проверяем и исправляем состояние dpkg перед установкой
            # Если dpkg был прерван ранее, apt не сможет установить пакет
            print("[INFO] Проверка состояния dpkg перед установкой...", level='INFO')
            
            # Проверяем состояние dpkg по выводу команды (не только по коду возврата)
            # dpkg --audit может вернуть 0, но вывести предупреждения о проблемах
            try:
                dpkg_audit_result = subprocess.run(
                    ['dpkg', '--audit'],
                    stdout=subprocess.PIPE,
                    stderr=subprocess.STDOUT,
                    text=True,
                    timeout=10
                )
                dpkg_output = dpkg_audit_result.stdout or ""
                
                # Проверяем наличие проблем в выводе
                has_problems = False
                if "настроены лишь частично" in dpkg_output or \
                   "частично настроены" in dpkg_output or \
                   "установлены триггеры" in dpkg_output or \
                   "триггеров" in dpkg_output.lower():
                    has_problems = True
                    print("[WARNING] Обнаружены проблемы с dpkg в выводе команды", level='WARNING')
                
                # Если есть проблемы, исправляем автоматически
                if has_problems or dpkg_audit_result.returncode != 0:
                    print("[WARNING] Обнаружены проблемы с dpkg, выполняем автоматическое исправление...", level='WARNING')
                    print("[INFO] Запускаем dpkg --configure -a для восстановления...", level='INFO')
                    
                    configure_result = self._run_process(
                        ['dpkg', '--configure', '-a'],
                        process_type="fix",
                        channels=["file", "terminal", "gui"]
                    )
                    
                    # Также обрабатываем триггеры, если они есть
                    if "триггеров" in dpkg_output.lower() or "триггеры" in dpkg_output.lower():
                        print("[INFO] Обрабатываем необработанные триггеры...", level='INFO')
                        self._run_process(
                            ['dpkg', '--configure', '--pending'],
                            process_type="fix",
                            channels=["file", "terminal", "gui"]
                        )
                    
                    if configure_result == 0:
                        print("[INFO] dpkg восстановлен успешно", level='INFO')
                    else:
                        print("[WARNING] dpkg --configure -a завершился с ошибкой, пробуем apt --fix-broken...", level='WARNING')
                        # Пробуем исправить сломанные зависимости
                        fix_result = self._run_process(
                            ['apt', '--fix-broken', 'install', '-y'],
                            process_type="fix",
                            channels=["file", "terminal", "gui"]
                        )
                        if fix_result == 0:
                            print("[INFO] Сломанные зависимости исправлены", level='INFO')
            except Exception as e:
                print(f"[WARNING] Ошибка проверки состояния dpkg: {e}", level='WARNING')
                # В случае ошибки проверки, все равно пробуем исправить
                print("[INFO] Запускаем dpkg --configure -a для восстановления...", level='INFO')
                self._run_process(
                    ['dpkg', '--configure', '-a'],
                    process_type="fix",
                    channels=["file", "terminal", "gui"]
                )
            
            # Используем UniversalProcessRunner для установки пакета
            return_code = self._run_process(
                ['apt', 'install', '-y', package_path],
                process_type="install",
                channels=["file", "terminal", "gui"]
            )
            
            # Если установка не удалась из-за проблем с dpkg, пробуем исправить и повторить
            if return_code != 0:
                # Проверяем, была ли ошибка связана с dpkg
                print("[INFO] Проверяем причину ошибки установки...", level='INFO')
                
                # Проверяем состояние dpkg по выводу команды
                try:
                    dpkg_audit_result = subprocess.run(
                        ['dpkg', '--audit'],
                        stdout=subprocess.PIPE,
                        stderr=subprocess.STDOUT,
                        text=True,
                        timeout=10
                    )
                    dpkg_output = dpkg_audit_result.stdout or ""
                    
                    # Проверяем наличие проблем в выводе
                    has_problems = False
                    if "настроены лишь частично" in dpkg_output or \
                       "частично настроены" in dpkg_output or \
                       "установлены триггеры" in dpkg_output or \
                       "триггеров" in dpkg_output.lower() or \
                       dpkg_audit_result.returncode != 0:
                        has_problems = True
                    
                    if has_problems:
                        print("[WARNING] Проблемы с dpkg обнаружены после неудачной установки, исправляем...", level='WARNING')
                        print("[INFO] Запускаем dpkg --configure -a...", level='INFO')
                        configure_result = self._run_process(
                            ['dpkg', '--configure', '-a'],
                            process_type="fix",
                            channels=["file", "terminal", "gui"]
                        )
                        
                        # Также обрабатываем триггеры, если они есть
                        if "триггеров" in dpkg_output.lower() or "триггеры" in dpkg_output.lower():
                            print("[INFO] Обрабатываем необработанные триггеры...", level='INFO')
                            self._run_process(
                                ['dpkg', '--configure', '--pending'],
                                process_type="fix",
                                channels=["file", "terminal", "gui"]
                            )
                        
                        if configure_result == 0:
                            print("[INFO] dpkg восстановлен, повторяем установку пакета...", level='INFO')
                            # Повторяем попытку установки
                            return_code = self._run_process(
                                ['apt', 'install', '-y', package_path],
                                process_type="install",
                                channels=["file", "terminal", "gui"]
                            )
                except Exception as e:
                    print(f"[WARNING] Ошибка проверки состояния dpkg после неудачной установки: {e}", level='WARNING')
                    # В случае ошибки проверки, все равно пробуем исправить
                    print("[INFO] Запускаем dpkg --configure -a...", level='INFO')
                    configure_result = self._run_process(
                        ['dpkg', '--configure', '-a'],
                        process_type="fix",
                        channels=["file", "terminal", "gui"]
                    )
                    if configure_result == 0:
                        print("[INFO] dpkg восстановлен, повторяем установку пакета...", level='INFO')
                        return_code = self._run_process(
                            ['apt', 'install', '-y', package_path],
                            process_type="install",
                            channels=["file", "terminal", "gui"]
                        )
            
            if return_code == 0:
                # КРИТИЧНО: Проверяем реальный статус компонента перед сообщением об успехе
                # apt install может вернуть код 0, но пакет не установится
                os.sync()  # Принудительная синхронизация файловой системы
                time.sleep(0.1)  # Минимальная задержка для обновления метаданных
                
                # Проверяем статус компонента
                actual_status = self.check_status(component_id, config)
                
                if actual_status:
                    print(f"Пакет {config['name']} установлен успешно")
                    self._update_progress(
                        stage_name=f"Установка {config['name']}",
                        stage_progress=100,
                        global_progress=100,
                        details=f"{config['name']} установлен успешно"
                    )
                    # ОБНОВЛЯЕМ СТАТУС: устанавливаем 'ok'
                    self._update_status(component_id, 'ok')
                    return True
                else:
                    print(f"apt install завершился успешно, но компонент {config['name']} не установлен", level='ERROR')
                    print(f"Проверка статуса компонента не подтвердила установку", level='ERROR')
                    # ОБНОВЛЯЕМ СТАТУС: устанавливаем 'error'
                    self._update_status(component_id, 'error')
                    return False
            else:
                print(f"Установка пакета {config['name']} (код: {return_code})", level='ERROR')
                # ОБНОВЛЯЕМ СТАТУС: устанавливаем 'error'
                self._update_status(component_id, 'error')
                return False
        finally:
            # Очистка временной директории (если файл был извлечен из архива или загружен)
            if temp_dir and files_result.get('cleanup'):
                source = files_result.get('source', 'unknown')
                print(f"[INFO] Очистка временных файлов (источник: {source})", level='DEBUG')
                try:
                    shutil.rmtree(temp_dir)
                except:
                    pass
    
    @track_class_activity('WinePackageHandler')
    def uninstall(self, component_id: str, config: dict) -> bool:
        """Удаление Wine пакета через apt-get purge"""
        # КРИТИЧНО: Сбрасываем флаг отмены в начале удаления
        # Это гарантирует, что удаление не будет прервано из-за старого флага
        global CANCEL_OPERATION
        CANCEL_OPERATION = False
        
        print(f"WinePackageHandler.uninstall() НАЧАЛО: component_id={component_id}, config={config.get('name', 'Unknown')}", level='DEBUG')
        # ОБНОВЛЯЕМ СТАТУС: устанавливаем 'removing'
        print(f"WinePackageHandler.uninstall() УСТАНАВЛИВАЕМ статус 'removing' для {component_id}", level='DEBUG')
        self._update_status(component_id, 'removing')
        print(f"WinePackageHandler.uninstall() статус 'removing' установлен для {component_id}", level='DEBUG')
        
        # КРИТИЧНО: Добавляем задержку после установки статуса 'removing' для обновления GUI
        # Это гарантирует, что пользователь увидит статус 'removing' перед началом удаления
        time.sleep(0.1)  # Минимальная задержка для обновления GUI
        
        print(f"Удаление компонента: {config['name']}")
        
        package_names = {
            'wine_astraregul': 'wine-astraregul',
            'wine_9': 'wine-9.0',
            'astra_wine_9': 'wine-9.0',
            'astra_wine_astraregul': 'wine-astraregul'
        }
        
        if component_id not in package_names:
            print(f"Неизвестный пакет для удаления: {component_id}", level='ERROR')
            self._update_status(component_id, 'error')
            return False
        
        package_name = package_names[component_id]
        
        # Универсальная логика остановки процессов:
        # Для листовых элементов - останавливаем только свои процессы
        # Для родителей - рекурсивно собираем процессы всех дочек
        print(f"Начало удаления компонента {component_id}", level='DEBUG')
        print(f"Проверка типа компонента (листовой/родитель)...", level='DEBUG')
        
        is_leaf = self._is_leaf_component(component_id)
        print(f"Компонент {component_id} является листовым: {is_leaf}", level='DEBUG')
        
        if is_leaf:
            # ЛИСТОВОЙ ЭЛЕМЕНТ: останавливаем только свои процессы
            own_processes = get_component_field(component_id, 'processes_to_stop', [])
            print(f"Собственные процессы компонента {component_id}: {own_processes}", level='DEBUG')
            if own_processes:
                print(f"Остановка своих процессов (листовой элемент): {', '.join(own_processes)}", level='DEBUG')
                processes_stopped = self._stop_processes(own_processes)
                if not processes_stopped:
                    print(f"Не все процессы остановлены для {component_id}, продолжаем удаление", level='WARNING')
            else:
                print(f"У компонента {component_id} нет процессов для остановки", level='DEBUG')
        else:
            # РОДИТЕЛЬ: рекурсивно собираем процессы всех дочек
            print(f"Сбор всех процессов для родительского компонента {component_id}...", level='DEBUG')
            all_processes = self._collect_all_processes_for_stop(component_id)
            print(f"Собрано процессов для остановки: {sorted(all_processes)}", level='DEBUG')
            if all_processes:
                print(f"Остановка всех процессов (родитель): {', '.join(sorted(all_processes))}", level='DEBUG')
                processes_stopped = self._stop_processes(list(all_processes))
                if not processes_stopped:
                    print(f"Не все процессы остановлены для {component_id}, продолжаем удаление", level='WARNING')
            else:
                print(f"У родительского компонента {component_id} и его дочек нет процессов для остановки", level='DEBUG')
        
        # Удаляем пакет через apt-get purge
        return_code = self._run_process(
            ['apt-get', 'purge', '-y', package_name],
            process_type="remove",
            channels=["file", "terminal"]
        )
        
        if return_code == 0:
            print(f"Пакет {config['name']} удален успешно")
            # Удаляем директории Wine вручную
            wine_dirs = {
                'wine_astraregul': '/opt/wine-astraregul',
                'wine_9': '/opt/wine-9.0',
                'astra_wine_9': '/opt/wine-9.0',
                'astra_wine_astraregul': '/opt/wine-astraregul'
            }
            if component_id in wine_dirs:
                wine_dir = wine_dirs[component_id]
                if os.path.exists(wine_dir):
                    shutil.rmtree(wine_dir)
                    print(f"  Удалена директория: {wine_dir}")
            
            # КРИТИЧНО: Проверяем реальный статус компонента перед установкой 'missing'
            # Это гарантирует, что статус 'missing' устанавливается только после проверки
            os.sync()  # Принудительная синхронизация файловой системы
            
            # Проверяем статус компонента
            actual_status = self.check_status(component_id, config)
            
            if not actual_status:
                # Компонент действительно удален - устанавливаем статус 'missing'
                self._update_status(component_id, 'missing')
                return True
            else:
                # Компонент все еще существует - устанавливаем статус 'error'
                print(f"Пакет {config['name']} не удален (проверка статуса не подтвердила удаление)", level='ERROR')
                self._update_status(component_id, 'error')
                return False
        else:
            print(f"Удаление пакета {config['name']}", level='ERROR')
            # ОБНОВЛЯЕМ СТАТУС: устанавливаем 'error'
            self._update_status(component_id, 'error')
            return False
    
    def check_status(self, component_id: str, config: dict) -> bool:
        """Проверка статуса Wine пакета"""
        # КРИТИЧНО: Используем единую функцию проверки статуса из глобального модуля
        # Используем wineprefix_path=None, чтобы путь определялся автоматически
        # из конфигурации компонента (wineprefix_path в COMPONENTS_CONFIG)
        return check_component_status(component_id, wineprefix_path=None)

# ============================================================================
# ОБРАБОТЧИК СИСТЕМНЫХ НАСТРОЕК
# ============================================================================
class SystemConfigHandler(ComponentHandler):
    """Обработчик системных настроек (ptrace_scope)"""
    
    def get_category(self) -> str:
        return 'system_config'
    
    @track_class_activity('SystemConfigHandler')
    def install(self, component_id: str, config: dict) -> bool:
        """Установка системной настройки"""
        # КРИТИЧНО: Проверяем, установлен ли компонент ПЕРЕД установкой статуса
        if self.check_status(component_id, config):
            return True
        
        # ОБНОВЛЯЕМ СТАТУС: устанавливаем 'installing'
        self._update_status(component_id, 'installing')
        
        print(f"Установка системной настройки: {config['name']}")
        
        if component_id == 'ptrace_scope':
            # Настройка ptrace_scope для Wine
            return_code = self._run_process(
                ['sysctl', '-w', 'kernel.yama.ptrace_scope=0'],
                process_type="config",
                channels=["file", "terminal"]
            )
            
            if return_code == 0:
                # КРИТИЧНО: Проверяем реальный статус компонента перед сообщением об успехе
                time.sleep(0.1)  # Минимальная задержка для применения настройки (sysctl применяется сразу)
                
                # Проверяем статус компонента
                actual_status = self.check_status(component_id, config)
                
                if actual_status:
                    print("ptrace_scope настроен успешно")
                    self._update_status(component_id, 'ok')
                    return True
                else:
                    print("sysctl завершился успешно, но ptrace_scope не настроен", level='ERROR')
                    self._update_status(component_id, 'error')
                    return False
            else:
                print(f"Настройка ptrace_scope (код: {return_code})", level='ERROR')
                self._update_status(component_id, 'error')
                return False
        elif component_id == 'winetricks':
            # Установка winetricks инструмента из архива
            return self._install_winetricks_tool(component_id, config)
        else:
            print(f"Неизвестная системная настройка: {component_id}", level='ERROR')
            self._update_status(component_id, 'error')
            return False
    
    @track_class_activity('SystemConfigHandler')
    def uninstall(self, component_id: str, config: dict) -> bool:
        """Удаление системной настройки (восстановление значения по умолчанию)"""
        # ОБНОВЛЯЕМ СТАТУС: устанавливаем 'removing'
        self._update_status(component_id, 'removing')
        
        print(f"Восстановление системной настройки: {config['name']}")
        
        if component_id == 'ptrace_scope':
            # Восстановление ptrace_scope к значению по умолчанию
            return_code = self._run_process(
                ['sysctl', '-w', 'kernel.yama.ptrace_scope=1'],
                process_type="config",
                channels=["file", "terminal"]
            )
            
            if return_code == 0:
                print("ptrace_scope восстановлен к значению по умолчанию")
                self._update_status(component_id, 'missing')
                return True
            else:
                print(f"Восстановление ptrace_scope (код: {return_code})", level='ERROR')
                self._update_status(component_id, 'error')
                return False
        elif component_id == 'winetricks':
            # Удаление winetricks инструмента (удаление всей папки кэша)
            winetricks_cache_dir = os.path.expanduser('~/.cache/winetricks')
            if os.path.exists(winetricks_cache_dir):
                try:
                    shutil.rmtree(winetricks_cache_dir)
                    print("Winetricks инструмент удален из кэша (удалена папка)")
                    self._update_status(component_id, 'missing')
                    return True
                except Exception as e:
                    print(f"Ошибка удаления winetricks: {e}", level='ERROR')
                    self._update_status(component_id, 'error')
                    return False
            else:
                print("Winetricks инструмент не найден в кэше")
                self._update_status(component_id, 'missing')
                return True
        else:
            print(f"Неизвестная системная настройка для удаления: {component_id}", level='ERROR')
            self._update_status(component_id, 'error')
            return False
    
    def check_status(self, component_id: str, config: dict) -> bool:
        """Проверка статуса системной настройки"""
        # КРИТИЧНО: Используем единую функцию проверки статуса из глобального модуля
        # Для системных настроек с check_method='system_config' проверка значения файла
        # выполняется автоматически в check_component_status()
        # Используем wineprefix_path=None, чтобы путь определялся автоматически
        # из конфигурации компонента (wineprefix_path в COMPONENTS_CONFIG)
        return check_component_status(component_id, wineprefix_path=None)
    
    def _install_winetricks_tool(self, component_id, config):
        """
        Установка winetricks инструмента из архива в кэш пользователя
        
        Args:
            component_id: ID компонента ('winetricks')
            config: Конфигурация компонента
        
        Returns:
            bool: True если установка успешна
        """
        try:
            winetricks_path = os.path.expanduser('~/.cache/winetricks/winetricks')
            
            # Проверяем, не установлен ли уже
            if os.path.exists(winetricks_path) and os.access(winetricks_path, os.X_OK):
                print("Winetricks инструмент уже установлен в кэше")
                self._update_status(component_id, 'ok')
                return True
            
            # Получаем путь к AstraPack
            astrapack_dir = getattr(self, 'astrapack_dir', None)
            if not astrapack_dir:
                # Пытаемся найти AstraPack относительно текущего скрипта
                script_dir = os.path.dirname(os.path.abspath(__file__))
                astrapack_dir = os.path.join(script_dir, 'AstraPack')
            
            # Получаем имя архива из конфигурации
            archive_name = config.get('winetricks_archive_name', 'winetricks_packages.tar.gz')
            
            # Ищем архив в папке Winetricks
            winetricks_dir = os.path.join(astrapack_dir, "Winetricks")
            archive_path = os.path.join(winetricks_dir, archive_name)
            
            if not os.path.exists(archive_path):
                print(f"Архив winetricks не найден: {archive_path}", level='ERROR')
                self._update_status(component_id, 'error')
                return False
            
            print(f"Извлечение winetricks из архива: {archive_path}")
            
            # Создаем папку кэша если нужно
            cache_dir = os.path.dirname(winetricks_path)
            os.makedirs(cache_dir, exist_ok=True)
            fix_dir_permissions(cache_dir)
            
            # Извлекаем winetricks из архива
            with tarfile.open(archive_path, 'r:gz') as tar:
                # Ищем файл winetricks в корне архива
                winetricks_member = None
                for member in tar.getmembers():
                    if member.name == 'winetricks' and member.isfile():
                        winetricks_member = member
                        break
                
                if not winetricks_member:
                    print("Файл winetricks не найден в архиве", level='ERROR')
                    self._update_status(component_id, 'error')
                    return False
                
                # Извлекаем файл
                fileobj = tar.extractfile(winetricks_member)
                if fileobj:
                    file_data = fileobj.read()
                    with open(winetricks_path, 'wb') as f:
                        f.write(file_data)
                    
                    # Устанавливаем права на выполнение
                    os.chmod(winetricks_path, 0o755)
                    
                    # Исправляем владельца файла
                    try:
                        current_uid = os.getuid()
                        if current_uid != 0:  # Не root
                            user_info = pwd.getpwuid(current_uid)
                            os.chown(winetricks_path, current_uid, user_info.pw_gid)
                    except Exception:
                        pass  # Игнорируем ошибки прав доступа
                    
                    print(f"Winetricks инструмент успешно установлен: {winetricks_path}")
                    self._update_status(component_id, 'ok')
                    return True
                else:
                    print("Не удалось извлечь winetricks из архива", level='ERROR')
                    self._update_status(component_id, 'error')
                    return False
                    
        except Exception as e:
            print(f"Ошибка установки winetricks инструмента: {e}", level='ERROR')
            for line in traceback.format_exc().split('\n'):
                if line.strip():
                    print(f"[DEBUG] {line}", level='DEBUG')
            self._update_status(component_id, 'error')
            return False

# ============================================================================
# ОБРАБОТЧИК WINE ОКРУЖЕНИЯ
# ============================================================================
class WineEnvironmentHandler(ComponentHandler):
    """Обработчик Wine окружения (WINEPREFIX)"""
    
    def get_category(self) -> str:
        return 'wine_environment'
    
    def _find_winetricks_archive(self, astrapack_dir, archive_name=None):
        """
        Поиск архива winetricks в папке Winetricks
        
        Args:
            astrapack_dir: Путь к директории AstraPack
            archive_name: Имя архива (если указано, используется оно, иначе поиск по расширению)
        
        Returns:
            str или None: Путь к найденному архиву или None
        """
        if not astrapack_dir:
            return None
        
        winetricks_dir = os.path.join(astrapack_dir, "Winetricks")
        if not os.path.exists(winetricks_dir):
            return None
        
        # Если указано имя архива - используем его
        if archive_name:
            archive_path = os.path.join(winetricks_dir, archive_name)
            if os.path.exists(archive_path) and os.path.isfile(archive_path):
                print(f"[DEBUG] Найден указанный архив winetricks: {archive_name}")
                return archive_path
            else:
                print(f"[DEBUG] Указанный архив не найден: {archive_name}")
                return None
        
        # Иначе ищем первый .tar.gz файл в папке Winetricks (fallback)
        for item in os.listdir(winetricks_dir):
            if item.endswith('.tar.gz'):
                archive_path = os.path.join(winetricks_dir, item)
                if os.path.isfile(archive_path):
                    print(f"[DEBUG] Найден архив winetricks (автопоиск): {item}")
                    return archive_path
        
        return None
    
    @track_class_activity('WineEnvironmentHandler')
    def install(self, component_id: str, config: dict) -> bool:
        """Инициализация Wine окружения"""
        # КРИТИЧНО: Проверяем, установлен ли компонент ПЕРЕД установкой статуса
        if self.check_status(component_id, config):
            return True
        
        # ОБНОВЛЯЕМ СТАТУС: устанавливаем 'installing'
        self._update_status(component_id, 'installing')
        
        print(f"Инициализация Wine окружения: {config['name']}")
        
        try:
            # НОВОЕ: Определяем путь к префиксу из конфигурации
            wineprefix_path = config.get('wineprefix_path')
            if wineprefix_path:
                self.wineprefix = expand_user_path(wineprefix_path)
            else:
                # Используем стандартный префикс
                self.wineprefix = os.path.join(self.home, ".wine-astraregul")
            
            # НОВОЕ: Определяем источник Wine
            wine_source = config.get('wine_source', 'astrapack')
            
            # Создаем директории кэша
            cache_wine = os.path.join(self.home, ".cache", "wine")
            cache_winetricks = os.path.join(self.home, ".cache", "winetricks")
            
            os.makedirs(cache_wine, exist_ok=True)
            os.makedirs(cache_winetricks, exist_ok=True)
            fix_dir_permissions(cache_wine)
            fix_dir_permissions(cache_winetricks)
            print(f"Созданы директории кэша: {cache_wine}, {cache_winetricks}")
            
            # Определяем uid/gid для установки владельца (если запущено от root)
            real_user = os.environ.get('SUDO_USER')
            uid = None
            gid = None
            if os.geteuid() == 0 and real_user and real_user != 'root':
                uid = pwd.getpwnam(real_user).pw_uid
                gid = pwd.getpwnam(real_user).pw_gid
            
            # Копируем wine-gecko компоненты (только если используется AstraPack Wine)
            if wine_source != 'system' and self.astrapack_dir:
                wine_gecko_dir = os.path.join(self.astrapack_dir, "wine-gecko")
                if os.path.exists(wine_gecko_dir):
                    print("Копирование wine-gecko компонентов...")
                    for item in os.listdir(wine_gecko_dir):
                        src = os.path.join(wine_gecko_dir, item)
                        dst = os.path.join(cache_wine, item)
                        if os.path.isfile(src):
                            shutil.copy2(src, dst)
                            if uid is not None and gid is not None:
                                os.chown(dst, uid, gid)
                            print(f"  Скопирован: {item}")
                    print("wine-gecko компоненты скопированы")
            
            # Инициализируем WINEPREFIX если его еще нет
            if not os.path.exists(os.path.join(self.wineprefix, 'system.reg')):
                print(f"Инициализация WINEPREFIX: {self.wineprefix}")
                
                # НОВОЕ: Определяем путь к wineboot в зависимости от источника Wine
                if wine_source == 'system':
                    # Используем системный Wine
                    wine_path = '/usr/bin'
                    wineboot_path = '/usr/bin/wineboot'
                    if not os.path.exists(wineboot_path):
                        # Пробуем найти в PATH
                        result = subprocess.run(['which', 'wineboot'], 
                                              stdout=subprocess.PIPE, 
                                              stderr=subprocess.PIPE, 
                                              text=True, timeout=5)
                        if result.returncode == 0:
                            wineboot_path = result.stdout.strip()
                            wine_path = os.path.dirname(wineboot_path)
                        else:
                            print("wineboot не найден в системе", level='ERROR')
                            self._update_status(component_id, 'error')
                            return False
                else:
                    # Используем Wine из AstraPack
                    wine_path = '/opt/wine-astraregul/bin'
                    wineboot_path = os.path.join(wine_path, 'wineboot')
                
                if not os.path.exists(wineboot_path):
                    print(f"wineboot не найден в {wine_path}", level='ERROR')
                    self._update_status(component_id, 'error')
                    return False
                
                # Создаем директорию WINEPREFIX если не существует
                os.makedirs(self.wineprefix, exist_ok=True)
                
                # КРИТИЧНО: Если запущено от root - устанавливаем владельца директории на пользователя
                # Иначе wineboot не сможет работать с директорией
                if os.geteuid() == 0 and real_user and real_user != 'root':
                    uid = pwd.getpwnam(real_user).pw_uid
                    gid = pwd.getpwnam(real_user).pw_gid
                    # Устанавливаем владельца на всю директорию WINEPREFIX
                    os.chown(self.wineprefix, uid, gid)
                    # Рекурсивно устанавливаем владельца для всех существующих файлов/директорий
                    for root_dir, dirs, files in os.walk(self.wineprefix):
                        try:
                            os.chown(root_dir, uid, gid)
                            for fname in files:
                                os.chown(os.path.join(root_dir, fname), uid, gid)
                        except (OSError, PermissionError):
                            pass  # Игнорируем ошибки доступа к отдельным файлам
                    print(f"Установлен владелец WINEPREFIX на пользователя: {real_user}")
                
                # Настраиваем переменные окружения
                env = os.environ.copy()
                env['WINEPREFIX'] = self.wineprefix
                env['WINEDEBUG'] = '-all'
                env['PATH'] = f'{wine_path}:{env.get("PATH", "")}'
                # КРИТИЧНО: Подавляем диалоги Wine для автоматической установки mono/gecko
                env['WINE_MONO_INSTALL'] = 'disabled'
                env['WINE_GECKO_INSTALL'] = 'disabled'
                env['WINEDLLOVERRIDES'] = 'mscoree,mshtml='
                
                # Если запущено от root - запускаем от имени пользователя
                if os.geteuid() == 0 and real_user and real_user != 'root':
                    # КРИТИЧНО: Экспортируем все переменные окружения для подавления диалогов mono/gecko
                    cmd = textwrap.dedent(f"""
                        export WINEPREFIX="{self.wineprefix}" &&
                        export WINEDEBUG="-all" &&
                        export WINE_MONO_INSTALL="disabled" &&
                        export WINE_GECKO_INSTALL="disabled" &&
                        export WINEDLLOVERRIDES="mscoree,mshtml=" &&
                        export PATH="{wine_path}:$PATH" &&
                        {wineboot_path} --init
                    """).strip()
                    result = subprocess.run(
                        ['su', real_user, '-c', cmd],
                        stdout=subprocess.PIPE,
                        stderr=subprocess.PIPE,
                        universal_newlines=True,
                        timeout=60
                    )
                else:
                    result = subprocess.run(
                        [wineboot_path, '--init'],
                        env=env,
                        stdout=subprocess.PIPE,
                        stderr=subprocess.PIPE,
                        universal_newlines=True,
                        timeout=60
                    )
                
                if result.returncode != 0:
                    print(f"Инициализация WINEPREFIX: {result.stderr}", level='ERROR')
                    self._update_status(component_id, 'error')
                    return False
                
                print("WINEPREFIX успешно инициализирован")
            else:
                print("WINEPREFIX уже существует, пропускаем инициализацию")
            
            # КРИТИЧНО: Проверяем реальный статус компонента перед сообщением об успехе
            # Проверяем статус компонента
            actual_status = self.check_status(component_id, config)
            
            if actual_status:
                # ОБНОВЛЯЕМ СТАТУС: устанавливаем 'ok'
                self._update_status(component_id, 'ok')
                return True
            else:
                print("WINEPREFIX инициализирован, но проверка статуса не подтвердила установку", level='ERROR')
                self._update_status(component_id, 'error')
                return False
            
        except Exception as e:
            print(f"Инициализация Wine окружения: {str(e)}", level='ERROR')
            traceback.print_exc()
            self._update_status(component_id, 'error')
            return False
    
    @track_class_activity('WineEnvironmentHandler')
    def uninstall(self, component_id: str, config: dict) -> bool:
        """Очистка Wine окружения (удаление WINEPREFIX)"""
        print(f"WineEnvironmentHandler.uninstall() НАЧАЛО: component_id={component_id}, config={config.get('name', 'Unknown')}", level='DEBUG')
        print(f"Очистка Wine окружения: {config['name']}")
        
        # КРИТИЧНО: Устанавливаем статус 'removing' сразу, чтобы он отобразился в GUI
        # Это гарантирует, что пользователь видит статус 'removing' для текущего компонента
        self._update_status(component_id, 'removing')
        
        time.sleep(0.1)  # Минимальная задержка для обновления GUI
        
        # НОВОЕ: Определяем путь к префиксу из конфигурации (как в методе install)
        wineprefix_path = config.get('wineprefix_path')
        if wineprefix_path:
            target_wineprefix = expand_user_path(wineprefix_path)
        else:
            # Используем стандартный префикс
            target_wineprefix = self.wineprefix
        
        # Проверяем, существует ли компонент
        # Если компонент уже удален, устанавливаем статус 'missing' и выходим
        if not os.path.exists(target_wineprefix):
            print("WINEPREFIX не найден (папка уже удалена или не была создана)")
            # ОБНОВЛЯЕМ СТАТУС: устанавливаем 'missing' для уже удаленного компонента
            self._update_status(component_id, 'missing')
            return True
        
        try:
            # Универсальная логика остановки процессов:
            # wineprefix - это родительский компонент, поэтому собираем процессы всех дочек
            all_processes = self._collect_all_processes_for_stop(component_id)
            if all_processes:
                print(f"Остановка всех процессов (родитель): {', '.join(sorted(all_processes))}")
                processes_stopped = self._stop_processes(list(all_processes))
                if not processes_stopped:
                    print(f"Не все процессы остановлены для {component_id}, продолжаем удаление", level='WARNING')
            
            # КРИТИЧНО: Удаляем WINEPREFIX в любом случае
            # Даже если компонент числится как неустановленный - папка может существовать
            if os.path.exists(target_wineprefix):
                print(f"Удаление WINEPREFIX: {target_wineprefix}")
                shutil.rmtree(target_wineprefix)
                print("WINEPREFIX удален успешно")
            else:
                print("WINEPREFIX не найден (папка уже удалена или не была создана)")
            
            # Удаляем кэши (опционально, но лучше удалить для полной очистки)
            cache_wine = os.path.join(self.home, ".cache", "wine")
            cache_winetricks = os.path.join(self.home, ".cache", "winetricks")
            
            if os.path.exists(cache_wine):
                print(f"Удаление кэша Wine: {cache_wine}")
                shutil.rmtree(cache_wine)
                print("Кэш Wine удален")
            
            if os.path.exists(cache_winetricks):
                print(f"Удаление кэша winetricks: {cache_winetricks}")
                shutil.rmtree(cache_winetricks)
                print("Кэш winetricks удален")
            
            os.sync()  # Принудительная синхронизация файловой системы
            
            # Проверяем статус компонента
            actual_status = self.check_status(component_id, config)
            
            if not actual_status:
                # Компонент действительно удален - устанавливаем статус 'missing'
                self._update_status(component_id, 'missing')
                return True
            else:
                # Компонент все еще существует - устанавливаем статус 'error'
                print(f"WINEPREFIX не удален (проверка статуса не подтвердила удаление)", level='ERROR')
                self._update_status(component_id, 'error')
                return False
            
        except Exception as e:
            print(f"Очистка Wine окружения: {str(e)}", level='ERROR')
            traceback.print_exc()
            self._update_status(component_id, 'error')
            return False
    
    def check_status(self, component_id: str, config: dict) -> bool:
        """Проверка статуса Wine окружения"""
        # КРИТИЧНО: Используем единую функцию проверки статуса из глобального модуля
        # НЕ передаем wineprefix_path - глобальная функция сама определит его из конфигурации компонента
        return check_component_status(component_id, wineprefix_path=None)
    
    def _get_script_dir(self):
        """Получить директорию скрипта"""
        return os.path.dirname(os.path.abspath(__file__))
    
    def create_wineprefix_template(self, component_id: str, config: dict, 
                                    archive_name: str = None, 
                                    output_dir: str = None,
                                    clean_temp: bool = True,
                                    clean_cache: bool = False,
                                    gui_instance=None) -> str:
        """
        Создать архив образа Wine-префикса (самый быстрый метод через системный tar)
        
        Args:
            component_id: ID компонента wineprefix
            config: Конфигурация компонента
            archive_name: Имя архива (если None, генерируется автоматически)
            output_dir: Директория для сохранения (если None, используется AstraPack/WinePrefixes/)
            clean_temp: Очистить временные файлы перед архивацией
            clean_cache: Очистить кэш перед архивацией
            gui_instance: Экземпляр GUI для обновления прогресса
        
        Returns:
            str: Путь к созданному архиву или None в случае ошибки
        """
        global CANCEL_OPERATION
        
        # Сбрасываем флаг отмены
        CANCEL_OPERATION = False
        
        print(f"Создание образа Wine-префикса: {config.get('name', component_id)}")
        
        # 1. Определяем путь к префиксу
        wineprefix_path = config.get('wineprefix_path')
        if wineprefix_path:
            wineprefix_path = expand_user_path(wineprefix_path)
        else:
            wineprefix_path = self.wineprefix
        
        if not os.path.exists(wineprefix_path):
            print(f"WINEPREFIX не найден: {wineprefix_path}", level='ERROR')
            return None
        
        # Проверяем наличие system.reg
        system_reg = os.path.join(wineprefix_path, 'system.reg')
        if not os.path.exists(system_reg):
            print(f"WINEPREFIX не инициализирован (нет system.reg): {wineprefix_path}", level='ERROR')
            return None
        
        # 2. Останавливаем все Wine-процессы
        print("Остановка всех Wine-процессов...")
        if gui_instance:
            gui_instance.root.after(0, lambda: gui_instance.wine_stage_label.config(
                text="Остановка Wine-процессов...", fg='blue'
            ))
        
        all_processes = self._collect_all_processes_for_stop(component_id)
        if all_processes:
            print(f"Остановка процессов: {', '.join(sorted(all_processes))}")
            processes_stopped = self._stop_processes(list(all_processes), max_wait_time=30)
            if not processes_stopped:
                print("Не все процессы остановлены, продолжаем архивацию", level='WARNING')
        
        self._terminate_wineserver()
        time.sleep(2)
        
        # 3. Очистка (опционально)
        if clean_temp:
            print("Очистка временных файлов...")
            if gui_instance:
                gui_instance.root.after(0, lambda: gui_instance.wine_stage_label.config(
                    text="Очистка временных файлов...", fg='blue'
                ))
            # Очистка временных файлов
            temp_patterns = ['*.tmp', '*.log', '*.bak']
            for root, dirs, files in os.walk(wineprefix_path):
                for file in files:
                    if any(file.endswith(pattern.replace('*', '')) for pattern in temp_patterns):
                        try:
                            file_path = os.path.join(root, file)
                            os.remove(file_path)
                        except:
                            pass
        
        # 4. Определяем путь для сохранения архива
        if not output_dir:
            if self.astrapack_dir:
                output_dir = os.path.join(self.astrapack_dir, 'WinePrefixes')
            else:
                script_dir = self._get_script_dir()
                output_dir = os.path.join(script_dir, 'WinePrefixes')
        
        os.makedirs(output_dir, exist_ok=True)
        
        # 5. Генерируем имя архива
        if not archive_name:
            archive_name = f"{component_id}_template.tar.gz"
        
        archive_path = os.path.join(output_dir, archive_name)
        
        if os.path.exists(archive_path):
            print(f"Архив уже существует: {archive_path}", level='WARNING')
        
        # 6. Подсчитываем размер для прогресса
        print("Подсчет размера архива...")
        if gui_instance:
            gui_instance.root.after(0, lambda: gui_instance.wine_stage_label.config(
                text="Подсчет размера...", fg='blue'
            ))
        
        total_size = 0
        total_files = 0
        total_dirs = 0
        
        for root, dirs, files in os.walk(wineprefix_path):
            if CANCEL_OPERATION:
                print("Операция отменена пользователем")
                return None
            total_dirs += len(dirs)
            for file in files:
                file_path = os.path.join(root, file)
                try:
                    total_size += os.path.getsize(file_path)
                    total_files += 1
                except:
                    pass
        
        # Форматируем размер
        if total_size < 1024 * 1024:
            size_str = f"{total_size / 1024:.1f} КБ"
        elif total_size < 1024 * 1024 * 1024:
            size_str = f"{total_size / (1024 * 1024):.1f} МБ"
        else:
            size_str = f"{total_size / (1024 * 1024 * 1024):.2f} ГБ"
        
        print(f"Размер архива: {size_str} ({total_files} файлов, {total_dirs} папок)")
        
        # 7. Инициализируем прогресс в GUI
        if gui_instance:
            gui_instance.root.after(0, lambda: gui_instance.wine_progress.config(maximum=100, value=0))
            gui_instance.root.after(0, lambda: gui_instance.wine_time_label.config(text="0 мин 0 сек"))
            gui_instance.root.after(0, lambda: gui_instance.wine_size_label.config(text="0 MB"))
            gui_instance.root.after(0, lambda: gui_instance.wine_stage_label.config(
                text="Создание архива...", fg='blue'
            ))
        
        start_time = time.time()
        
        # 8. Создаем архив через системный tar с мониторингом прогресса
        print(f"Создание архива: {archive_path}")
        
        # Проверяем наличие tar
        if not self._check_command_available('tar'):
            print("Команда tar не найдена, используем Python tarfile (медленнее)", level='WARNING')
            return self._create_archive_with_tarfile(wineprefix_path, archive_path, gui_instance, 
                                                    start_time, total_size, total_files)
        
        # Строим команду tar
        # ПРОВЕРКА: Убеждаемся, что пути существуют и правильные
        if not os.path.exists(wineprefix_path):
            print(f"[ERROR] Путь wineprefix не существует: {wineprefix_path}", level='ERROR')
            return None
        
        if not os.path.isdir(wineprefix_path):
            print(f"[ERROR] Путь wineprefix не является директорией: {wineprefix_path}", level='ERROR')
            return None
        
        # Проверяем родительскую директорию
        parent_dir = os.path.dirname(wineprefix_path)
        if not os.path.exists(parent_dir):
            print(f"[ERROR] Родительская директория не существует: {parent_dir}", level='ERROR')
            return None
        
        # Получаем абсолютные пути для надежности
        wineprefix_path_abs = os.path.abspath(wineprefix_path)
        archive_path_abs = os.path.abspath(archive_path)
        parent_dir_abs = os.path.abspath(parent_dir)
        basename = os.path.basename(wineprefix_path_abs)
        
        print(f"[DEBUG] Создание архива:")
        print(f"[DEBUG]   wineprefix_path: {wineprefix_path_abs}")
        print(f"[DEBUG]   archive_path: {archive_path_abs}")
        print(f"[DEBUG]   parent_dir: {parent_dir_abs}")
        print(f"[DEBUG]   basename: {basename}")
        
        tar_cmd = [
            'tar',
            '-czf',  # -c (create), -z (gzip), -f (file)
            archive_path_abs,
            '-C', parent_dir_abs,  # Переходим в родительскую директорию
            basename  # Архивируем только папку префикса
        ]
        
        print(f"[DEBUG] Команда tar: {' '.join(tar_cmd)}")
        
        # Запускаем tar в отдельном процессе
        process = subprocess.Popen(
            tar_cmd,
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            cwd=parent_dir_abs  # Устанавливаем рабочую директорию
        )
        
        # Собираем список всех файлов для отслеживания текущего (в фоне, не блокируя запуск tar)
        all_files = []
        cumulative_sizes = []
        cumulative_size = 0
        files_ready = threading.Event()  # Событие готовности списка файлов
        
        def collect_files():
            """Сбор списка файлов в фоне"""
            nonlocal cumulative_size
            try:
                for root, dirs, files in os.walk(wineprefix_path):
                    for file in files:
                        file_path = os.path.join(root, file)
                        try:
                            file_size = os.path.getsize(file_path)
                            arcname = os.path.relpath(file_path, wineprefix_path)
                            all_files.append(arcname)
                            cumulative_size += file_size
                            cumulative_sizes.append(cumulative_size)
                        except:
                            pass
            finally:
                files_ready.set()  # Сигнализируем о готовности
        
        # Запускаем сбор файлов в отдельном потоке (не блокируем запуск tar)
        collect_thread = threading.Thread(target=collect_files, daemon=True)
        collect_thread.start()
        
        # Переменная для хранения текущего обрабатываемого файла
        current_file = [os.path.basename(wineprefix_path)]  # Используем список для изменения из вложенной функции
        
        # Флаг для остановки потока мониторинга
        monitoring_active = threading.Event()
        monitoring_active.set()  # Устанавливаем флаг активным
        
        # Мониторим прогресс через обход файлов
        def monitor_progress():
            """Мониторинг прогресса архивации"""
            while monitoring_active.is_set() and process.poll() is None:
                if CANCEL_OPERATION:
                    print("Операция отменена, завершаем процесс...")
                    process.terminate()
                    try:
                        process.wait(timeout=5)
                    except subprocess.TimeoutExpired:
                        process.kill()
                    return
                
                # Проверяем размер создаваемого архива
                if os.path.exists(archive_path):
                    try:
                        current_archive_size = os.path.getsize(archive_path)
                        # Приблизительный прогресс на основе размера архива
                        # Используем более консервативный коэффициент сжатия (0.6) для расчета максимума
                        # Но не ограничиваем прогресс - он может достичь 100%
                        if total_size > 0:
                            estimated_final_size = total_size * 0.6  # Более консервативная оценка
                            progress = min(100, (current_archive_size / max(estimated_final_size, 1)) * 100)
                        else:
                            progress = 0
                        
                        # Определяем текущий файл на основе размера архива (только если список готов)
                        if files_ready.is_set() and cumulative_sizes and current_archive_size > 0:
                            # Предполагаем коэффициент сжатия ~0.7 (архив примерно 70% от исходного размера)
                            estimated_processed_size = current_archive_size / 0.7
                            # Бинарный поиск для быстрого нахождения файла (O(log n) вместо O(n))
                            idx = bisect.bisect_left(cumulative_sizes, estimated_processed_size)
                            if idx < len(all_files):
                                # Показываем только папку, без имени файла
                                file_path = all_files[idx]
                                dir_path = os.path.dirname(file_path)
                                current_file[0] = dir_path if dir_path else os.path.basename(wineprefix_path)
                            elif all_files:
                                # Показываем только папку последнего файла
                                last_file = all_files[-1]
                                dir_path = os.path.dirname(last_file)
                                current_file[0] = dir_path if dir_path else os.path.basename(wineprefix_path)
                        
                        elapsed_time = time.time() - start_time
                        elapsed_minutes = int(elapsed_time // 60)
                        elapsed_seconds = int(elapsed_time % 60)
                        
                        # Использование диска (размер архива)
                        if current_archive_size < 1024 * 1024:
                            disk_str = f"{current_archive_size / 1024:.1f} КБ"
                        elif current_archive_size < 1024 * 1024 * 1024:
                            disk_str = f"{current_archive_size / (1024 * 1024):.1f} МБ"
                        else:
                            disk_str = f"{current_archive_size / (1024 * 1024 * 1024):.2f} ГБ"
                        
                        # Обновляем GUI
                        if gui_instance:
                            gui_instance.root.after(0, lambda p=progress: gui_instance.wine_progress.config(value=p))
                            gui_instance.root.after(0, lambda t=f"{elapsed_minutes} мин {elapsed_seconds} сек": 
                                                    gui_instance.wine_time_label.config(text=t))
                            gui_instance.root.after(0, lambda d=disk_str: gui_instance.wine_size_label.config(text=d))
                            gui_instance.root.after(0, lambda cf=current_file[0]: gui_instance.wine_stage_label.config(
                                text=f"Архивация: {self._truncate_path(cf, 60)}", fg='blue'
                            ))
                    except:
                        pass
                
                time.sleep(0.5)  # Обновляем каждые 0.5 секунды
        
        # Запускаем мониторинг в отдельном потоке
        monitor_thread = threading.Thread(target=monitor_progress, daemon=True)
        monitor_thread.start()
        
        # Ждем завершения процесса
        try:
            stdout, stderr = process.communicate()
            
            # Останавливаем поток мониторинга
            monitoring_active.clear()
            
            # Закрываем файловые дескрипторы процесса
            if process.stdout:
                try:
                    process.stdout.close()
                except:
                    pass
            if process.stderr:
                try:
                    process.stderr.close()
                except:
                    pass
            
            # КРИТИЧНО: Убеждаемся, что процесс полностью завершился
            if process.poll() is None:
                print("[WARNING] Процесс tar еще не завершился, ждем...", level='WARNING')
                try:
                    process.wait(timeout=30)  # Ждем до 30 секунд
                except subprocess.TimeoutExpired:
                    print("[ERROR] Процесс tar не завершился за 30 секунд!", level='ERROR')
                    # Завершаем все дочерние процессы
                    try:
                        if PSUTIL_AVAILABLE:
                            parent = psutil.Process(process.pid)
                            children = parent.children(recursive=True)
                            for child in children:
                                try:
                                    child.terminate()
                                except:
                                    pass
                            # Ждем завершения дочерних процессов
                            gone, alive = psutil.wait_procs(children, timeout=5)
                            for child in alive:
                                try:
                                    child.kill()
                                except:
                                    pass
                    except:
                        pass
                    process.kill()
                    process.wait()
                    return None
            
            # Проверяем, что процесс завершился с кодом
            if process.returncode is None:
                print("[ERROR] Не удалось получить код возврата процесса tar", level='ERROR')
                return None
            
            if CANCEL_OPERATION:
                # Удаляем частично созданный архив
                if os.path.exists(archive_path):
                    try:
                        os.remove(archive_path)
                    except:
                        pass
                if gui_instance:
                    gui_instance.root.after(0, lambda: gui_instance.wine_stage_label.config(
                        text="Операция отменена", fg='orange'
                    ))
                return None
            
            if process.returncode != 0:
                error_msg = stderr.decode('utf-8', errors='ignore') if stderr else "Неизвестная ошибка"
                stdout_msg = stdout.decode('utf-8', errors='ignore') if stdout else ""
                print(f"Ошибка создания архива (код {process.returncode}): {error_msg}", level='ERROR')
                if stdout_msg:
                    print(f"[DEBUG] stdout: {stdout_msg}", level='DEBUG')
                print(f"[DEBUG] Команда была: {' '.join(tar_cmd)}", level='DEBUG')
                if gui_instance:
                    gui_instance.root.after(0, lambda: gui_instance.wine_stage_label.config(
                        text="Ошибка создания архива", fg='red'
                    ))
                return None
            
            # Успешное завершение
            # Небольшая задержка для завершения записи архива
            time.sleep(0.5)
            
            # КРИТИЧНО: Убеждаемся, что все дочерние процессы завершены
            try:
                if PSUTIL_AVAILABLE and process.pid:
                    try:
                        parent = psutil.Process(process.pid)
                        # Проверяем, не остались ли дочерние процессы
                        children = parent.children(recursive=True)
                        if children:
                            print(f"[DEBUG] Обнаружено {len(children)} дочерних процессов, ожидаем их завершения...", level='DEBUG')
                            gone, alive = psutil.wait_procs(children, timeout=5)
                            if alive:
                                print(f"[WARNING] {len(alive)} дочерних процессов не завершились, принудительно завершаем...", level='WARNING')
                                for child in alive:
                                    try:
                                        child.kill()
                                    except:
                                        pass
                    except (psutil.NoSuchProcess, psutil.AccessDenied):
                        # Процесс уже завершен или нет доступа
                        pass
            except Exception as e:
                print(f"[DEBUG] Ошибка проверки дочерних процессов: {e}", level='DEBUG')
            
            # КРИТИЧНО: Синхронизируем файловую систему для гарантии записи
            try:
                sync_result = subprocess.run(['sync'], timeout=10, 
                                            stdout=subprocess.PIPE, stderr=subprocess.PIPE)
                if sync_result.returncode != 0:
                    print(f"[WARNING] Ошибка синхронизации файловой системы: {sync_result.stderr.decode('utf-8', errors='ignore')}", level='WARNING')
            except Exception as e:
                print(f"[WARNING] Не удалось синхронизировать файловую систему: {e}", level='WARNING')
            
            # Проверяем, что архив существует и доступен (используем абсолютный путь)
            if not os.path.exists(archive_path_abs):
                print(f"[ERROR] Архив не найден после создания: {archive_path_abs}", level='ERROR')
                return None
            
            # Убеждаемся, что файл полностью записан и доступен
            max_retries = 5
            retry_count = 0
            archive_size = 0
            while retry_count < max_retries:
                try:
                    # Пытаемся получить размер файла
                    archive_size = os.path.getsize(archive_path_abs)
                    # Пытаемся открыть файл для чтения
                    with open(archive_path_abs, 'rb') as test_file:
                        test_file.seek(0, 2)  # Переходим в конец файла
                        actual_size = test_file.tell()
                    if archive_size == actual_size and archive_size > 0:
                        break  # Файл готов
                    else:
                        retry_count += 1
                        if retry_count < max_retries:
                            time.sleep(1)  # Ждем 1 секунду перед повторной попыткой
                except (IOError, OSError) as e:
                    retry_count += 1
                    if retry_count >= max_retries:
                        print(f"[ERROR] Архив недоступен после {max_retries} попыток: {e}", level='ERROR')
                        return None
                    time.sleep(1)  # Ждем 1 секунду перед повторной попыткой
            
            # Проверяем размер архива (должен быть больше 0)
            if archive_size == 0:
                print(f"[ERROR] Архив создан, но имеет размер 0 байт!", level='ERROR')
                if os.path.exists(archive_path_abs):
                    try:
                        os.remove(archive_path_abs)
                    except:
                        pass
                return None
            
            # Проверяем целостность архива (пытаемся открыть и прочитать заголовок)
            try:
                with gzip.open(archive_path_abs, 'rb') as f:
                    # Читаем первые несколько байт для проверки
                    header = f.read(512)
                    if len(header) < 100:  # Минимальный размер для валидного tar.gz
                        print(f"[WARNING] Архив слишком мал или поврежден (заголовок: {len(header)} байт)", level='WARNING')
            except Exception as e:
                print(f"[WARNING] Не удалось проверить целостность архива: {e}", level='WARNING')
                # Не возвращаем None, так как это может быть ложная тревога
            
            elapsed_time = time.time() - start_time
            elapsed_minutes = int(elapsed_time // 60)
            elapsed_seconds = int(elapsed_time % 60)
            
            # Финальное обновление GUI
            if gui_instance:
                gui_instance.root.after(0, lambda: gui_instance.wine_progress.config(value=100))
                gui_instance.root.after(0, lambda t=f"{elapsed_minutes} мин {elapsed_seconds} сек": 
                                        gui_instance.wine_time_label.config(text=t))
                
                # Финальный размер архива (уже получен выше при проверке)
                if archive_size < 1024 * 1024:
                    disk_str = f"{archive_size / 1024:.1f} КБ"
                elif archive_size < 1024 * 1024 * 1024:
                    disk_str = f"{archive_size / (1024 * 1024):.1f} МБ"
                else:
                    disk_str = f"{archive_size / (1024 * 1024 * 1024):.2f} ГБ"
                
                gui_instance.root.after(0, lambda d=disk_str: gui_instance.wine_size_label.config(text=d))
                gui_instance.root.after(0, lambda: gui_instance.wine_stage_label.config(
                    text="Архив создан успешно", fg='green'
                ))
            
            print(f"Архив создан успешно за {elapsed_minutes}м {elapsed_seconds}с")
            print(f"Путь: {archive_path}")
            
            # Устанавливаем права пользователя на архив и папку
            try:
                real_user = os.environ.get('SUDO_USER')
                if os.geteuid() == 0 and real_user and real_user != 'root':
                    uid = pwd.getpwnam(real_user).pw_uid
                    gid = pwd.getpwnam(real_user).pw_gid
                    # Устанавливаем владельца на архив (используем абсолютный путь)
                    os.chown(archive_path_abs, uid, gid)
                    # Устанавливаем владельца на папку output_dir
                    os.chown(output_dir, uid, gid)
                    print(f"Установлен владелец архива и папки на пользователя: {real_user}")
            except Exception as e:
                print(f"Предупреждение: не удалось установить права доступа: {e}", level='WARNING')
            
            # Возвращаем оригинальный путь (не абсолютный)
            return archive_path
            
        except Exception as e:
            # Останавливаем поток мониторинга при ошибке
            if 'monitoring_active' in locals():
                monitoring_active.clear()
            # Закрываем файловые дескрипторы процесса
            if 'process' in locals():
                try:
                    if process.stdout:
                        process.stdout.close()
                    if process.stderr:
                        process.stderr.close()
                    # Завершаем процесс если он еще работает
                    if process.poll() is None:
                        process.terminate()
                        try:
                            process.wait(timeout=5)
                        except:
                            process.kill()
                            process.wait()
                except:
                    pass
            print(f"Ошибка при создании архива: {e}", level='ERROR')
            traceback.print_exc()
            if gui_instance:
                gui_instance.root.after(0, lambda: gui_instance.wine_stage_label.config(
                    text="Ошибка создания архива", fg='red'
                ))
            return None
    
    def _create_archive_with_tarfile(self, wineprefix_path, archive_path, gui_instance, 
                                     start_time, total_size, total_files):
        """Fallback: создание архива через Python tarfile (медленнее)"""
        global CANCEL_OPERATION
        
        try:
            processed_size = 0
            processed_files = 0  # Счетчик обработанных файлов
            with tarfile.open(archive_path, 'w:gz') as tar:
                # Добавляем весь префикс
                for root, dirs, files in os.walk(wineprefix_path):
                    if CANCEL_OPERATION:
                        return None
                    
                    for file in files:
                        if CANCEL_OPERATION:
                            return None
                        
                        file_path = os.path.join(root, file)
                        arcname = os.path.relpath(file_path, wineprefix_path)
                        # Получаем относительный путь к папке (без имени файла)
                        folder_path = os.path.relpath(root, wineprefix_path)
                        
                        try:
                            tar.add(file_path, arcname=arcname)
                            processed_size += os.path.getsize(file_path)
                            processed_files += 1  # Увеличиваем счетчик файлов
                            
                            # Обновляем прогресс по количеству файлов (более точно)
                            if gui_instance and total_files > 0:
                                progress = min(100, (processed_files / total_files) * 100)
                                elapsed_time = time.time() - start_time
                                elapsed_minutes = int(elapsed_time // 60)
                                elapsed_seconds = int(elapsed_time % 60)
                                
                                gui_instance.root.after(0, lambda p=progress: 
                                    gui_instance.wine_progress.config(value=p))
                                gui_instance.root.after(0, lambda t=f"{elapsed_minutes} мин {elapsed_seconds} сек": 
                                    gui_instance.wine_time_label.config(text=t))
                                gui_instance.root.after(0, lambda fp=folder_path if folder_path != '.' else os.path.basename(wineprefix_path): gui_instance.wine_stage_label.config(
                                    text=f"Архивация: {self._truncate_path(fp, 60)}", fg='blue'
                                ))
                        except:
                            pass
            
            # Финальное обновление GUI после успешного завершения
            if gui_instance:
                elapsed_time = time.time() - start_time
                elapsed_minutes = int(elapsed_time // 60)
                elapsed_seconds = int(elapsed_time % 60)
                
                # Устанавливаем 100% прогресс
                gui_instance.root.after(0, lambda: gui_instance.wine_progress.config(value=100))
                gui_instance.root.after(0, lambda t=f"{elapsed_minutes} мин {elapsed_seconds} сек": 
                    gui_instance.wine_time_label.config(text=t))
                
                # Финальный размер архива
                archive_size = os.path.getsize(archive_path)
                if archive_size < 1024 * 1024:
                    disk_str = f"{archive_size / 1024:.1f} КБ"
                elif archive_size < 1024 * 1024 * 1024:
                    disk_str = f"{archive_size / (1024 * 1024):.1f} МБ"
                else:
                    disk_str = f"{archive_size / (1024 * 1024 * 1024):.2f} ГБ"
                
                gui_instance.root.after(0, lambda d=disk_str: gui_instance.wine_size_label.config(text=d))
                gui_instance.root.after(0, lambda: gui_instance.wine_stage_label.config(
                    text="Архив создан успешно", fg='green'
                ))
            
            print(f"Архив создан успешно за {elapsed_minutes}м {elapsed_seconds}с")
            print(f"Обработано файлов: {processed_files} из {total_files}")
            print(f"Путь: {archive_path}")
            
            # Устанавливаем права пользователя на архив и папку
            try:
                real_user = os.environ.get('SUDO_USER')
                if os.geteuid() == 0 and real_user and real_user != 'root':
                    uid = pwd.getpwnam(real_user).pw_uid
                    gid = pwd.getpwnam(real_user).pw_gid
                    # Устанавливаем владельца на архив
                    os.chown(archive_path, uid, gid)
                    # Устанавливаем владельца на папку output_dir (получаем из archive_path)
                    output_dir = os.path.dirname(archive_path)
                    if os.path.exists(output_dir):
                        os.chown(output_dir, uid, gid)
                    print(f"Установлен владелец архива и папки на пользователя: {real_user}")
            except Exception as e:
                print(f"Предупреждение: не удалось установить права доступа: {e}", level='WARNING')
            
            return archive_path
        except Exception as e:
            print(f"Ошибка создания архива через tarfile: {e}", level='ERROR')
            return None

# ============================================================================
# ОБРАБОТЧИК WINETRICKS КОМПОНЕНТОВ
# ============================================================================
class WinetricksHandler(ComponentHandler):
    """Обработчик winetricks компонентов (wine_mono, dotnet48, vcrun2013, и т.д.)"""
    
    def __init__(self, use_minimal=False, **kwargs):
        """
        Инициализация обработчика winetricks
        
        Args:
            use_minimal: Использовать минимальный winetricks (по умолчанию False)
            **kwargs: Остальные параметры для ComponentHandler
        """
        super().__init__(**kwargs)
        self.use_minimal = use_minimal
        self.astrapack_dir_for_winetricks = self.astrapack_dir  # Сохраняем для ленивой инициализации
        self.winetricks_manager = None  # Создадим при первом использовании (ленивая инициализация)
    
    def _find_winetricks_archive(self, astrapack_dir, archive_name=None):
        """
        Поиск архива winetricks в папке Winetricks
        
        Args:
            astrapack_dir: Путь к директории AstraPack
            archive_name: Имя архива (если указано, используется оно, иначе поиск по расширению)
        
        Returns:
            str или None: Путь к найденному архиву или None
        """
        if not astrapack_dir:
            return None
        
        winetricks_dir = os.path.join(astrapack_dir, "Winetricks")
        if not os.path.exists(winetricks_dir):
            return None
        
        # Если указано имя архива - используем его
        if archive_name:
            archive_path = os.path.join(winetricks_dir, archive_name)
            if os.path.exists(archive_path) and os.path.isfile(archive_path):
                print(f"[DEBUG] Найден указанный архив winetricks: {archive_name}")
                return archive_path
            else:
                print(f"[DEBUG] Указанный архив не найден: {archive_name}")
                return None
        
        # Иначе ищем первый .tar.gz файл в папке Winetricks (fallback)
        for item in os.listdir(winetricks_dir):
            if item.endswith('.tar.gz'):
                archive_path = os.path.join(winetricks_dir, item)
                if os.path.isfile(archive_path):
                    print(f"[DEBUG] Найден архив winetricks (автопоиск): {item}")
                    return archive_path
        
        return None
    
    def _get_winetricks_manager(self):
        """Ленивая инициализация WinetricksManager - создается только при реальном использовании"""
        if self.winetricks_manager is None:
            self.winetricks_manager = WinetricksManager(
                self.astrapack_dir_for_winetricks, 
                use_minimal=self.use_minimal
            )
        return self.winetricks_manager
    
    def _get_component_extract_info(self, config, component_id):
        """
        Определяет что нужно извлечь из конфигурации компонента
        
        Поддерживает:
        - Один файл: download_filename
        - Два файла: download_filename_x86/x64 или download_filename_32/64
        - Множественные файлы: download_filenames (список)
        - Целую папку: download_folder или download_path
        
        Args:
            config: Конфигурация компонента
            component_id: ID компонента
        
        Returns:
            dict: {
                'files': [список файлов],
                'folders': [список папок],
                'extract_mode': 'files' | 'folder'
            }
        """
        result = {
            'files': [],
            'folders': [],
            'extract_mode': None
        }
        
        # ПРИОРИТЕТ 1: Проверяем папку (если указана)
        if config.get('download_folder'):
            folder_name = config.get('download_folder')
            result['folders'].append(folder_name)
            result['extract_mode'] = 'folder'
            return result
        
        if config.get('download_path'):
            folder_path = config.get('download_path')
            result['folders'].append(folder_path)
            result['extract_mode'] = 'folder'
            return result
        
        # ПРИОРИТЕТ 2: Проверяем список файлов (любое количество)
        if config.get('download_filenames'):
            files_list = config.get('download_filenames')
            if isinstance(files_list, list) and len(files_list) > 0:
                result['files'].extend(files_list)
                result['extract_mode'] = 'files'
                return result
        
        # ПРИОРИТЕТ 3: Проверяем множественные файлы (x86/x64, 32/64)
        if config.get('download_filename_x86') and config.get('download_filename_x64'):
            result['files'].extend([
                config.get('download_filename_x86'),
                config.get('download_filename_x64')
            ])
            result['extract_mode'] = 'files'
            return result
        
        if config.get('download_filename_32') and config.get('download_filename_64'):
            result['files'].extend([
                config.get('download_filename_32'),
                config.get('download_filename_64')
            ])
            result['extract_mode'] = 'files'
            return result
        
        # ПРИОРИТЕТ 4: Один файл
        if config.get('download_filename'):
            result['files'].append(config.get('download_filename'))
            result['extract_mode'] = 'files'
            return result
        
        # ПРИОРИТЕТ 5: Нет параметров - используем component_id как папку
        result['folders'].append(component_id)
        result['extract_mode'] = 'folder'
        return result
    
    def _extract_from_archive(self, archive_path, extract_info, component_id, user_cache_dir):
        """
        Извлечение файлов/папок из архива сразу в кэш пользователя
        
        Args:
            archive_path: Путь к архиву
            extract_info: Информация о том, что извлекать (из _get_component_extract_info)
            component_id: ID компонента
            user_cache_dir: Путь к кэшу пользователя (~/.cache/winetricks)
        
        Returns:
            int: Количество извлеченных файлов
        """
        os.makedirs(user_cache_dir, exist_ok=True)
        fix_dir_permissions(user_cache_dir)
        
        try:
            archive_size = os.path.getsize(archive_path)
            print(f"[DEBUG] Размер архива: {archive_size} байт ({archive_size / (1024*1024):.2f} МБ)")
            
            extracted_count = 0
            
            with tarfile.open(archive_path, 'r:gz') as tar:
                members = tar.getmembers()
                total_members = len(members)
                print(f"[DEBUG] Всего элементов в архиве: {total_members}")
                
                # Проверяем структуру архива
                has_winetricks_cache_dir = any(
                    m.name.startswith('winetricks-cache/') or m.name == 'winetricks-cache' 
                    for m in members
                )
                
                items_to_extract = []
                
                if extract_info['extract_mode'] == 'folder':
                    # ИЗВЛЕЧЕНИЕ ПАПКИ
                    folder_name = extract_info['folders'][0]
                    
                    # Определяем путь к папке
                    # Если в конфигурации указан download_path - используем его
                    try:
                        full_config = get_component_data(component_id)
                        if full_config and full_config.get('download_path'):
                            expected_path = full_config.get('download_path')
                        else:
                            expected_path = f'winetricks-cache/{component_id}/{folder_name}'
                    except Exception:
                        expected_path = f'winetricks-cache/{component_id}/{folder_name}'
                    
                    print(f"[DEBUG] Ищем папку: {expected_path}")
                    
                    # Собираем ВСЕ файлы из папки
                    for member in members:
                        if member.isfile() and member.name.startswith(expected_path + '/'):
                            items_to_extract.append(member)
                    
                    # Если не найдено - ищем по имени папки во всем архиве
                    if not items_to_extract:
                        folder_basename = os.path.basename(expected_path)
                        print(f"[DEBUG] Папка не найдена по пути, ищем по имени: {folder_basename}")
                        
                        for member in members:
                            if member.isfile() and f'/{folder_basename}/' in member.name:
                                items_to_extract.append(member)
                    
                    print(f"[DEBUG] Найдено файлов в папке: {len(items_to_extract)}")
                
                elif extract_info['extract_mode'] == 'files':
                    # ИЗВЛЕЧЕНИЕ ФАЙЛОВ
                    component_files = extract_info['files']
                    found_by_path = []
                    
                    print(f"[DEBUG] Ищем {len(component_files)} файлов в архиве...")
                    
                    # ШАГ 1: Ищем каждый файл по указанному пути
                    for filename in component_files:
                        expected_path = f'winetricks-cache/{component_id}/{filename}'
                        
                        for member in members:
                            if member.isfile() and member.name == expected_path:
                                items_to_extract.append(member)
                                found_by_path.append(filename)
                                print(f"[DEBUG] Найден файл {filename} по пути: {member.name}")
                                break
                    
                    # ШАГ 2: Если не все файлы найдены - ищем по имени во всем архиве
                    missing_files = [f for f in component_files if f not in found_by_path]
                    
                    if missing_files:
                        print(f"[DEBUG] Не найдены по пути {len(missing_files)} файлов, ищем по имени в архиве...")
                        
                        # Читаем список всех файлов в архиве
                        all_archive_files = {
                            os.path.basename(m.name): m 
                            for m in members if m.isfile()
                        }
                        print(f"[DEBUG] Всего файлов в архиве: {len(all_archive_files)}")
                        
                        for filename in missing_files:
                            if filename in all_archive_files:
                                member = all_archive_files[filename]
                                items_to_extract.append(member)
                                print(f"[DEBUG] Найден файл {filename} в архиве по пути: {member.name}")
                            else:
                                print(f"[DEBUG] Файл {filename} не найден в архиве")
                
                # Извлекаем все найденные файлы в папку компонента с сохранением структуры
                component_cache_dir = os.path.join(user_cache_dir, component_id)
                os.makedirs(component_cache_dir, exist_ok=True)
                fix_dir_permissions(component_cache_dir)
                
                for member in items_to_extract:
                    # Определяем относительный путь внутри папки компонента
                    archive_prefix = f'winetricks-cache/{component_id}/'
                    if member.name.startswith(archive_prefix):
                        # Убираем префикс "winetricks-cache/component_id/" для получения относительного пути
                        relative_path = member.name[len(archive_prefix):]
                    else:
                        # Если файл не в папке компонента (найден по имени), используем только имя
                        relative_path = os.path.basename(member.name)
                    
                    # Создаем полный путь в кэше пользователя с сохранением структуры
                    target_path = os.path.join(component_cache_dir, relative_path)
                    
                    # Создаем родительские папки если нужно
                    parent_dir = os.path.dirname(target_path)
                    if parent_dir and parent_dir != component_cache_dir:
                        os.makedirs(parent_dir, exist_ok=True)
                        fix_dir_permissions(parent_dir)
                    
                    # Извлекаем файл из архива
                    fileobj = tar.extractfile(member)
                    if fileobj:
                        file_data = fileobj.read()
                        with open(target_path, 'wb') as f:
                            f.write(file_data)
                        
                        # КРИТИЧНО: Устанавливаем права доступа на файл
                        os.chmod(target_path, 0o644)
                        
                        # Если запущено от root - устанавливаем владельца файла на пользователя
                        if os.geteuid() == 0:
                            real_user = os.environ.get('SUDO_USER')
                            if real_user and real_user != 'root':
                                try:
                                    user_info = pwd.getpwnam(real_user)
                                    os.chown(target_path, user_info.pw_uid, user_info.pw_gid)
                                except (KeyError, ImportError):
                                    pass  # Игнорируем ошибки
                        
                        extracted_count += 1
                        print(f"[DEBUG] Извлечен файл: {relative_path} -> {target_path}")
                
                print(f"[INFO] Извлечено файлов: {extracted_count}")
                return extracted_count
                
        except Exception as e:
            print(f"[ERROR] Ошибка при извлечении из архива: {e}", level='ERROR')
            for line in traceback.format_exc().split('\n'):
                if line.strip():
                    print(f"[DEBUG] {line}", level='DEBUG')
            return 0
    
    def get_category(self) -> str:
        return 'winetricks'
    
    def set_use_minimal(self, use_minimal):
        """
        Обновление режима использования минимального winetricks
        
        Args:
            use_minimal: True для минимального, False для оригинального
        """
        self.use_minimal = use_minimal
        if self.winetricks_manager:
            self.winetricks_manager.set_use_minimal(use_minimal)
        print(f"[WinetricksHandler] Режим изменен: {'минимальный' if use_minimal else 'оригинальный'} winetricks")
    
    @track_class_activity('WinetricksHandler')
    def install(self, component_id: str, config: dict) -> bool:
        """Установка winetricks компонента"""
        print(f"WinetricksHandler.install() вызван с component_id={component_id}, config={config}", level='DEBUG')
        
        # КРИТИЧНО: Проверяем, установлен ли компонент ПЕРЕД установкой статуса
        if self.check_status(component_id, config):
            print(f"Компонент {component_id} уже установлен, пропускаем установку", level='DEBUG')
            return True
        
        # ОБНОВЛЯЕМ СТАТУС: устанавливаем 'installing'
        print(f"WinetricksHandler.install() устанавливаем статус installing для {component_id}", level='DEBUG')
        self._update_status(component_id, 'installing')
        
        print(f"Установка winetricks компонента: {config['name']}")
        
        # ПРИОРИТЕТ: Извлекаем файлы из архива если нужно
        if self.astrapack_dir:
            # Определяем что нужно извлечь из конфигурации
            extract_info = self._get_component_extract_info(config, component_id)
            
            # Проверяем кэш пользователя - все файлы уже там?
            user_cache_dir = os.path.join(os.path.expanduser('~'), '.cache', 'winetricks')
            all_files_in_cache = True
            
            if extract_info['extract_mode'] == 'files':
                # Проверяем наличие всех файлов в кэше пользователя
                for filename in extract_info['files']:
                    cache_path = os.path.join(user_cache_dir, filename)
                    if not os.path.exists(cache_path):
                        all_files_in_cache = False
                        break
            elif extract_info['extract_mode'] == 'folder':
                # Для папки проверяем наличие хотя бы одного файла
                # (полную проверку делаем при извлечении)
                all_files_in_cache = False
            
            if not all_files_in_cache:
                # Нужно извлечь из архива
                archive_name = config.get('winetricks_archive_name')
                winetricks_archive = self._find_winetricks_archive(self.astrapack_dir, archive_name=archive_name)
                
                if winetricks_archive and os.path.exists(winetricks_archive):
                    print(f"[INFO] Извлечение файлов компонента {component_id} из архива...")
                    extracted_count = self._extract_from_archive(
                        winetricks_archive, 
                        extract_info, 
                        component_id,
                        user_cache_dir
                    )
                    
                    if extracted_count == 0:
                        if config.get('source_fallback', True):
                            print(f"[INFO] Файлы не найдены в архиве, будет использован fallback на скачивание", level='INFO')
                        else:
                            print(f"[WARNING] Файлы не найдены в архиве и fallback отключен!", level='WARNING')
                else:
                    print(f"[DEBUG] Архив winetricks не найден")
                    if config.get('source_fallback', True):
                        print(f"[INFO] Будет использован fallback на скачивание из интернета", level='INFO')
            else:
                print(f"[DEBUG] Все файлы компонента {component_id} уже в кэше пользователя")
        
        # Обновляем прогресс
        self._update_progress(
            stage_name=f"Установка {config['name']}",
            stage_progress=0,
            global_progress=0,
            details=f"Подготовка к установке {component_id}"
        )
        
        try:
            # Получаем имя компонента winetricks из конфигурации через универсальную функцию
            winetricks_component = get_component_field(component_id, 'command_name')
            print(f"WinetricksHandler.install() command_name из конфигурации: {winetricks_component}", level='DEBUG')
            
            # Если command_name не указан, используем component_id
            if not winetricks_component:
                print(f"WinetricksHandler.install() command_name не указан, используем component_id: {component_id}", level='DEBUG')
                winetricks_component = component_id
            else:
                print(f"WinetricksHandler.install() используем winetricks_component: {winetricks_component}", level='DEBUG')
            
            # Используем WinetricksManager (который учитывает use_minimal флаг)
            def status_callback(message):
                print(f"[WinetricksManager] {message}")
                if self.callback:
                    if message.startswith("UPDATE_COMPONENT:"):
                        component = message.split(":", 1)[1]
                        self.callback(f"UPDATE_COMPONENT:{component}")
                    else:
                        self.callback(message)
            
            # Обновляем прогресс
            self._update_progress(
                stage_name=f"Установка {config['name']}",
                stage_progress=50,
                global_progress=50,
                details=f"Установка через winetricks..."
            )
            
            # КРИТИЧНО: Winetricks НЕЛЬЗЯ запускать от root!
            # Определяем реального пользователя
            real_user = os.environ.get('SUDO_USER')
            print(f"WinetricksHandler.install() реальный пользователь: {real_user}, euid={os.geteuid()}", level='DEBUG')
            
            # Если запущено от root - запускаем от имени пользователя
            if os.geteuid() == 0:
                print(f"WinetricksHandler.install() запущено от root, проверяем пользователя", level='DEBUG')
                if not real_user or real_user == 'root':
                    print(f"WinetricksHandler.install() не удалось определить реального пользователя", level='DEBUG')
                    print("Не удалось определить реального пользователя для winetricks", level='ERROR')
                    print("winetricks не может запускаться от root!", level='ERROR')
                    self._update_status(component_id, 'error')
                    return False
                
                print(f"WinetricksHandler.install() запуск winetricks от пользователя: {real_user}", level='DEBUG')
                print(f"Запуск winetricks установки от пользователя: {real_user}")
                
                # Для минимального winetricks - используем его напрямую, но от пользователя
                # Для оригинального winetricks - формируем команду через su
                if self.use_minimal:
                    print(f"WinetricksHandler.install() используем MinimalWinetricks (use_minimal=True)", level='DEBUG')
                    # Для минимального winetricks вызываем его напрямую
                    # Но нужно убедиться что он работает от пользователя
                    # Используем WinetricksManager, но через su
                    script_path = os.path.abspath(sys.argv[0] if hasattr(sys, 'argv') else __file__)
                    cmd_string = textwrap.dedent(f"""
                        cd {self.astrapack_dir} &&
                        export WINEPREFIX="$HOME"/.wine-astraregul &&
                        export WINEDEBUG="-all" &&
                        export WINE=/opt/wine-9.0/bin/wine &&
                        export PATH="/opt/wine-9.0/bin:$PATH" &&
                        python3 -c "import sys; \\
                            sys.path.insert(0, '{os.path.dirname(script_path)}'); \\
                            from astra_automation import MinimalWinetricks; \\
                            m = MinimalWinetricks(astrapack_dir='{self.astrapack_dir}'); \\
                            m.install_components(['{winetricks_component}'], wineprefix='$HOME/.wine-astraregul')"
                    """).strip()
                    print(f"WinetricksHandler.install() команда для MinimalWinetricks: {cmd_string[:200]}...", level='DEBUG')
                    
                    # КРИТИЧНО: Обертываем команду в bash -c с правильным экранированием
                    # Это гарантирует корректное выполнение многострочной команды и мониторинг вывода
                    bash_cmd = f"bash -c {shlex.quote(cmd_string)}"
                    
                    print(f"[DEBUG] WinetricksHandler.install() MinimalWinetricks - команда для выполнения:", level='DEBUG')
                    print(f"[DEBUG]   cmd_string: {cmd_string}", level='DEBUG')
                    print(f"[DEBUG]   bash_cmd: {bash_cmd}", level='DEBUG')
                    print(f"[DEBUG]   Полная команда: su - {real_user} -c {shlex.quote(bash_cmd)}", level='DEBUG')
                    print(f"WinetricksHandler.install() запускаем процесс через su - (login shell)", level='DEBUG')
                    return_code = self._run_process(
                        ['su', '-', real_user, '-c', bash_cmd],
                        process_type="install",
                        channels=["file", "terminal"],
                        timeout=600  # 10 минут максимум для установки
                    )
                    success = (return_code == 0)
                    print(f"WinetricksHandler.install() процесс завершился с кодом: {return_code}, success={success}", level='DEBUG')
                else:
                    # Для оригинального winetricks используем bash-скрипт
                    # КРИТИЧНО: Получаем правильную домашнюю директорию пользователя
                    # При запуске от root os.path.expanduser('~') вернет /root, а не /home/fsa
                    if os.geteuid() == 0 and real_user and real_user != 'root':
                        try:
                            user_home = pwd.getpwnam(real_user).pw_dir
                        except (KeyError, ImportError):
                            user_home = os.path.expanduser('~')  # Fallback
                    else:
                        user_home = os.path.expanduser('~')
                    
                    winetricks_path = os.path.join(user_home, '.cache', 'winetricks', 'winetricks')
                    winetricks_dir = os.path.dirname(winetricks_path)
                    print(f"[DEBUG] WinetricksHandler.install() путь к winetricks: {winetricks_path}", level='DEBUG')
                    print(f"[DEBUG] WinetricksHandler.install() директория winetricks: {winetricks_dir}", level='DEBUG')
                    print(f"[DEBUG] WinetricksHandler.install() проверка существования: {os.path.exists(winetricks_path)}", level='DEBUG')
                    
                    # КРИТИЧНО: Как в оригинальном скрипте - переходим в директорию winetricks и запускаем ./winetricks
                    # Это важно, так как winetricks может искать файлы относительно своей директории
                    # КРИТИЧНО: Добавляем явный перехват stderr (2>&1) для диагностики ошибок
                    cmd_string = textwrap.dedent(f"""
                        export WINEPREFIX="$HOME"/.wine-astraregul &&
                        export WINEDEBUG="-all" &&
                        export WINE=/opt/wine-9.0/bin/wine &&
                        export PATH="/opt/wine-9.0/bin:$PATH" &&
                        export W_OPT_UNATTENDED=1 &&
                        cd {shlex.quote(winetricks_dir)} &&
                        ./winetricks -q -f {winetricks_component} 2>&1
                    """).strip()
                    
                    # КРИТИЧНО: Пробуем два варианта запуска
                    # Вариант 1: Через временный bash скрипт (более надежный для сложных команд)
                    temp_script = None
                    try:
                        # Создаем временный скрипт
                        temp_script = tempfile.NamedTemporaryFile(mode='w', suffix='.sh', delete=False)
                        temp_script.write('#!/bin/bash\n')
                        # НЕ используем set -e, так как winetricks может возвращать ненулевые коды, которые обрабатываются внутри
                        temp_script.write('set -x\n')  # Включить отладочный вывод
                        temp_script.write(cmd_string + '\n')
                        temp_script.close()
                        
                        # Устанавливаем права на выполнение
                        os.chmod(temp_script.name, 0o755)
                        
                        # Если запущено от root - устанавливаем владельца скрипта на пользователя
                        if os.geteuid() == 0 and real_user and real_user != 'root':
                            try:
                                user_info = pwd.getpwnam(real_user)
                                os.chown(temp_script.name, user_info.pw_uid, user_info.pw_gid)
                            except (KeyError, ImportError):
                                pass
                        
                        print(f"[DEBUG] WinetricksHandler.install() создан временный скрипт: {temp_script.name}", level='DEBUG')
                        print(f"[DEBUG] WinetricksHandler.install() содержимое скрипта:", level='DEBUG')
                        with open(temp_script.name, 'r') as f:
                            script_content = f.read()
                            print(f"[DEBUG] {script_content}", level='DEBUG')
                        
                        # КРИТИЧНО: Диагностический запуск winetricks напрямую (без su -) для проверки реальной ошибки
                        # Это поможет увидеть ошибки, которые могут теряться при запуске через su
                        diagnostic_success = False
                        if os.geteuid() == 0 and real_user and real_user != 'root':
                            print(f"[DEBUG] WinetricksHandler.install() ДИАГНОСТИКА: пробуем запустить winetricks напрямую от пользователя {real_user}", level='DEBUG')
                            try:
                                # Запускаем winetricks напрямую через runuser (если доступен) или su без login shell
                                test_cmd = f"export W_OPT_UNATTENDED=1 && cd {shlex.quote(winetricks_dir)} && ./winetricks -q -f {winetricks_component} 2>&1"
                                test_result = self._run_process(
                                    ['runuser', '-u', real_user, '--', 'bash', '-c', test_cmd],
                                    process_type="install",
                                    channels=["file", "terminal"],
                                    timeout=30  # Короткий таймаут для диагностики
                                )
                                print(f"[DEBUG] WinetricksHandler.install() ДИАГНОСТИКА: прямой запуск завершился с кодом: {test_result}", level='DEBUG')
                                if test_result == 0:
                                    print(f"[DEBUG] WinetricksHandler.install() ДИАГНОСТИКА: прямой запуск успешен!", level='DEBUG')
                                    diagnostic_success = True
                                    return_code = 0
                                    success = True
                            except Exception as diag_e:
                                print(f"[DEBUG] WinetricksHandler.install() ДИАГНОСТИКА: ошибка прямого запуска: {diag_e}", level='DEBUG')
                                # Продолжаем с обычным запуском через su -
                        
                        # Если диагностический запуск не удался, используем обычный способ
                        if not diagnostic_success:
                            # Запускаем скрипт через su
                            script_cmd = f"bash {temp_script.name}"
                            print(f"[DEBUG] WinetricksHandler.install() запускаем через временный скрипт: su - {real_user} -c {shlex.quote(script_cmd)}", level='DEBUG')
                            
                            return_code = self._run_process(
                                ['su', '-', real_user, '-c', script_cmd],
                                process_type="install",
                                channels=["file", "terminal"],
                                timeout=600  # 10 минут максимум для установки
                            )
                            success = (return_code == 0)
                            print(f"[DEBUG] WinetricksHandler.install() процесс завершился с кодом: {return_code}, success={success}", level='DEBUG')
                        
                    except Exception as e:
                        print(f"[DEBUG] WinetricksHandler.install() ошибка при создании временного скрипта: {e}", level='DEBUG')
                        print(f"[DEBUG] WinetricksHandler.install() пробуем альтернативный вариант через bash -c", level='DEBUG')
                        
                        # Вариант 2: Через bash -c (fallback)
                        bash_cmd = f"bash -c {shlex.quote(cmd_string)}"
                        print(f"[DEBUG] WinetricksHandler.install() Оригинальный winetricks - команда для выполнения:", level='DEBUG')
                        print(f"[DEBUG]   cmd_string: {cmd_string}", level='DEBUG')
                        print(f"[DEBUG]   bash_cmd: {bash_cmd}", level='DEBUG')
                        print(f"[DEBUG]   Полная команда: su - {real_user} -c {shlex.quote(bash_cmd)}", level='DEBUG')
                        print(f"WinetricksHandler.install() запускаем процесс через su - (login shell)", level='DEBUG')
                        
                        return_code = self._run_process(
                            ['su', '-', real_user, '-c', bash_cmd],
                            process_type="install",
                            channels=["file", "terminal"],
                            timeout=600  # 10 минут максимум для установки
                        )
                        success = (return_code == 0)
                        print(f"[DEBUG] WinetricksHandler.install() процесс завершился с кодом: {return_code}, success={success}", level='DEBUG')
                    finally:
                        # Удаляем временный скрипт
                        if temp_script and os.path.exists(temp_script.name):
                            try:
                                os.unlink(temp_script.name)
                                print(f"[DEBUG] WinetricksHandler.install() временный скрипт удален: {temp_script.name}", level='DEBUG')
                            except Exception as e:
                                print(f"[DEBUG] WinetricksHandler.install() ошибка удаления временного скрипта: {e}", level='DEBUG')
            else:
                # Уже не root - используем WinetricksManager напрямую
                # WinetricksManager сам решает использовать минимальный или оригинальный winetricks
                success = self._get_winetricks_manager().install_wine_packages(
                    components=[winetricks_component],
                    wineprefix=self.wineprefix,
                    callback=status_callback
                )
            
            print(f"WinetricksHandler.install() проверка результата: success={success}", level='DEBUG')
            if success:
                # КРИТИЧНО: Проверяем реальный статус компонента перед сообщением об успехе
                # Winetricks может вернуть код 0, но компонент не установится
                print(f"WinetricksHandler.install() команда завершилась успешно, проверяем статус компонента", level='DEBUG')
                os.sync()  # Принудительная синхронизация файловой системы
                time.sleep(0.2)  # Небольшая задержка для завершения операций winetricks
                
                # КРИТИЧНО: Сразу после установки проверяем winetricks.log (как это делает сам winetricks)
                # Это более надежно, чем проверка файлов, так как файлы могут появиться с задержкой
                winetricks_log = os.path.join(self.wineprefix, 'winetricks.log')
                log_check_passed = False
                if os.path.exists(winetricks_log):
                    try:
                        with open(winetricks_log, 'r', encoding='utf-8', errors='ignore') as f:
                            log_content = f.read()
                            command_name = config.get('command_name', component_id)
                            pattern = r'\b' + re.escape(command_name) + r'\b'
                            if re.search(pattern, log_content):
                                print(f"[DEBUG] WinetricksHandler.install() компонент {component_id} ({command_name}) найден в winetricks.log", level='DEBUG')
                                log_check_passed = True
                    except Exception as e:
                        print(f"[DEBUG] WinetricksHandler.install() ошибка чтения winetricks.log: {e}", level='DEBUG')
                
                # Проверяем статус компонента через файлы (стандартная проверка)
                actual_status = self.check_status(component_id, config)
                print(f"WinetricksHandler.install() проверка статуса вернула: {actual_status}", level='DEBUG')
                
                # Если проверка лога прошла успешно, считаем установку успешной даже если файлы еще не появились
                if log_check_passed:
                    actual_status = True
                    print(f"[DEBUG] WinetricksHandler.install() установка подтверждена через winetricks.log", level='DEBUG')
                
                if actual_status:
                    print(f"WinetricksHandler.install() компонент {component_id} установлен успешно", level='DEBUG')
                    print(f"Компонент {config['name']} успешно установлен через winetricks")
                    self._update_progress(
                        stage_name=f"Установка {config['name']}",
                        stage_progress=100,
                        global_progress=100,
                        details=f"{config['name']} установлен успешно"
                    )
                    # ОБНОВЛЯЕМ СТАТУС: устанавливаем 'ok'
                    print(f"WinetricksHandler.install() устанавливаем статус ok для {component_id}", level='DEBUG')
                    self._update_status(component_id, 'ok')
                    return True
                else:
                    print(f"WinetricksHandler.install() команда завершилась успешно, но компонент не установлен", level='DEBUG')
                    print(f"Команда winetricks завершилась успешно, но компонент {config['name']} не установлен", level='ERROR')
                    print(f"Проверка статуса компонента не подтвердила установку", level='ERROR')
                    # ОБНОВЛЯЕМ СТАТУС: устанавливаем 'error'
                    print(f"WinetricksHandler.install() устанавливаем статус error для {component_id}", level='DEBUG')
                    self._update_status(component_id, 'error')
                    return False
            else:
                print(f"WinetricksHandler.install() команда завершилась с ошибкой", level='DEBUG')
                print(f"Установка компонента {config['name']}", level='ERROR')
                # ОБНОВЛЯЕМ СТАТУС: устанавливаем 'error'
                print(f"WinetricksHandler.install() устанавливаем статус error для {component_id}", level='DEBUG')
                self._update_status(component_id, 'error')
                return False
                    
        except Exception as e:
            print(f"WinetricksHandler.install() ИСКЛЮЧЕНИЕ: {str(e)}", level='DEBUG')
            print(f"Установка компонента через winetricks: {str(e)}", level='ERROR')
            traceback.print_exc()
            print(f"WinetricksHandler.install() устанавливаем статус error для {component_id}", level='DEBUG')
            self._update_status(component_id, 'error')
            return False
    
    @track_class_activity('WinetricksHandler')
    def uninstall(self, component_id: str, config: dict) -> bool:
        """Удаление winetricks компонента"""
        print(f"WinetricksHandler.uninstall() НАЧАЛО: component_id={component_id}, config={config.get('name', 'Unknown')}", level='DEBUG')
        print(f"Удаление winetricks компонента: {config['name']}")
        
        # КРИТИЧНО: Устанавливаем статус 'removing' сразу, чтобы он отобразился в GUI
        # Это гарантирует, что пользователь видит статус 'removing' для текущего компонента
        print(f"WinetricksHandler.uninstall() УСТАНАВЛИВАЕМ статус 'removing' для {component_id}", level='DEBUG')
        self._update_status(component_id, 'removing')
        print(f"WinetricksHandler.uninstall() статус 'removing' установлен для {component_id}", level='DEBUG')
        
        time.sleep(0.1)  # Минимальная задержка для обновления GUI
        
        # Проверяем, существует ли компонент
        # Если компонент уже удален, устанавливаем статус 'missing' и выходим
        check_paths = get_component_field(component_id, 'check_paths', [])
        if not check_paths:
            print(f"Не указаны check_paths для {component_id}, удаление невозможно", level='WARNING')
            print(f"Компонент {config['name']} находится внутри WINEPREFIX и удалится вместе с ним", level='WARNING')
            # Устанавливаем статус 'missing', так как компонент физически удалится с WINEPREFIX
            self._update_status(component_id, 'missing')
            return True
        
        # Проверяем, существует ли хотя бы один путь компонента
        component_exists = False
        for path in check_paths:
            # Обрабатываем специальные пути
            if path.startswith('drive_c/'):
                # Путь внутри WINEPREFIX
                full_path = os.path.join(self.wineprefix, path)
            elif path.startswith('~/'):
                # КРИТИЧНО: Используем expand_user_path для учета SUDO_USER
                full_path = expand_user_path(path)
            else:
                full_path = path
            
            if os.path.exists(full_path):
                component_exists = True
                break
        
        # Если компонент уже удален, устанавливаем статус 'missing' и выходим
        if not component_exists:
            print(f"Компонент {config['name']} уже удален (файлы не найдены)")
            # ОБНОВЛЯЕМ СТАТУС: устанавливаем 'missing' для уже удаленного компонента
            self._update_status(component_id, 'missing')
            return True
        
        try:
            # Универсальная логика остановки процессов:
            # Winetricks компоненты - это листовые элементы, поэтому останавливаем только свои процессы
            # Деинсталлятор winetricks сам остановит процессы, но для надежности остановим свои
            is_leaf = self._is_leaf_component(component_id)
            
            if is_leaf:
                # ЛИСТОВОЙ ЭЛЕМЕНТ: останавливаем только свои процессы
                own_processes = get_component_field(component_id, 'processes_to_stop', [])
                if own_processes:
                    print(f"Остановка своих процессов (листовой элемент): {', '.join(own_processes)}")
                    processes_stopped = self._stop_processes(own_processes)
                    if not processes_stopped:
                        print(f"Не все процессы остановлены для {component_id}, продолжаем удаление", level='WARNING')
            else:
                # РОДИТЕЛЬ: рекурсивно собираем процессы всех дочек
                all_processes = self._collect_all_processes_for_stop(component_id)
                if all_processes:
                    print(f"Остановка всех процессов (родитель): {', '.join(sorted(all_processes))}")
                    processes_stopped = self._stop_processes(list(all_processes))
                    if not processes_stopped:
                        print(f"Не все процессы остановлены для {component_id}, продолжаем удаление", level='WARNING')
            
            # КРИТИЧНО: winetricks НЕ ПОДДЕРЖИВАЕТ команду 'remove'!
            # Вместо этого удаляем файлы/папки компонента вручную по check_paths
            # Все winetricks компоненты находятся внутри WINEPREFIX и удаляются удалением файлов/папок
            
            # Удаляем файлы/папки компонента по check_paths
            # Для winetricks компонентов определяем корневую директорию компонента и удаляем её
            removed_paths = set()  # Используем set для избежания дубликатов
            
            for path in check_paths:
                # Обрабатываем специальные пути
                if path.startswith('drive_c/'):
                    # Путь внутри WINEPREFIX
                    full_path = os.path.join(self.wineprefix, path)
                elif path.startswith('~/'):
                    full_path = os.path.expanduser(path)
                else:
                    full_path = path
                
                if not os.path.exists(full_path):
                    continue
                
                # Определяем корневую директорию компонента для удаления
                if os.path.isdir(full_path):
                    # Это директория - удаляем её целиком
                    removed_paths.add(full_path)
                else:
                    # Это файл - определяем корневую директорию компонента
                    # Например: drive_c/windows/mono/mono-2.0/bin/libmono-2.0-x86.dll
                    # Для mono: удаляем drive_c/windows/mono/
                    # Для .NET: удаляем drive_c/windows/Microsoft.NET/
                    # Для VC++: удаляем только конкретные файлы
                    
                    parts = path.split('/')
                    if 'mono' in parts:
                        # Для mono: удаляем drive_c/windows/mono/
                        mono_idx = parts.index('mono')
                        mono_path = '/'.join(parts[:mono_idx+1])
                        removed_paths.add(os.path.join(self.wineprefix, mono_path))
                    elif 'Microsoft.NET' in parts:
                        # Для .NET: удаляем drive_c/windows/Microsoft.NET/
                        net_idx = parts.index('Microsoft.NET')
                        net_path = '/'.join(parts[:net_idx+1])
                        removed_paths.add(os.path.join(self.wineprefix, net_path))
                    elif 'system32' in parts:
                        # Для VC++ и других DLL в system32 - удаляем только конкретные файлы
                        removed_paths.add(full_path)
                    else:
                        # Для других компонентов - удаляем родительскую директорию файла
                        # Но берем только 2 уровня вверх (чтобы не удалить слишком много)
                        parent_dir = os.path.dirname(full_path)
                        removed_paths.add(parent_dir)
            
            # Удаляем найденные пути
            removed_count = 0
            for path_to_remove in removed_paths:
                if os.path.exists(path_to_remove):
                    try:
                        if os.path.isdir(path_to_remove):
                            shutil.rmtree(path_to_remove)
                            print(f"  Удалена директория: {path_to_remove}")
                        else:
                            os.remove(path_to_remove)
                            print(f"  Удален файл: {path_to_remove}")
                        removed_count += 1
                    except Exception as e:
                        print(f"  ОШИБКА удаления {path_to_remove}: {e}", level='WARNING')
            
            os.sync()  # Принудительная синхронизация файловой системы
            
            # Проверяем статус компонента
            actual_status = self.check_status(component_id, config)
            
            if not actual_status:
                # Компонент действительно удален - устанавливаем статус 'missing'
                if removed_count > 0:
                    print(f"Компонент {config['name']} успешно удален (удалено {removed_count} элементов)")
                else:
                    print(f"Компонент {config['name']} не найден (возможно, уже удален)")
                self._update_status(component_id, 'missing')
                return True
            else:
                # Компонент все еще существует - устанавливаем статус 'error'
                print(f"Компонент {config['name']} не удален (проверка статуса не подтвердила удаление)", level='ERROR')
                self._update_status(component_id, 'error')
                return False
                    
        except Exception as e:
            print(f"Удаление winetricks компонента: {str(e)}", level='ERROR')
            
            traceback.print_exc()
            self._update_status(component_id, 'error')
            return False
    
    def check_status(self, component_id: str, config: dict) -> bool:
        """Проверка статуса winetricks компонента"""
        # КРИТИЧНО: Используем единую функцию проверки статуса из глобального модуля
        # Используем wineprefix_path=None, чтобы путь определялся автоматически
        # из конфигурации компонента (wineprefix_path в COMPONENTS_CONFIG)
        return check_component_status(component_id, wineprefix_path=None)

# ============================================================================
# ОБРАБОТЧИК APT ПАКЕТОВ
# ============================================================================
class AptPackageHandler(ComponentHandler):
    """Обработчик APT пакетов Linux (gimp, vlc, libreoffice)"""
    
    def get_category(self) -> str:
        return 'apt_packages'
    
    @track_class_activity('AptPackageHandler')
    def install(self, component_id: str, config: dict) -> bool:
        """Установка APT пакета"""
        # КРИТИЧНО: Проверяем, установлен ли компонент ПЕРЕД установкой статуса
        if self.check_status(component_id, config):
            return True
        
        # ОБНОВЛЯЕМ СТАТУС: устанавливаем 'installing'
        self._update_status(component_id, 'installing')
        
        component_name = get_component_field(component_id, 'name', 'Unknown')
        command_name = get_component_field(component_id, 'command_name')
        
        if not command_name:
            print(f"Не указано command_name для компонента {component_id}", level='ERROR')
            self._update_status(component_id, 'error')
            return False
        
        print(f"Установка APT пакета: {component_name}")
        
        # Обновляем прогресс
        self._update_progress(
            stage_name=f"Установка {component_name}",
            stage_progress=0,
            global_progress=0,
            details=f"Подготовка к установке {component_id}"
        )
        
        # Обновляем прогресс
        self._update_progress(
            stage_name=f"Установка {component_name}",
            stage_progress=50,
            global_progress=50,
            details=f"Установка через apt..."
        )
        
        # НОВОЕ: Разбиваем command_name на список пакетов (если содержит пробелы)
        packages = command_name.split() if ' ' in command_name else [command_name]
        
        # Используем UniversalProcessRunner для установки через apt
        return_code = self._run_process(
            ['apt', 'install', '-y'] + packages,
            process_type="install",
            channels=["file", "terminal", "gui"]
        )
        
        if return_code == 0:
            # КРИТИЧНО: Проверяем реальный статус компонента перед сообщением об успехе
            os.sync()  # Принудительная синхронизация файловой системы
            time.sleep(0.1)  # Минимальная задержка для обновления метаданных
            
            # Проверяем статус компонента
            actual_status = self.check_status(component_id, config)
            
            if actual_status:
                print(f"Пакет {component_name} установлен успешно")
                self._update_progress(
                    stage_name=f"Установка {component_name}",
                    stage_progress=100,
                    global_progress=100,
                    details=f"{component_name} установлен успешно"
                )
                # ОБНОВЛЯЕМ СТАТУС: устанавливаем 'ok'
                self._update_status(component_id, 'ok')
                return True
            else:
                print(f"apt install завершился успешно, но компонент {component_name} не установлен", level='ERROR')
                print(f"Проверка статуса компонента не подтвердила установку", level='ERROR')
                # ОБНОВЛЯЕМ СТАТУС: устанавливаем 'error'
                self._update_status(component_id, 'error')
                return False
        else:
            print(f"Установка пакета {component_name} (код: {return_code})", level='ERROR')
            # ОБНОВЛЯЕМ СТАТУС: устанавливаем 'error'
            self._update_status(component_id, 'error')
            return False
    
    @track_class_activity('AptPackageHandler')
    def uninstall(self, component_id: str, config: dict) -> bool:
        """Удаление APT пакета"""
        print(f"AptPackageHandler.uninstall() НАЧАЛО: component_id={component_id}, config={config.get('name', 'Unknown')}", level='DEBUG')
        # ОБНОВЛЯЕМ СТАТУС: устанавливаем 'removing'
        self._update_status(component_id, 'removing')
        
        component_name = get_component_field(component_id, 'name', 'Unknown')
        command_name = get_component_field(component_id, 'command_name')
        
        if not command_name:
            print(f"Не указано command_name для компонента {component_id}", level='ERROR')
            self._update_status(component_id, 'error')
            return False
        
        print(f"Удаление APT пакета: {component_name}")
        
        # Универсальная логика остановки процессов:
        # APT пакеты - это листовые элементы, поэтому останавливаем только свои процессы
        # Деинсталлятор apt-get сам остановит процессы, но для надежности остановим свои
        is_leaf = self._is_leaf_component(component_id)
        
        if is_leaf:
            # ЛИСТОВОЙ ЭЛЕМЕНТ: останавливаем только свои процессы
            own_processes = get_component_field(component_id, 'processes_to_stop', [])
            if own_processes:
                print(f"Остановка своих процессов (листовой элемент): {', '.join(own_processes)}")
                self._stop_processes(own_processes)
        else:
            # РОДИТЕЛЬ: рекурсивно собираем процессы всех дочек
            all_processes = self._collect_all_processes_for_stop(component_id)
            if all_processes:
                print(f"Остановка всех процессов (родитель): {', '.join(sorted(all_processes))}")
                self._stop_processes(list(all_processes))
        
        # НОВОЕ: Разбиваем command_name на список пакетов (если содержит пробелы)
        packages = command_name.split() if ' ' in command_name else [command_name]
        
        # Удаляем пакет через apt-get purge
        return_code = self._run_process(
            ['apt-get', 'purge', '-y'] + packages,
            process_type="remove",
            channels=["file", "terminal"]
        )
        
        if return_code == 0:
            print(f"Пакет {component_name} удален успешно")
            # КРИТИЧНО: Проверяем реальный статус компонента перед установкой 'missing'
            os.sync()  # Принудительная синхронизация файловой системы
            
            # Проверяем статус компонента
            actual_status = self.check_status(component_id, config)
            
            if not actual_status:
                # Компонент действительно удален - устанавливаем статус 'missing'
                self._update_status(component_id, 'missing')
                return True
            else:
                # Компонент все еще существует - устанавливаем статус 'error'
                print(f"Компонент не удален (проверка статуса не подтвердила удаление)", level='ERROR')
                self._update_status(component_id, 'error')
                return False
        else:
            print(f"Удаление пакета {component_name}", level='ERROR')
            # ОБНОВЛЯЕМ СТАТУС: устанавливаем 'error'
            self._update_status(component_id, 'error')
            return False
    
    def check_status(self, component_id: str, config: dict) -> bool:
        """Проверка статуса APT пакета"""
        # КРИТИЧНО: Используем единую функцию проверки статуса из глобального модуля
        # Используем wineprefix_path=None, чтобы путь определялся автоматически
        # из конфигурации компонента (wineprefix_path в COMPONENTS_CONFIG)
        return check_component_status(component_id, wineprefix_path=None)

# ============================================================================
# ОБРАБОТЧИК WINE ПРИЛОЖЕНИЙ
# ============================================================================
class WineApplicationHandler(ComponentHandler):
    """Обработчик Wine приложений Windows (notepad++, winrar, firefox_wine)"""
    
    def get_category(self) -> str:
        return 'wine_application'
    
    @track_class_activity('WineApplicationHandler')
    def install(self, component_id: str, config: dict) -> bool:
        """Установка Wine приложения"""
        # КРИТИЧНО: Проверяем, установлен ли компонент ПЕРЕД установкой статуса
        if self.check_status(component_id, config):
            return True
        
        # ОБНОВЛЯЕМ СТАТУС: устанавливаем 'installing' только если компонент не установлен
        self._update_status(component_id, 'installing')
        
        component_name = get_component_field(component_id, 'name', 'Unknown')
        print(f"Установка Wine приложения: {component_name}")
        
        # НОВОЕ: Отслеживание времени начала установки
        install_start_time = time.time()
        
        # НОВОЕ: Определяем путь к префиксу из конфигурации
        wineprefix_path = config.get('wineprefix_path')
        if wineprefix_path:
            self.wineprefix = expand_user_path(wineprefix_path)
        
        # Обновляем прогресс
        self._update_progress(
            stage_name=f"Установка {component_name}",
            stage_progress=0,
            global_progress=0,
            details=f"Подготовка к установке {component_id}",
            elapsed_time=0
        )
        
        # НОВОЕ: Проверяем наличие метода копирования предустановленной конфигурации
        copy_method = config.get('copy_method')
        source_dir = config.get('source_dir')
        
        if copy_method == 'replace' and source_dir:
            # Копируем предустановленную конфигурацию с передачей времени начала
            if not self._copy_preinstalled_config(component_id, config, install_start_time):
                self._update_status(component_id, 'error')
                return False
        
        # Для Wine приложений используем метод wine_executable или wine_application
        install_method = get_component_field(component_id, 'install_method')
        if install_method == 'wine_executable':
            return self._install_wine_executable(component_id, config)
        elif install_method == 'wine_application':
            # Для wine_application просто проверяем статус после копирования
            if self.check_status(component_id, config):
                self._update_status(component_id, 'ok')
                return True
            else:
                print(f"Приложение не найдено после копирования конфигурации", level='ERROR')
                self._update_status(component_id, 'error')
                return False
        else:
            print(f"Неизвестный метод установки для {component_id}: {install_method}", level='ERROR')
            self._update_status(component_id, 'error')
            return False
    
    @track_class_activity('WineApplicationHandler')
    def uninstall(self, component_id: str, config: dict) -> bool:
        """Удаление Wine приложения"""
        print(f"WineApplicationHandler.uninstall() НАЧАЛО: component_id={component_id}, config={config.get('name', 'Unknown')}", level='DEBUG')
        # ОБНОВЛЯЕМ СТАТУС: устанавливаем 'removing'
        self._update_status(component_id, 'removing')
        
        time.sleep(0.1)  # Минимальная задержка для обновления GUI
        
        component_name = get_component_field(component_id, 'name', 'Unknown')
        print(f"Удаление Wine приложения: {component_name}")
        
        uninstall_method = get_component_field(component_id, 'uninstall_method')
        if uninstall_method == 'wine_executable' or uninstall_method == 'wine_application':
            return self._uninstall_wine_executable(component_id, config)
        else:
            print(f"Неизвестный метод удаления для {component_id}: {uninstall_method}", level='ERROR')
            self._update_status(component_id, 'error')
            return False
    
    def _copy_preinstalled_config(self, component_id: str, config: dict, install_start_time: float = None) -> bool:
        """
        Копирование предустановленной конфигурации Wine префикса
        Поддерживает приоритеты источников: 'directory' (папка) или 'archive' (архив)
        Использует быстрые методы копирования через отдельные процессы
        
        Args:
            component_id: ID компонента
            config: Конфигурация компонента
            install_start_time: Время начала установки (для отслеживания времени)
        
        Returns:
            bool: True если копирование успешно
        """
        # Если время начала не передано, используем текущее время
        if install_start_time is None:
            install_start_time = time.time()
        
        source_dir = config.get('source_dir')
        if not source_dir:
            print("source_dir не указан в конфигурации", level='ERROR')
            return False
        
        # Получаем приоритет источника из конфигурации
        source_priority = config.get('source_priority', 'archive')  # По умолчанию архив
        source_fallback = config.get('source_fallback', True)  # По умолчанию с fallback
        
        # Определяем пути к источникам
        script_dir = self._get_script_dir()
        
        # 1. Путь к папке (рядом с AstraPack)
        directory_path = os.path.join(script_dir, source_dir)
        
        # 2. Путь к архиву (в AstraPack/Cont/ или AstraPack/)
        archive_path = None
        if self.astrapack_dir:
            # Получаем имя архива из конфигурации (если указано)
            archive_name = config.get('archive_name')
            if not archive_name:
                # Если не указано, используем старое поведение: {source_dir}.tar.gz
                archive_name = f"{source_dir}.tar.gz"
            
            # Определяем группу по component_id (cont -> Cont, astra -> Astra)
            group_name = None
            if 'cont' in component_id.lower():
                group_name = 'Cont'
            elif 'astra' in component_id.lower():
                group_name = 'Astra'
            
            if group_name:
                archive_path = os.path.join(self.astrapack_dir, group_name, archive_name)
            else:
                # Если группа не определена, ищем в корне AstraPack
                archive_path = os.path.join(self.astrapack_dir, archive_name)
        
        # Определяем порядок проверки источников
        if source_priority == 'directory':
            check_order = ['directory', 'archive'] if source_fallback else ['directory']
        else:  # 'archive' или по умолчанию
            check_order = ['archive', 'directory'] if source_fallback else ['archive']
        
        # Пробуем источники в порядке приоритета
        for source_type in check_order:
            if source_type == 'directory':
                if os.path.exists(directory_path) and os.path.isdir(directory_path):
                    print(f"Пробуем источник: папка {directory_path}")
                    if self._copy_from_directory_fast(directory_path, component_id, config, install_start_time):
                        return True
                    elif not source_fallback:
                        # Если fallback отключен и источник не сработал - выходим
                        return False
                    else:
                        print(f"Источник папка не сработал, пробуем следующий...", level='WARNING')
            
            elif source_type == 'archive':
                if archive_path and os.path.exists(archive_path) and os.path.isfile(archive_path):
                    print(f"Пробуем источник: архив {archive_path}")
                    if self._copy_from_archive_fast(archive_path, source_dir, component_id, config, install_start_time):
                        return True
                    elif not source_fallback:
                        # Если fallback отключен и источник не сработал - выходим
                        return False
                    else:
                        print(f"Источник архив не сработал, пробуем следующий...", level='WARNING')
        
        # Если ни один источник не найден или не сработал
        print(f"Источник не найден или не сработал: папка {directory_path} и архив {archive_path}", level='ERROR')
        return False
    
    def _copy_preinstalled_config_old(self, component_id: str, config: dict, install_start_time: float = None) -> bool:
        """
        СТАРАЯ РЕАЛИЗАЦИЯ: Копирование предустановленной конфигурации Wine префикса
        Оставлена для совместимости (fallback если новые методы не работают)
        """
        # Если время начала не передано, используем текущее время
        if install_start_time is None:
            install_start_time = time.time()
        source_dir = config.get('source_dir')
        if not source_dir:
            print("source_dir не указан в конфигурации", level='ERROR')
            return False
        
        # Сначала проверяем наличие архива .tar.gz
        archive_path = None
        temp_extract_dir = None
        
        # Определяем возможные пути к архиву
        # Для CountPack ищем в AstraPack/Cont/CountPack.tar.gz
        if self.astrapack_dir:
            # Получаем имя архива из конфигурации (если указано)
            archive_name = config.get('archive_name')
            if not archive_name:
                # Если не указано, используем старое поведение: {source_dir}.tar.gz
                archive_name = f"{source_dir}.tar.gz"
            
            # Определяем группу по component_id (cont -> Cont, astra -> Astra)
            group_name = None
            if 'cont' in component_id.lower():
                group_name = 'Cont'
            elif 'astra' in component_id.lower():
                group_name = 'Astra'
            
            if group_name:
                archive_path = os.path.join(self.astrapack_dir, group_name, archive_name)
            else:
                # Если группа не определена, ищем в корне AstraPack
                archive_path = os.path.join(self.astrapack_dir, archive_name)
        
        # Определяем путь к целевому префиксу
        wineprefix_path = config.get('wineprefix_path', self.wineprefix)
        wineprefix_path = expand_user_path(wineprefix_path)
        
        # Проверяем наличие архива
        if archive_path and os.path.exists(archive_path) and os.path.isfile(archive_path):
            print(f"Найден архив: {archive_path}")
            print(f"Распаковка архива напрямую в {wineprefix_path}...")
            print("Файлы из архива заменят существующие, файлы которых нет в архиве останутся нетронутыми")
            
            # Инициализируем переменные для восстановления umask (до try блока)
            old_umask = None
            
            try:
                # Инициализируем время начала распаковки и размер
                unpack_start_time = time.time()
                extracted_size = 0  # Размер распакованных данных в байтах
                
                # Определяем uid/gid для установки прав (один раз в начале)
                real_user = os.environ.get('SUDO_USER')
                if os.geteuid() == 0 and real_user and real_user != 'root':
                    # Если запущено от root - используем SUDO_USER
                    unpack_uid = pwd.getpwnam(real_user).pw_uid
                    unpack_gid = pwd.getpwnam(real_user).pw_gid
                else:
                    # Если запущено от обычного пользователя - используем текущего пользователя
                    unpack_uid = os.getuid()
                    unpack_gid = os.getgid()
                
                # Устанавливаем umask для правильных прав по умолчанию (644 для файлов, 755 для директорий)
                old_umask = os.umask(0o022)
                
                # Счетчики для пакетной установки прав
                files_since_last_chown = 0
                last_chown_time = time.time()
                CHOWN_BATCH_SIZE = 1000  # Устанавливаем права каждые 1000 файлов
                CHOWN_TIME_INTERVAL = 10  # Или каждые 10 секунд (что наступит раньше)
                
                # Распаковываем архив напрямую в целевую папку
                # Файлы из архива автоматически заменят существующие при записи (режим 'wb')
                # Файлы, которых нет в архиве, останутся нетронутыми
                with tarfile.open(archive_path, 'r:gz') as tar:
                    # Определяем, содержит ли архив папку с именем source_dir
                    members = tar.getmembers()
                    has_source_dir = any(m.name.startswith(f"{source_dir}/") or m.name == source_dir for m in members)
                    
                    if has_source_dir:
                        # Архив содержит папку source_dir - извлекаем только её содержимое
                        print(f"Архив содержит папку {source_dir}, извлекаем содержимое...")
                        prefix = f"{source_dir}/"
                        # Сортируем members для правильного порядка создания папок
                        sorted_members = sorted(members, key=lambda m: (m.isdir(), m.name))
                        
                        # Фильтруем только нужные элементы (с префиксом source_dir/)
                        items_to_extract = [m for m in sorted_members if m.name.startswith(prefix) and m.name != source_dir]
                        total_items = len(items_to_extract)
                        files_count = sum(1 for m in items_to_extract if m.isfile())
                        dirs_count = sum(1 for m in items_to_extract if m.isdir())
                        
                        print(f"Всего элементов для извлечения: {total_items} (файлов: {files_count}, папок: {dirs_count})")
                        
                        # НОВОЕ: Обновляем только global_progress (не stage_progress)
                        # Время обновляется автоматически через таймер
                        self._update_progress(
                            stage_name=f"Распаковка архива {source_dir}",
                            stage_progress=0,  # Не обновляем
                            global_progress=0,  # Начальный прогресс
                            details=f"Найдено элементов: {total_items} (файлов: {files_count}, папок: {dirs_count})"
                        )
                        
                        extracted_count = 0
                        for member in items_to_extract:
                            # Проверяем флаг отмены в начале каждой итерации
                            if CANCEL_OPERATION:
                                print("Распаковка прервана пользователем")
                                # КРИТИЧНО: ВСЕГДА устанавливаем права на все распакованные файлы при отмене
                                self._set_extracted_files_permissions(wineprefix_path)
                                os.umask(old_umask)  # Восстанавливаем umask
                                return False
                            
                            # Создаем новый путь, убирая префикс source_dir/
                            new_name = member.name[len(prefix):]
                            if not new_name:  # Пропускаем пустые имена
                                continue
                            
                            target_path = os.path.join(wineprefix_path, new_name)
                            
                            # Извлекаем файл/папку
                            if member.isfile():
                                # Создаем родительские папки если нужно
                                parent_dir = os.path.dirname(target_path)
                                if parent_dir:
                                    os.makedirs(parent_dir, exist_ok=True)
                                # Извлекаем файл
                                fileobj = tar.extractfile(member)
                                if fileobj:
                                    file_data = fileobj.read()
                                    with open(target_path, 'wb') as f:
                                        f.write(file_data)
                                    # Добавляем размер файла к общему размеру
                                    extracted_size += len(file_data)
                                
                                extracted_count += 1
                                
                                # Устанавливаем права пакетно (не на каждый файл!)
                                files_since_last_chown += 1
                                current_time = time.time()
                                
                                # Устанавливаем права пакетно: каждые 1000 файлов или каждые 10 секунд
                                if files_since_last_chown >= CHOWN_BATCH_SIZE or (current_time - last_chown_time) >= CHOWN_TIME_INTERVAL:
                                    try:
                                        os.chown(target_path, unpack_uid, unpack_gid)
                                        os.chmod(target_path, 0o644)
                                    except (OSError, PermissionError):
                                        pass  # Игнорируем ошибки доступа
                                    files_since_last_chown = 0
                                    last_chown_time = current_time
                                    
                                    # Проверяем отмену после установки прав
                                    if CANCEL_OPERATION:
                                        print("Распаковка прервана пользователем")
                                        # КРИТИЧНО: ВСЕГДА устанавливаем права на все распакованные файлы при отмене
                                        self._set_extracted_files_permissions(wineprefix_path)
                                        os.umask(old_umask)
                                        return False
                                
                                if extracted_count % 100 == 0 or extracted_count == total_items:
                                    # Вычисляем прошедшее время
                                    elapsed_time = time.time() - unpack_start_time
                                    elapsed_minutes = int(elapsed_time // 60)
                                    elapsed_seconds = int(elapsed_time % 60)
                                    
                                    # Форматируем размер распакованных данных
                                    if extracted_size < 1024:
                                        size_str = f"{extracted_size} Б"
                                    elif extracted_size < 1024 * 1024:
                                        size_str = f"{extracted_size / 1024:.1f} КБ"
                                    elif extracted_size < 1024 * 1024 * 1024:
                                        size_str = f"{extracted_size / (1024 * 1024):.1f} МБ"
                                    else:
                                        size_str = f"{extracted_size / (1024 * 1024 * 1024):.2f} ГБ"
                                    
                                    # НОВОЕ: Обновляем только global_progress на основе количества файлов
                                    global_progress = int((extracted_count / total_items) * 100) if total_items > 0 else 0
                                    print(f"Извлечено элементов: {extracted_count}/{total_items} ({global_progress}%) | Время: {elapsed_minutes}м {elapsed_seconds}с | Размер: {size_str}")
                                    # Время обновляется автоматически через таймер
                                    self._update_progress(
                                        stage_name=f"Распаковка архива {source_dir}",
                                        stage_progress=0,  # Не обновляем
                                        global_progress=global_progress,  # Только global_progress
                                        details=f"Извлечено: {extracted_count}/{total_items} ({new_name[:50]}...) | {size_str}"
                                    )
                            elif member.isdir():
                                # Создаем папку
                                os.makedirs(target_path, exist_ok=True)
                                # Директорий меньше - устанавливаем права сразу
                                try:
                                    os.chown(target_path, unpack_uid, unpack_gid)
                                    os.chmod(target_path, 0o755)
                                except (OSError, PermissionError):
                                    pass  # Игнорируем ошибки доступа
                                extracted_count += 1
                            elif member.issym() or member.islnk():
                                # Для символических ссылок и жестких ссылок
                                # Создаем родительские папки если нужно
                                parent_dir = os.path.dirname(target_path)
                                if parent_dir:
                                    os.makedirs(parent_dir, exist_ok=True)
                                # Извлекаем ссылку
                                tar.extract(member, wineprefix_path)
                                # Переименовываем после извлечения
                                old_path = os.path.join(wineprefix_path, member.name)
                                if os.path.exists(old_path):
                                    if os.path.exists(target_path):
                                        if os.path.isdir(target_path):
                                            shutil.rmtree(target_path)
                                        else:
                                            os.remove(target_path)
                                    os.rename(old_path, target_path)
                                extracted_count += 1
                        
                        # НОВОЕ: Финальное обновление - только global_progress
                        # Вычисляем итоговое время и размер
                        elapsed_time = time.time() - unpack_start_time
                        elapsed_minutes = int(elapsed_time // 60)
                        elapsed_seconds = int(elapsed_time % 60)
                        
                        # Форматируем итоговый размер
                        if extracted_size < 1024:
                            size_str = f"{extracted_size} Б"
                        elif extracted_size < 1024 * 1024:
                            size_str = f"{extracted_size / 1024:.1f} КБ"
                        elif extracted_size < 1024 * 1024 * 1024:
                            size_str = f"{extracted_size / (1024 * 1024):.1f} МБ"
                        else:
                            size_str = f"{extracted_size / (1024 * 1024 * 1024):.2f} ГБ"
                        
                        print(f"Распаковка завершена: извлечено {extracted_count}/{total_items} элементов | Время: {elapsed_minutes}м {elapsed_seconds}с | Размер: {size_str}")
                        self._update_progress(
                            stage_name=f"Распаковка архива {source_dir}",
                            stage_progress=0,  # Не обновляем
                            global_progress=100,  # Завершено
                            details=f"Успешно извлечено {extracted_count} элементов | {size_str}"
                        )
                        
                        # Восстанавливаем umask
                        os.umask(old_umask)
                        
                        # КРИТИЧНО: ВСЕГДА устанавливаем права на все распакованные файлы (на случай пропущенных)
                        self._set_extracted_files_permissions(wineprefix_path)
                    else:
                        # Архив содержит файлы в корне - извлекаем всё
                        print("Архив содержит файлы в корне, извлекаем всё...")
                        total_items = len([m for m in members if m.isfile()])
                        print(f"Всего файлов для извлечения: {total_items}")
                        
                        self._update_progress(
                            stage_name=f"Распаковка архива {source_dir}",
                            stage_progress=0,
                            global_progress=0,
                            details=f"Найдено файлов: {total_items}"
                        )
                        
                        tar.extractall(wineprefix_path)
                        
                        # НОВОЕ: Финальное обновление - только global_progress
                        # Время обновляется автоматически через таймер
                        print(f"Распаковка завершена: извлечено {total_items} файлов")
                        self._update_progress(
                            stage_name=f"Распаковка архива {source_dir}",
                            stage_progress=0,  # Не обновляем
                            global_progress=100,  # Завершено
                            details=f"Успешно извлечено {total_items} файлов"
                        )
                        
                        # Восстанавливаем umask
                        os.umask(old_umask)
                        
                        # КРИТИЧНО: ВСЕГДА устанавливаем права на все распакованные файлы
                        self._set_extracted_files_permissions(wineprefix_path)
                
                print(f"Архив успешно распакован в {wineprefix_path}")
                
            except Exception as e:
                # Восстанавливаем umask даже при ошибке (если был установлен)
                if old_umask is not None:
                    try:
                        os.umask(old_umask)
                    except:
                        pass
                print(f"Ошибка распаковки архива: {e}", level='ERROR')
                traceback.print_exc()
                # При ошибке также устанавливаем права на уже распакованные файлы (если есть)
                try:
                    self._set_extracted_files_permissions(wineprefix_path)
                except:
                    pass
                return False
        else:
            # Архив не найден - используем существующую логику с папкой
            full_source_dir = self._get_source_dir(source_dir)
            
            if not full_source_dir or not os.path.exists(full_source_dir):
                print(f"Папка с предустановленной конфигурацией не найдена: {full_source_dir}", level='ERROR')
                return False
            
            print(f"Копирование предустановленной конфигурации из {full_source_dir} в {wineprefix_path}")
            
            try:
                # КРИТИЧНО: Копируем с заменой всех файлов
                # Копируем dosdevices и drive_c (НЕ копируем Ярлыки - они обрабатываются отдельно)
                items_to_copy = ['dosdevices', 'drive_c']
                
                for item in items_to_copy:
                    src = os.path.join(full_source_dir, item)
                    dst = os.path.join(wineprefix_path, item)
                    
                    if not os.path.exists(src):
                        print(f"Предупреждение: {item} не найден в {full_source_dir}", level='WARNING')
                        continue
                    
                    if os.path.isdir(src):
                        # Копируем директорию с заменой
                        if os.path.exists(dst):
                            print(f"Удаление существующей директории: {dst}")
                            shutil.rmtree(dst)
                        print(f"Копирование директории: {item}")
                        shutil.copytree(src, dst)
                        print(f"  Директория скопирована: {item}")
                    else:
                        # Копируем файл с заменой
                        if os.path.exists(dst):
                            os.remove(dst)
                        print(f"Копирование файла: {item}")
                        shutil.copy2(src, dst)
                        print(f"  Файл скопирован: {item}")
                
                # Копируем файлы реестра (если есть)
                reg_files = ['system.reg', 'user.reg', 'userdef.reg']
                for reg_file in reg_files:
                    src = os.path.join(full_source_dir, reg_file)
                    dst = os.path.join(wineprefix_path, reg_file)
                    
                    if os.path.exists(src):
                        if os.path.exists(dst):
                            os.remove(dst)
                        shutil.copy2(src, dst)
                        print(f"  Файл реестра скопирован: {reg_file}")
                
            except Exception as e:
                print(f"Ошибка копирования предустановленной конфигурации: {str(e)}", level='ERROR')
                traceback.print_exc()
                return False
        
        # Устанавливаем правильного владельца
        try:
            real_user = os.environ.get('SUDO_USER')
            if os.geteuid() == 0 and real_user and real_user != 'root':
                uid = pwd.getpwnam(real_user).pw_uid
                gid = pwd.getpwnam(real_user).pw_gid
                
                # Устанавливаем владельца на всю директорию префикса
                os.chown(wineprefix_path, uid, gid)
                for root, dirs, files in os.walk(wineprefix_path):
                    for d in dirs:
                        os.chown(os.path.join(root, d), uid, gid)
                    for f in files:
                        os.chown(os.path.join(root, f), uid, gid)
                
                print(f"Установлен владелец префикса: {real_user}")
        except Exception as e:
            print(f"Предупреждение: не удалось установить владельца: {e}", level='WARNING')
        
        print("Предустановленная конфигурация успешно установлена")
        return True
    
    def _set_extracted_files_permissions(self, wineprefix_path: str) -> None:
        """
        Устанавливает правильные права доступа на распакованные файлы
        
        Args:
            wineprefix_path: Путь к WINEPREFIX
        """
        try:
            real_user = os.environ.get('SUDO_USER')
            
            # Определяем uid/gid для установки владельца
            if os.geteuid() == 0 and real_user and real_user != 'root':
                # Если запущено от root - используем SUDO_USER
                uid = pwd.getpwnam(real_user).pw_uid
                gid = pwd.getpwnam(real_user).pw_gid
            else:
                # Если запущено от обычного пользователя - используем текущего пользователя
                uid = os.getuid()
                gid = os.getgid()
            
            # Устанавливаем владельца на все распакованные файлы и директории
            os.chown(wineprefix_path, uid, gid)
            
            # Рекурсивно устанавливаем владельца для всех файлов и директорий
            for root, dirs, files in os.walk(wineprefix_path):
                try:
                    # Устанавливаем владельца для директорий
                    for d in dirs:
                        dir_path = os.path.join(root, d)
                        os.chown(dir_path, uid, gid)
                        # Устанавливаем права доступа: 755 для директорий
                        os.chmod(dir_path, 0o755)
                    
                    # Устанавливаем владельца для файлов
                    for f in files:
                        file_path = os.path.join(root, f)
                        os.chown(file_path, uid, gid)
                        # Устанавливаем права доступа: 644 для файлов
                        os.chmod(file_path, 0o644)
                except (OSError, PermissionError) as e:
                    # Игнорируем ошибки доступа к отдельным файлам/директориям
                    print(f"Предупреждение: не удалось установить права для {root}: {e}", level='DEBUG')
            
            if os.geteuid() == 0 and real_user and real_user != 'root':
                print(f"Установлен владелец распакованных файлов: {real_user}")
            else:
                print(f"Установлены права доступа на распакованные файлы")
        except Exception as e:
            print(f"Предупреждение: не удалось установить права доступа: {e}", level='WARNING')
    
    def _check_command_available(self, command: str) -> bool:
        """
        Проверка доступности команды в системе
        
        Args:
            command: Имя команды (например, 'rsync', 'tar', 'cp')
        
        Returns:
            bool: True если команда доступна
        """
        return shutil.which(command) is not None
    
    def _count_files_recursive(self, directory: str):
        """
        Генератор для подсчета файлов рекурсивно
        
        Args:
            directory: Путь к директории
        
        Yields:
            str: Путь к каждому файлу
        """
        for root, dirs, files in os.walk(directory):
            for file in files:
                yield os.path.join(root, file)
    
    def _check_archive_structure(self, archive_path: str, source_dir: str) -> bool:
        """
        Проверяет структуру архива: содержит ли он папку source_dir
        
        Args:
            archive_path: Путь к архиву
            source_dir: Имя директории для проверки
        
        Returns:
            bool: True если архив содержит папку source_dir
        """
        try:
            # Используем tar -tzf для просмотра содержимого без распаковки
            result = subprocess.run(
                ['tar', '-tzf', archive_path],
                stdout=subprocess.PIPE,
                stderr=subprocess.PIPE,
                text=True,
                timeout=10
            )
            
            if result.returncode != 0:
                return False
            
            # Проверяем, есть ли папка source_dir в архиве
            for line in result.stdout.split('\n'):
                if line.startswith(f'{source_dir}/') or line == source_dir:
                    return True
            
            return False
            
        except Exception as e:
            print(f"Ошибка проверки структуры архива: {e}", level='DEBUG')
            return False
    
    def _count_files_in_archive(self, archive_path: str, prefix: str = None) -> int:
        """
        Подсчитывает количество файлов в архиве (для прогресса)
        
        Args:
            archive_path: Путь к архиву
            prefix: Префикс для фильтрации (например, 'CountPack/')
        
        Returns:
            int: Количество файлов
        """
        try:
            # Используем tar -tzf для просмотра содержимого
            result = subprocess.run(
                ['tar', '-tzf', archive_path],
                stdout=subprocess.PIPE,
                stderr=subprocess.PIPE,
                text=True,
                timeout=10
            )
            
            if result.returncode != 0:
                return 0
            
            count = 0
            for line in result.stdout.split('\n'):
                line = line.strip()
                if not line:
                    continue
                
                # Если указан префикс, считаем только файлы с этим префиксом
                if prefix:
                    if line.startswith(f'{prefix}/') and line != prefix:
                        # Проверяем, что это файл (не директория)
                        if not line.endswith('/'):
                            count += 1
                else:
                    # Считаем все файлы (не директории)
                    if not line.endswith('/'):
                        count += 1
            
            return count
            
        except Exception as e:
            print(f"Ошибка подсчета файлов в архиве: {e}", level='DEBUG')
            return 0
    
    def _copy_from_directory_fast(self, directory_path: str, component_id: str, 
                                   config: dict, install_start_time: float) -> bool:
        """
        Быстрое копирование из папки через отдельный процесс (rsync/tar/cp)
        С мониторингом и возможностью прерывания
        
        Args:
            directory_path: Путь к исходной папке
            component_id: ID компонента
            config: Конфигурация компонента
            install_start_time: Время начала установки
        
        Returns:
            bool: True если копирование успешно
        """
        wineprefix_path = config.get('wineprefix_path', self.wineprefix)
        wineprefix_path = expand_user_path(wineprefix_path)
        
        print(f"Найдена папка: {directory_path}")
        print(f"Быстрое копирование из {directory_path} в {wineprefix_path}")
        
        # Определяем uid/gid для установки владельца после копирования
        real_user = os.environ.get('SUDO_USER')
        if os.geteuid() == 0 and real_user and real_user != 'root':
            copy_uid = pwd.getpwnam(real_user).pw_uid
            copy_gid = pwd.getpwnam(real_user).pw_gid
        else:
            copy_uid = os.getuid()
            copy_gid = os.getgid()
        
        # Пробуем использовать rsync (самый быстрый)
        if self._check_command_available('rsync'):
            return self._copy_with_rsync(directory_path, wineprefix_path, 
                                        copy_uid, copy_gid, component_id, config, install_start_time)
        
        # Fallback: tar (очень быстрый)
        elif self._check_command_available('tar'):
            return self._copy_with_tar(directory_path, wineprefix_path, 
                                      copy_uid, copy_gid, component_id, config, install_start_time)
        
        # Fallback: cp (простой, но быстрый)
        else:
            return self._copy_with_cp(directory_path, wineprefix_path, 
                                     copy_uid, copy_gid, component_id, config, install_start_time)
    
    def _copy_from_archive_fast(self, archive_path: str, source_dir: str, component_id: str,
                               config: dict, install_start_time: float) -> bool:
        """
        ГИБРИДНАЯ быстрая распаковка архива:
        - Python tarfile для быстрого чтения метаданных (без таймаутов)
        - Системный tar для быстрой распаковки
        - Мониторинг прогресса на основе метаданных
        
        Args:
            archive_path: Путь к архиву
            source_dir: Имя директории в архиве (если есть)
            component_id: ID компонента
            config: Конфигурация компонента
            install_start_time: Время начала установки
        
        Returns:
            bool: True если распаковка успешна
        """
        wineprefix_path = config.get('wineprefix_path', self.wineprefix)
        wineprefix_path = expand_user_path(wineprefix_path)
        
        print(f"Найден архив: {archive_path}")
        print(f"Быстрая распаковка архива напрямую в {wineprefix_path}...")
        print("Файлы из архива заменят существующие, файлы которых нет в архиве останутся нетронутыми")
        
        # Определяем uid/gid для установки владельца после распаковки
        real_user = os.environ.get('SUDO_USER')
        if os.geteuid() == 0 and real_user and real_user != 'root':
            unpack_uid = pwd.getpwnam(real_user).pw_uid
            unpack_gid = pwd.getpwnam(real_user).pw_gid
        else:
            unpack_uid = os.getuid()
            unpack_gid = os.getgid()
        
        # Проверяем доступность tar
        if not self._check_command_available('tar'):
            print("Команда tar не найдена, используем Python tarfile (медленнее)", level='WARNING')
            return self._copy_preinstalled_config_old(component_id, config, install_start_time)
        
        # ШАГ 1: Быстрое чтение метаданных через Python tarfile (как в старой версии)
        # Это читает только заголовки, не весь архив - БЫСТРО и БЕЗ таймаутов!
        try:
            with tarfile.open(archive_path, 'r:gz') as tar:
                members = tar.getmembers()  # ← БЫСТРО! Читает только заголовки
                
                # Определяем структуру архива из метаданных
                has_source_dir = any(m.name.startswith(f"{source_dir}/") or m.name == source_dir for m in members)
                
                if has_source_dir:
                    # Архив содержит папку source_dir - извлекаем только её содержимое (без папки)
                    prefix = f"{source_dir}/"
                    items_to_extract = [m for m in members if m.name.startswith(prefix) and m.name != source_dir]
                    total_items = len(items_to_extract)
                    files_count = sum(1 for m in items_to_extract if m.isfile())
                    dirs_count = sum(1 for m in items_to_extract if m.isdir())
                    total_size = sum(m.size for m in items_to_extract if m.isfile())
                    
                    print(f"Архив содержит папку {source_dir}, извлекаем содержимое (без папки)...")
                    print(f"Всего элементов для извлечения: {total_items} (файлов: {files_count}, папок: {dirs_count})")
                else:
                    # Архив содержит файлы в корне - извлекаем всё
                    items_to_extract = [m for m in members]
                    total_items = len([m for m in members if m.isfile()])
                    files_count = total_items
                    dirs_count = sum(1 for m in members if m.isdir())
                    total_size = sum(m.size for m in members if m.isfile())
                    
                    print("Архив содержит файлы в корне, извлекаем всё...")
                    print(f"Всего файлов для извлечения: {total_items}")
                
                # Форматируем общий размер
                if total_size < 1024 * 1024:
                    size_str = f"{total_size / 1024:.1f} КБ"
                elif total_size < 1024 * 1024 * 1024:
                    size_str = f"{total_size / (1024 * 1024):.1f} МБ"
                else:
                    size_str = f"{total_size / (1024 * 1024 * 1024):.2f} ГБ"
                
                print(f"Общий размер: {size_str}")
                
        except Exception as e:
            # Если не удалось прочитать метаданные - архив поврежден
            print(f"Ошибка чтения метаданных архива: {e}", level='ERROR')
            print("Архив поврежден или недоступен, распаковка невозможна", level='ERROR')
            return False
        
        self._update_progress(
            stage_name=f"Распаковка архива {os.path.basename(archive_path)}",
            stage_progress=0,
            global_progress=0,
            details=f"Найдено элементов: {total_items} (файлов: {files_count}, папок: {dirs_count}) | Размер: {size_str if total_size > 0 else 'неизвестно'}"
        )
        
        # ШАГ 2: Распаковка через системный tar (быстрее Python tarfile)
        tar_cmd = [
            'tar',
            '-xzf',  # -x (extract), -z (gzip), -f (file)
            archive_path,
            '-C', wineprefix_path,  # Изменить директорию перед извлечением
        ]
        
        # Если архив содержит папку source_dir, нужно извлечь только её содержимое
        if has_source_dir:
            # Используем --strip-components=1 чтобы убрать первый уровень (source_dir/)
            tar_cmd.extend(['--strip-components=1'])
            # И указываем что извлекать только source_dir/
            tar_cmd.append(f'{source_dir}/')
        else:
            # Извлекаем всё из корня архива
            tar_cmd.append('.')
        
        process = None
        monitor_thread = None
        cancel_flag = threading.Event()
        old_umask = None
        
        try:
            # Устанавливаем umask для правильных прав
            old_umask = os.umask(0o022)
            
            # Запускаем tar в отдельном процессе
            process = subprocess.Popen(
                tar_cmd,
                stdout=subprocess.PIPE,
                stderr=subprocess.PIPE,
                universal_newlines=True
            )
            
            # ШАГ 3: Запускаем мониторинг прогресса на основе метаданных
            monitor_thread = threading.Thread(
                target=self._monitor_tar_with_metadata,
                args=(process, wineprefix_path, total_items, total_size, install_start_time, cancel_flag, component_id, items_to_extract),
                daemon=True
            )
            monitor_thread.start()
            
            # Ждем завершения процесса с проверкой отмены
            while process.poll() is None:
                if CANCEL_OPERATION or cancel_flag.is_set():
                    print("Распаковка прервана пользователем")
                    process.terminate()  # Отправляем SIGTERM
                    try:
                        process.wait(timeout=5)
                    except subprocess.TimeoutExpired:
                        process.kill()  # Принудительно завершаем
                    if old_umask is not None:
                        os.umask(old_umask)
                    # Устанавливаем права на уже распакованные файлы
                    self._set_extracted_files_permissions(wineprefix_path)
                    return False
                
                time.sleep(0.1)  # Небольшая задержка для проверки
            
            # Восстанавливаем umask
            if old_umask is not None:
                os.umask(old_umask)
            
            # Проверяем код возврата
            return_code = process.returncode
            
            if return_code != 0:
                stderr_output = ""
                if process.stderr:
                    try:
                        stderr_output = process.stderr.read()
                    except:
                        pass
                print(f"tar завершился с ошибкой (код: {return_code})", level='ERROR')
                if stderr_output:
                    print(f"Ошибка tar: {stderr_output}", level='ERROR')
                if old_umask is not None:
                    os.umask(old_umask)
                return False
            
            # Устанавливаем владельца и права (tar может не сохранить владельца)
            print("Установка владельца и прав доступа...")
            self._set_extracted_files_permissions(wineprefix_path)
            
            elapsed_time = time.time() - install_start_time
            elapsed_minutes = int(elapsed_time // 60)
            elapsed_seconds = int(elapsed_time % 60)
            
            print(f"Распаковка завершена за {elapsed_minutes}м {elapsed_seconds}с")
            self._update_progress(
                stage_name=f"Распаковка архива {os.path.basename(archive_path)}",
                stage_progress=0,
                global_progress=100,
                details=f"Успешно извлечено {total_items} элементов"
            )
            
            return True
            
        except Exception as e:
            if process and process.poll() is None:
                process.terminate()
                try:
                    process.wait(timeout=2)
                except:
                    process.kill()
            
            if old_umask is not None:
                try:
                    os.umask(old_umask)
                except:
                    pass
            
            print(f"Ошибка распаковки архива: {e}", level='ERROR')
            traceback.print_exc()
            # Устанавливаем права на уже распакованные файлы (если есть)
            try:
                self._set_extracted_files_permissions(wineprefix_path)
            except:
                pass
            return False
    
    def _copy_with_rsync(self, src_dir: str, dst_dir: str, uid: int, gid: int,
                        component_id: str, config: dict, start_time: float) -> bool:
        """
        Копирование через rsync (максимальная скорость)
        """
        # Подсчитываем общее количество файлов для прогресса
        total_files = sum(1 for _ in self._count_files_recursive(src_dir))
        print(f"Всего файлов для копирования: {total_files}")
        
        self._update_progress(
            stage_name=f"Копирование через rsync",
            stage_progress=0,
            global_progress=0,
            details=f"Найдено файлов: {total_files}"
        )
        
        # Команда rsync с оптимизацией для скорости
        rsync_cmd = [
            'rsync',
            '--archive',           # Сохраняет все атрибуты
            '--inplace',           # Обновляет файлы на месте (быстрее)
            '--no-whole-file',     # Дельта-копирование (быстрее для изменений)
            '--progress',          # Показывает прогресс
            '--human-readable',     # Читаемый формат
            '--info=progress2',    # Общий прогресс (не по каждому файлу)
            f'{src_dir}/',         # Исходная директория (с / в конце)
            dst_dir                # Целевая директория
        ]
        
        process = None
        monitor_thread = None
        cancel_flag = threading.Event()
        
        try:
            # Запускаем rsync в отдельном процессе
            process = subprocess.Popen(
                rsync_cmd,
                stdout=subprocess.PIPE,
                stderr=subprocess.STDOUT,
                universal_newlines=True,
                bufsize=1
            )
            
            # Запускаем поток мониторинга
            monitor_thread = threading.Thread(
                target=self._monitor_rsync_progress,
                args=(process, total_files, start_time, cancel_flag, component_id),
                daemon=True
            )
            monitor_thread.start()
            
            # Ждем завершения процесса с проверкой отмены
            while process.poll() is None:
                if CANCEL_OPERATION or cancel_flag.is_set():
                    print("Копирование прервано пользователем")
                    process.terminate()  # Отправляем SIGTERM
                    try:
                        process.wait(timeout=5)
                    except subprocess.TimeoutExpired:
                        process.kill()  # Принудительно завершаем
                    return False
                
                time.sleep(0.1)  # Небольшая задержка для проверки
            
            # Проверяем код возврата
            return_code = process.returncode
            if return_code != 0:
                print(f"rsync завершился с ошибкой (код: {return_code})", level='ERROR')
                return False
            
            # Устанавливаем владельца и права (rsync может не сохранить владельца)
            print("Установка владельца и прав доступа...")
            self._set_extracted_files_permissions(dst_dir)
            
            elapsed_time = time.time() - start_time
            elapsed_minutes = int(elapsed_time // 60)
            elapsed_seconds = int(elapsed_time % 60)
            
            print(f"Копирование завершено за {elapsed_minutes}м {elapsed_seconds}с")
            self._update_progress(
                stage_name=f"Копирование через rsync",
                stage_progress=0,
                global_progress=100,
                details=f"Успешно скопировано {total_files} файлов"
            )
            
            return True
            
        except Exception as e:
            if process and process.poll() is None:
                process.terminate()
                try:
                    process.wait(timeout=2)
                except:
                    process.kill()
            
            print(f"Ошибка копирования через rsync: {e}", level='ERROR')
            traceback.print_exc()
            return False
    
    def _copy_with_tar(self, src_dir: str, dst_dir: str, uid: int, gid: int,
                      component_id: str, config: dict, start_time: float) -> bool:
        """
        Копирование через tar (очень быстро, через pipe)
        """
        total_files = sum(1 for _ in self._count_files_recursive(src_dir))
        print(f"Всего файлов для копирования: {total_files}")
        
        self._update_progress(
            stage_name=f"Копирование через tar",
            stage_progress=0,
            global_progress=0,
            details=f"Найдено файлов: {total_files}"
        )
        
        # Команда: tar -c (создать) | tar -x (извлечь)
        tar_cmd = ['tar', '-C', src_dir, '-cf', '-', '.']
        untar_cmd = ['tar', '-C', dst_dir, '-xf', '-']
        
        process1 = None
        process2 = None
        cancel_flag = threading.Event()
        
        try:
            # Создаем pipe между двумя процессами tar
            process1 = subprocess.Popen(
                tar_cmd,
                stdout=subprocess.PIPE,
                stderr=subprocess.PIPE
            )
            
            process2 = subprocess.Popen(
                untar_cmd,
                stdin=process1.stdout,
                stdout=subprocess.PIPE,
                stderr=subprocess.PIPE
            )
            
            # Закрываем stdout первого процесса (он теперь подключен к stdin второго)
            process1.stdout.close()
            
            # Запускаем поток мониторинга
            monitor_thread = threading.Thread(
                target=self._monitor_tar_copy_progress,
                args=(process1, process2, dst_dir, total_files, start_time, cancel_flag),
                daemon=True
            )
            monitor_thread.start()
            
            # Ждем завершения
            while process2.poll() is None:
                if CANCEL_OPERATION or cancel_flag.is_set():
                    print("Копирование прервано пользователем")
                    process1.terminate()
                    process2.terminate()
                    try:
                        process1.wait(timeout=2)
                        process2.wait(timeout=2)
                    except:
                        process1.kill()
                        process2.kill()
                    return False
                
                time.sleep(0.1)
            
            # Проверяем коды возврата
            process1.wait()
            return_code = process2.returncode
            
            if return_code != 0:
                print(f"tar завершился с ошибкой (код: {return_code})", level='ERROR')
                return False
            
            # Устанавливаем владельца и права
            self._set_extracted_files_permissions(dst_dir)
            
            elapsed_time = time.time() - start_time
            elapsed_minutes = int(elapsed_time // 60)
            elapsed_seconds = int(elapsed_time % 60)
            
            print(f"Копирование завершено за {elapsed_minutes}м {elapsed_seconds}с")
            self._update_progress(
                stage_name=f"Копирование через tar",
                stage_progress=0,
                global_progress=100,
                details=f"Успешно скопировано {total_files} файлов"
            )
            
            return True
            
        except Exception as e:
            if process1 and process1.poll() is None:
                process1.terminate()
            if process2 and process2.poll() is None:
                process2.terminate()
            
            print(f"Ошибка копирования через tar: {e}", level='ERROR')
            traceback.print_exc()
            return False
    
