class FilesystemFilter(object):
    """Класс для фильтрации изменений файловой системы"""
    
    def __init__(self):
        self.exclude_paths = [
            '/tmp', '/var/tmp', '/proc', '/sys', '/dev',
            '/run', '/var/run', '/lost+found',
            '/etc/cups',  # Исключаем директорию CUPS (системные файлы печати)
        ]
        self.exclude_patterns = [
            '*.tmp', '*.log', '*.cache', '*.swp', '*.lock',
            '.DS_Store', 'Thumbs.db',
        ]
        self.exclude_hidden = True
        self.min_file_size = 0
    
    def should_include(self, file_path, is_directory=False):
        """Проверяет, нужно ли показывать файл/директорию"""
        
        # Проверка путей
        for exclude_path in self.exclude_paths:
            if file_path.startswith(exclude_path):
                return False
        
        # Проверка паттернов (только для файлов)
        if not is_directory:
            filename = os.path.basename(file_path)
            for pattern in self.exclude_patterns:
                if fnmatch.fnmatch(filename, pattern):
                    return False
        
        # Проверка скрытых файлов
        if self.exclude_hidden and os.path.basename(file_path).startswith('.'):
            return False
        
        return True
    
    def filter_changes(self, changes):
        """Фильтрует изменения согласно настройкам фильтра"""
        filtered = {
            'new_files': [],
            'modified_files': [],
            'deleted_files': [],
            'new_directories': [],
            'deleted_directories': [],
            'timestamp': changes.get('timestamp')
        }
        
        # Фильтруем новые файлы
        for file_path in changes.get('new_files', []):
            if self.should_include(file_path, is_directory=False):
                filtered['new_files'].append(file_path)
        
        # Фильтруем измененные файлы
        for file_path in changes.get('modified_files', []):
            if self.should_include(file_path, is_directory=False):
                filtered['modified_files'].append(file_path)
        
        # Фильтруем удаленные файлы
        for file_path in changes.get('deleted_files', []):
            if self.should_include(file_path, is_directory=False):
                filtered['deleted_files'].append(file_path)
        
        # Фильтруем новые папки
        for dir_path in changes.get('new_directories', []):
            if self.should_include(dir_path, is_directory=True):
                filtered['new_directories'].append(dir_path)
        
        # Фильтруем удаленные папки
        for dir_path in changes.get('deleted_directories', []):
            if self.should_include(dir_path, is_directory=True):
                filtered['deleted_directories'].append(dir_path)
        
        return filtered

class DirectorySnapshot(object):
    """Класс для хранения снимка состояния директории"""
    
    def __init__(self, directory_path, exclude_paths=None, max_depth=None, max_files=50000, calculate_hashes=False):
        """
        Инициализация снимка директории
        
        Args:
            directory_path: Путь к директории для сканирования
            exclude_paths: Список путей для исключения из сканирования
            max_depth: Максимальная глубина вложенности (None = без ограничений)
            max_files: Максимальное количество файлов для сканирования
            calculate_hashes: Вычислять ли хеши файлов (по умолчанию False для производительности)
        """
        self.directory_path = directory_path
        self.timestamp = datetime.datetime.now()
        self.files = {}  # {relative_path: (size, mtime, hash)}
        self.directories = set()  # {relative_path1, relative_path2, ...}
        
        # Метрики производительности
        self.scan_start_time = None
        self.scan_duration = 0.0
        self.files_scanned = 0
        self.directories_scanned = 0
        self.hash_calculation_time = 0.0
        self.memory_usage = 0
        
        # Ограничения сканирования
        self.max_depth = max_depth
        self.max_files = max_files
        self.calculate_hashes = calculate_hashes
        
        # Расширенный список путей для исключения
        self.exclude_paths = exclude_paths or [
            '/proc', '/sys', '/dev', '/tmp', '/var/tmp',
            '/run', '/var/run', '/lost+found',
            '/boot', '/snap', '/var/cache', '/var/log',
            '/var/lib', '/usr/share/doc', '/usr/share/man',
            '/home', '/root/.cache', '/root/.local',
            '/var/spool', '/var/mail', '/var/backups',
            '/etc/cups'  # Исключаем директорию CUPS (системные файлы печати)
        ]
        
        self._scan_directory()
    
    def _should_exclude_path(self, path):
        """Проверяет, нужно ли исключить путь из сканирования"""
        for exclude_path in self.exclude_paths:
            if path.startswith(exclude_path):
                return True
        return False
    
    def _scan_directory(self):
        """Сканирование директории и создание снимка"""
        if not os.path.exists(self.directory_path):
            return
        
        self.scan_start_time = time.time()
        
        try:
            # Вычисляем глубину корневой директории
            root_depth = len(self.directory_path.rstrip('/').split('/'))
            
            # Счетчик для неблокирующей работы
            files_processed = 0
            chunk_size = 100  # Обрабатываем по 100 файлов, затем делаем паузу
            
            for root, dirs, files in os.walk(self.directory_path):
                # Проверяем ограничение по количеству файлов
                if self.files_scanned >= self.max_files:
                    break
                
                # Исключаем пути
                if self._should_exclude_path(root):
                    dirs[:] = []  # Не сканируем поддиректории
                    continue
                
                # Проверяем ограничение по глубине
                if self.max_depth is not None:
                    current_depth = len(root.rstrip('/').split('/')) - root_depth
                    if current_depth > self.max_depth:
                        dirs[:] = []  # Не сканируем глубже
                        continue
                
                # Добавляем директории
                rel_root = os.path.relpath(root, self.directory_path)
                if rel_root != '.':
                    self.directories.add(rel_root)
                    self.directories_scanned += 1
                
                # Добавляем файлы
                for file in files:
                    # Проверяем ограничение по количеству файлов
                    if self.files_scanned >= self.max_files:
                        break
                    
                    file_path = os.path.join(root, file)
                    rel_path = os.path.relpath(file_path, self.directory_path)
                    
                    # Исключаем файлы в исключенных путях
                    if self._should_exclude_path(file_path):
                        continue
                    
                    try:
                        stat = os.stat(file_path)
                        
                        # Вычисляем хеш только если нужно
                        file_hash = 0
                        if self.calculate_hashes:
                            hash_start = time.time()
                            file_hash = self._quick_hash(file_path)
                            self.hash_calculation_time += time.time() - hash_start
                        
                        self.files[rel_path] = (stat.st_size, stat.st_mtime, file_hash)
                        self.files_scanned += 1
                        files_processed += 1
                        
                        # Делаем паузу каждые chunk_size файлов для неблокирующей работы
                        if files_processed >= chunk_size:
                            time.sleep(0.01)  # 10ms пауза
                            files_processed = 0
                    except (OSError, IOError):
                        # Пропускаем файлы, к которым нет доступа
                        continue
                
                # Если достигли лимита, прекращаем обход
                if self.files_scanned >= self.max_files:
                    break
                    
        except (OSError, IOError):
            # Пропускаем директории, к которым нет доступа
            pass
        finally:
            if self.scan_start_time:
                self.scan_duration = time.time() - self.scan_start_time
                # Вычисляем использование памяти (приблизительно)
                self.memory_usage = sys.getsizeof(self.files) + sys.getsizeof(self.directories)
    
    def _quick_hash(self, file_path):
        """Быстрое хеширование файла (первые 8 байт + размер)"""
        try:
            with open(file_path, 'rb') as f:
                data = f.read(8)  # Читаем первые 8 байт
                size = os.path.getsize(file_path)
                return hash(data + str(size).encode())
        except (OSError, IOError):
            return 0
    
    def get_performance_metrics(self):
        """Возвращает метрики производительности сканирования"""
        return {
            'scan_duration': getattr(self, 'scan_duration', 0.0),
            'files_scanned': getattr(self, 'files_scanned', 0),
            'directories_scanned': getattr(self, 'directories_scanned', 0),
            'hash_calculation_time': getattr(self, 'hash_calculation_time', 0.0),
            'memory_usage': getattr(self, 'memory_usage', 0),
            'timestamp': getattr(self, 'timestamp', datetime.datetime.now())
        }
    
    def save_to_file(self, file_path):
        """Сохраняет снимок в файл (pickle)"""
        try:
            # Создаем директорию если не существует
            cache_dir = os.path.dirname(file_path)
            if cache_dir and not os.path.exists(cache_dir):
                os.makedirs(cache_dir, exist_ok=True)
            
            # Сохраняем снимок
            with open(file_path, 'wb') as f:
                pickle.dump({
                    'directory_path': self.directory_path,
                    'timestamp': self.timestamp,
                    'files': self.files,
                    'directories': list(self.directories),  # Преобразуем set в list для сериализации
                    'performance_metrics': self.get_performance_metrics()
                }, f)
            return True
        except Exception as e:
            print(f"[DirectorySnapshot] Ошибка сохранения снимка: {e}")
            return False
    
    @classmethod
    def load_from_file(cls, file_path):
        """Загружает снимок из файла"""
        try:
            if not os.path.exists(file_path):
                return None
            
            with open(file_path, 'rb') as f:
                data = pickle.load(f)
            
            # Создаем экземпляр без сканирования
            snapshot = cls.__new__(cls)
            snapshot.directory_path = data['directory_path']
            snapshot.timestamp = data['timestamp']
            snapshot.files = data['files']
            snapshot.directories = set(data['directories'])  # Преобразуем обратно в set
            
            # Восстанавливаем метрики
            metrics = data.get('performance_metrics', {})
            snapshot.scan_start_time = None
            snapshot.scan_duration = metrics.get('scan_duration', 0.0)
            snapshot.files_scanned = metrics.get('files_scanned', 0)
            snapshot.directories_scanned = metrics.get('directories_scanned', 0)
            snapshot.hash_calculation_time = metrics.get('hash_calculation_time', 0.0)
            snapshot.memory_usage = metrics.get('memory_usage', 0)
            snapshot.exclude_paths = []
            
            return snapshot
        except Exception as e:
            print(f"[DirectorySnapshot] Ошибка загрузки снимка: {e}")
            return None
    
    def is_valid(self, max_age_hours=1):
        """Проверяет, не устарел ли снимок"""
        if not self.timestamp:
            return False
        
        age = datetime.datetime.now() - self.timestamp
        return age.total_seconds() < (max_age_hours * 3600)
class DirectoryMonitor(object):
# ============================================================================
# КЛАСС МОНИТОРИНГА ИЗМЕНЕНИЙ В ДИРЕКТОРИИ
# ============================================================================
    """Класс для мониторинга изменений в директории"""
    
    def __init__(self, compact_mode=False):
        
        self.baseline = None  # Базовый снимок
        self.last_snapshot = None  # Последний снимок
        self.monitoring = False
        self.compact_mode = compact_mode  # Режим компактного вывода
        
        # Метрики производительности
        self.compare_start_time = None
        self.compare_duration = 0.0
        self.last_scan_metrics = {}
        self.total_operations = 0
        self.total_files_compared = 0
    
    def start_monitoring(self, directory_path):
        """Начать мониторинг директории (создать базовый снимок)"""
        self.baseline = DirectorySnapshot(directory_path)
        self.last_snapshot = self.baseline
        self.monitoring = True
        print(f"[DirectoryMonitor] Мониторинг начат: {directory_path}")
        print(f"[DirectoryMonitor] Базовый снимок: {len(self.baseline.files)} файлов, {len(self.baseline.directories)} папок")
    
    def check_changes(self, directory_path):
        """Проверить изменения в директории (сравнить с последним снимком)"""
        if not self.monitoring:
            print("[DirectoryMonitor] Мониторинг не активен!")
            return None
        
        current_snapshot = DirectorySnapshot(directory_path)
        changes = self._compare_snapshots(self.last_snapshot, current_snapshot)
        
        # Обновляем последний снимок
        self.last_snapshot = current_snapshot
        
        return changes
    
    def get_incremental_changes(self, directory_path):
        """Получить инкрементальные изменения (с предыдущего снимка)"""
        return self.check_changes(directory_path)
    
    def get_total_changes(self, directory_path):
        """Получить полные изменения (с базового снимка)"""
        if not self.monitoring or not self.baseline:
            return None
        
        current_snapshot = DirectorySnapshot(directory_path)
        return self._compare_snapshots(self.baseline, current_snapshot)
    
    def reset_baseline(self, directory_path):
        """Сбросить базовый снимок (создать новый)"""
        self.baseline = DirectorySnapshot(directory_path)
        self.last_snapshot = self.baseline
        print(f"[DirectoryMonitor] Базовый снимок сброшен: {len(self.baseline.files)} файлов, {len(self.baseline.directories)} папок")
    
    def detect_installed_components(self, changes):
        """Определяет какие компоненты установились на основе ключевых файлов"""
        component_files = {
            'wine_mono': [
                'drive_c/windows/mono/mono-2.0/bin/libmono-2.0-x86.dll',
                'drive_c/windows/mono/mono-2.0/bin/libmono-2.0-x86_64.dll'
            ],
            'd3dcompiler_43': [
                'drive_c/windows/system32/d3dcompiler_43.dll',
                'drive_c/windows/syswow64/d3dcompiler_43.dll'
            ],
            'd3dcompiler_47': [
                'drive_c/windows/system32/d3dcompiler_47.dll',
                'drive_c/windows/syswow64/d3dcompiler_47.dll'
            ],
            'vcrun2013': [
                'drive_c/windows/system32/msvcp120.dll',
                'drive_c/windows/system32/msvcr120.dll'
            ],
            'vcrun2022': [
                'drive_c/windows/system32/msvcp140.dll',
                'drive_c/windows/system32/vcruntime140.dll'
            ],
            'dotnet48': [
                'drive_c/windows/Microsoft.NET/Framework/v4.0.30319/mscorlib.dll',
                'drive_c/windows/Microsoft.NET/Framework64/v4.0.30319/mscorlib.dll'
            ],
            'dxvk': [
                'drive_c/windows/system32/dxgi.dll',
                'drive_c/windows/system32/d3d11.dll'
            ]
        }
        
        installed_components = []
        for component, key_files in component_files.items():
            for file_path in changes.get('new_files', []):
                if any(key_file in file_path for key_file in key_files):
                    installed_components.append(component)
                    break
        
        return installed_components
    
    def format_changes_compact(self, changes):
        """Компактное форматирование изменений для вывода"""
        if not changes:
            return "Изменений не обнаружено"
        
        # Определяем установленные компоненты
        installed_components = self.detect_installed_components(changes)
        
        # Фильтруем служебные файлы Wine
        filtered_files = self._filter_wine_service_files(changes.get('new_files', []))
        filtered_dirs = self._filter_wine_service_files(changes.get('new_directories', []))
        
        # Подсчитываем изменения
        new_files_count = len(filtered_files)
        modified_files_count = len(changes.get('modified_files', []))
        new_dirs_count = len(filtered_dirs)
        
        timestamp = changes['timestamp'].strftime("%H:%M:%S")
        
        # Формируем компактный вывод
        if installed_components:
            components_str = ", ".join(installed_components)
            stats = []
            if new_files_count > 0:
                stats.append(f"+{new_files_count} файлов")
            if new_dirs_count > 0:
                stats.append(f"+{new_dirs_count} папок")
            if modified_files_count > 0:
                stats.append(f"~{modified_files_count} файлов")
            
            stats_str = f" ({', '.join(stats)})" if stats else ""
            return f"[{timestamp}] Установлены компоненты: {components_str}{stats_str}"
        else:
            stats = []
            if new_files_count > 0:
                stats.append(f"+{new_files_count} файлов")
            if new_dirs_count > 0:
                stats.append(f"+{new_dirs_count} папок")
            if modified_files_count > 0:
                stats.append(f"~{modified_files_count} файлов")
            
            if stats:
                return f"[{timestamp}] Изменения: {', '.join(stats)}"
            else:
                return f"[{timestamp}] Изменений не обнаружено"
    
    def _filter_wine_service_files(self, file_list):
        """Фильтрует служебные файлы Wine из списка"""
        service_patterns = [
            'dosdevices/com',
            'dosdevices/lpt',
            'dosdevices/prn',
            'dosdevices/aux',
            'dosdevices/con',
            '.update-timestamp',
            'dosdevices/z:',
            'dosdevices/y:',
            'dosdevices/x:',
            'dosdevices/w:',
            'dosdevices/v:',
            'dosdevices/u:',
            'dosdevices/t:',
            'dosdevices/s:',
            'dosdevices/r:',
            'dosdevices/q:',
            'dosdevices/p:',
            'dosdevices/o:',
            'dosdevices/n:',
            'dosdevices/m:',
            'dosdevices/l:',
            'dosdevices/k:',
            'dosdevices/j:',
            'dosdevices/i:',
            'dosdevices/h:',
            'dosdevices/g:',
            'dosdevices/f:',
            'dosdevices/e:',
            'dosdevices/d:',
            'dosdevices/c:',
            'dosdevices/b:',
            'dosdevices/a:'
        ]
        
        filtered = []
        for file_path in file_list:
            is_service = False
            for pattern in service_patterns:
                if pattern in file_path:
                    is_service = True
                    break
            if not is_service:
                filtered.append(file_path)
        
        return filtered

    def _compare_snapshots(self, old_snapshot, new_snapshot):
        """Сравнение двух снимков и определение изменений"""
        self.compare_start_time = time.time()
        self.total_operations += 1
        
        changes = {
            'new_files': [],
            'modified_files': [],
            'deleted_files': [],
            'new_directories': [],
            'deleted_directories': [],
            'timestamp': new_snapshot.timestamp
        }
        
        # Проверяем файлы
        old_files = set(old_snapshot.files.keys())
        new_files = set(new_snapshot.files.keys())
        self.total_files_compared = len(old_files | new_files)
        
        # Новые файлы
        for file_path in new_files - old_files:
            changes['new_files'].append(file_path)
        
        # Удаленные файлы
        for file_path in old_files - new_files:
            changes['deleted_files'].append(file_path)
        
        # Измененные файлы
        for file_path in old_files & new_files:
            old_info = old_snapshot.files[file_path]
            new_info = new_snapshot.files[file_path]
            if old_info != new_info:
                changes['modified_files'].append(file_path)
        
        # Проверяем директории
        old_dirs = old_snapshot.directories
        new_dirs = new_snapshot.directories
        
        # Новые директории
        for dir_path in new_dirs - old_dirs:
            changes['new_directories'].append(dir_path)
        
        # Удаленные директории
        for dir_path in old_dirs - new_dirs:
            changes['deleted_directories'].append(dir_path)
        
        # Сохраняем метрики
        if self.compare_start_time:
            self.compare_duration = time.time() - self.compare_start_time
            self.last_scan_metrics = new_snapshot.get_performance_metrics() if hasattr(new_snapshot, 'get_performance_metrics') else {}
        
        return changes
    
    def get_performance_metrics(self):
        """Возвращает метрики производительности мониторинга"""
        return {
            'compare_duration': self.compare_duration,
            'total_operations': self.total_operations,
            'total_files_compared': self.total_files_compared,
            'last_scan_metrics': self.last_scan_metrics
        }
    
    def get_process_info(self):
        """Возвращает информацию для ProcessMonitor"""
        if not self.monitoring:
            return None
        
        # Определяем статус
        if self.compare_start_time and (time.time() - self.compare_start_time) < 5:
            status = 'СРАВНЕНИЕ'
            cpu_usage = 2.0  # Примерная нагрузка
        elif self.baseline and hasattr(self.baseline, 'scan_start_time') and self.baseline.scan_start_time:
            status = 'СКАНИРОВАНИЕ'
            cpu_usage = 5.0  # Примерная нагрузка при сканировании
        else:
            status = 'ОЖИДАНИЕ'
            cpu_usage = 0.1
        
        # Вычисляем использование памяти
        memory_mb = 0
        if self.baseline:
            memory_mb = getattr(self.baseline, 'memory_usage', 0) / (1024 * 1024)
        
        return {
            'name': 'DirectoryMonitor',
            'cpu': cpu_usage,
            'memory': memory_mb,
            'status': status,
            'info': f"Мониторинг: {getattr(self.baseline, 'directory_path', 'N/A')} | Файлов: {getattr(self.baseline, 'files_scanned', 0)}"
        }
    
    def format_changes(self, changes):
        """Форматирование изменений для вывода"""
        if not changes:
            return "Изменений не обнаружено"
        
        # Если включен компактный режим, используем компактное форматирование
        if self.compact_mode:
            return self.format_changes_compact(changes)
        
        # Полный режим - детальный вывод
        output = []
        timestamp = changes['timestamp'].strftime("%H:%M:%S")
        
        # Фильтруем служебные файлы Wine для полного режима
        filtered_new_files = self._filter_wine_service_files(changes['new_files'])
        filtered_new_dirs = self._filter_wine_service_files(changes['new_directories'])
        
        if filtered_new_files:
            output.append(f"[{timestamp}] НОВЫЕ ФАЙЛЫ:")
            for file_path in sorted(filtered_new_files):
                output.append(f"  ├─ {file_path}")
        
        if changes['modified_files']:
            output.append(f"[{timestamp}] ИЗМЕНЕННЫЕ ФАЙЛЫ:")
            for file_path in sorted(changes['modified_files']):
                output.append(f"  ├─ {file_path}")
        
        if filtered_new_dirs:
            output.append(f"[{timestamp}] НОВЫЕ ПАПКИ:")
            for dir_path in sorted(filtered_new_dirs):
                output.append(f"  └─ {dir_path}/")
        
        if changes['deleted_files']:
            output.append(f"[{timestamp}] УДАЛЕННЫЕ ФАЙЛЫ:")
            for file_path in sorted(changes['deleted_files']):
                output.append(f"  ├─ {file_path}")
        
        if changes['deleted_directories']:
            output.append(f"[{timestamp}] УДАЛЕННЫЕ ПАПКИ:")
            for dir_path in sorted(changes['deleted_directories']):
                output.append(f"  └─ {dir_path}/")
        
        return "\n".join(output) if output else "Изменений не обнаружено"

def find_running_instance():
    """Поиск запущенного экземпляра программы (только для Linux)"""
    current_pid = os.getpid()
    
    try:
        result = subprocess.run(
            ['pgrep', '-f', 'astra_automation.py'],
            capture_output=True,
            text=True,
            timeout=1
        )
        
        if result.returncode == 0:
            for pid_str in result.stdout.strip().split('\n'):
                if not pid_str:
                    continue
                
                try:
                    proc_pid = int(pid_str.strip())
                    if proc_pid == current_pid:
                        continue
                    
                    try:
                        with open(f'/proc/{proc_pid}/cmdline', 'r') as f:
                            cmdline = f.read().replace('\x00', ' ')
                            if 'astra_automation.py' in cmdline:
                                return proc_pid
                    except (IOError, OSError):
                        continue
                except ValueError:
                    continue
    except Exception:
        pass
    
    return None

def activate_existing_window():
    """Активация существующего окна программы"""
    app_name = "FSA-AstraInstall"
    
    # Метод 1: wmctrl
    try:
        result = subprocess.run(['wmctrl', '-l'], 
                               capture_output=True, 
                               text=True, 
                               timeout=1)
        if result.returncode == 0:
            for line in result.stdout.split('\n'):
                if app_name in line:
                    window_id = line.split()[0]
                    subprocess.run(['wmctrl', '-i', '-a', window_id], 
                                 timeout=1,
                                 stdout=subprocess.DEVNULL,
                                 stderr=subprocess.DEVNULL)
                    return True
    except:
        pass
    
    # Метод 2: xdotool
    try:
        subprocess.run(['xdotool', 'search', '--name', app_name, 'windowactivate'],
                     timeout=1,
                     stdout=subprocess.DEVNULL,
                     stderr=subprocess.DEVNULL)
        return True
    except:
        pass
    
    return False

def main():
# ============================================================================
# ОСНОВНАЯ ФУНКЦИЯ
# ============================================================================
    """Основная функция"""
    # КРИТИЧНО: Устанавливаем GLOBAL_LOG_FILE СРАЗУ в начале main()
    log_file = None
    log_timestamp = None  # КРИТИЧНО: timestamp для единого лог-файла
    
    # Обрабатываем --log-file и --log-timestamp
    if len(sys.argv) > 1:
        for i, arg in enumerate(sys.argv):
            if arg == '--log-file' and i + 1 < len(sys.argv):
                log_file = sys.argv[i + 1]
            elif arg == '--log-timestamp' and i + 1 < len(sys.argv):
                log_timestamp = sys.argv[i + 1]
    
    # Если не передан, создаем автоматически
    if log_file is None:
        if log_timestamp is None:
            log_timestamp = datetime.datetime.now().strftime("%Y%m%d_%H%M%S")
        script_dir = os.path.dirname(os.path.abspath(__file__))
        log_file = os.path.join(script_dir, "Log", "astra_automation_%s.log" % log_timestamp)
    else:
        # Если передан log_file, но не передан timestamp - извлекаем из имени файла
        if log_timestamp is None:
            match = re.search(r'(\d{8}_\d{6})', log_file)
            if match:
                log_timestamp = match.group(1)
                print(f"[GLOBAL_LOG] Извлечен timestamp из имени файла: {log_timestamp}")
    
    # Создаем глобальную переменную для лог-файла СРАЗУ
    global GLOBAL_LOG_FILE
    GLOBAL_LOG_FILE = log_file
    print(f"[GLOBAL_LOG] Установлен глобальный лог-файл: {GLOBAL_LOG_FILE}")
    if log_timestamp:
        print(f"[GLOBAL_LOG] Используется timestamp: {log_timestamp}")
    
    # Создаем директорию Log если нужно
    log_dir = os.path.dirname(log_file)
    if not os.path.exists(log_dir):
        os.makedirs(log_dir, exist_ok=True)
    
    # НОВОЕ: Инициализируем DualStreamLogger для разделения потоков
    print("[DUAL_STREAM] Инициализация системы двойных потоков логирования...")
    dual_logger = None
    try:
        # Создаём DualStreamLogger с интеграцией в существующую систему
        # КРИТИЧНО: Передаем timestamp для единого RAW лог-файла
        dual_logger = DualStreamLogger.create_default_logger(
            analysis_log_path=GLOBAL_LOG_FILE,
            max_buffer_size=50000,
            timestamp=log_timestamp  # Передаем timestamp для RAW файла
        )
        
        # Запускаем файловое логирование
        dual_logger.start_file_logging()
        
        print("[DUAL_STREAM] OK: DualStreamLogger создан и запущен")
        print("[DUAL_STREAM]   - RAW-поток (apt): %s" % os.path.basename(dual_logger._raw_log_path))
        print("[DUAL_STREAM]   - ANALYSIS-поток: %s" % os.path.basename(dual_logger._analysis_log_path))
        
        # НОВОЕ: Устанавливаем глобальную переменную для доступа из UniversalProcessRunner
        global _global_dual_logger
        _global_dual_logger = dual_logger
        
            # Принудительная запись только в исключительных случаях (например, перед завершением)
        # flush_buffers() не нужен - асинхронная запись через очередь работает автоматически
    except Exception as e:
        print("[DUAL_STREAM] WARNING: Ошибка инициализации DualStreamLogger: %s" % str(e))
        print("[DUAL_STREAM]   Продолжаем без разделения потоков...")
        dual_logger = None
        _global_dual_logger = None
    
    # Создаем единый universal_runner для всего приложения (dual_logger через глобальную переменную)
    logger = UniversalProcessRunner()
    logger.set_log_file(log_file)
    
    # КРИТИЧНО: Немедленно обрабатываем очередь для записи в лог файл!
    logger.process_queue()
    
    # Диагностическая информация
    print(f"[INFO] {APP_NAME} версия: {APP_VERSION}", gui_log=True)
    print(f"[INFO] Python версия: {sys.version}", gui_log=True)
    
    # КРИТИЧНО: Обрабатываем --close-terminal СРАЗУ после создания лог файла
    close_terminal_pid = None
    start_mode = None
    console_mode = False
    setup_repos = False
    dry_run = False  # Инициализируем dry_run
    
    # Обрабатываем аргументы командной строки
    i = 0
    while i < len(sys.argv):
        arg = sys.argv[i]
        if arg == '--console':
            console_mode = True
            print("[INFO] Включен консольный режим", gui_log=True)
        elif arg == '--dry-run':
            dry_run = True
            print("[INFO] Включен режим тестирования", gui_log=True)
        elif arg == '--log-file':
            # Уже обработан выше
            i += 1  # Пропускаем следующий аргумент
        elif arg == '--log-timestamp':
            # Уже обработан выше
            i += 1  # Пропускаем следующий аргумент
        elif arg == '--setup-repos':
            setup_repos = True
            print("[INFO] Режим: только настройка репозиториев", gui_log=True)
        elif arg == '--close-terminal':
            # Следующий аргумент - PID терминала
            if i + 1 < len(sys.argv):
                close_terminal_pid = sys.argv[i + 1]
                
                # КРИТИЧНО: Проверяем что это действительно число, а не другой аргумент
                if close_terminal_pid and close_terminal_pid.isdigit():
                    # ЗАКРЫВАЕМ ТЕРМИНАЛ СРАЗУ!
                    try:
                        pid = int(close_terminal_pid)
                        
                        # Проверяем что процесс существует
                        try:
                            os.kill(pid, 0)  # Сигнал 0 - только проверка существования
                            
                            # Сначала мягкое завершение
                            os.kill(pid, signal.SIGTERM)
                            
                            # Даем время на завершение
                            time.sleep(0.5)
                            
                            # Проверяем что процесс завершился
                            try:
                                os.kill(pid, 0)
                                # Процесс еще жив - отправляем SIGKILL
                                os.kill(pid, signal.SIGKILL)
                            except OSError:
                                # Процесс уже завершился
                                pass
                                
                        except OSError as e:
                            # Процесс уже не существует
                            pass
                            
                    except (ValueError, TypeError) as e:
                        print(f"[WARNING] Некорректный PID терминала: {close_terminal_pid}", gui_log=True)
                else:
                    # Это не число - возможно это следующий аргумент (например --log-timestamp)
                    print(f"[WARNING] PID терминала не указан или некорректен: {close_terminal_pid}", gui_log=True)
                i += 1  # Пропускаем следующий аргумент
